MF_Data = {  
["002:01"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ölümlü ırkların bir araya gelip Burning Legion'ın kudretine karşı birlik olmalarının üzerinden dört yıl geçti. ", ["ORYG"]="Four years have passed since the mortal races banded together and stood united against the might of the Burning Legion. "},
["002:02"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Azeroth kurtarılmış olsa da Horde ve Alliance arasındaki zayıf anlaşma neredeyse buharlaştı. ", ["ORYG"]="Though Azeroth was saved, the tenuous pact between the Horde and the Alliance has all but evaporated. "},
["002:03"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Savaş tamtamları bir kez daha çalıyor. ", ["ORYG"]="The drums of war thunder once again. "},
["014:01"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Highlord Bolvar! Işığa şükürler olsun!", ["ORYG"]="Highlord Bolvar! Thank the Light!"},
["014:02"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Lordaeron için!", ["ORYG"]="For Lordaeron!"},
["014:03"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="İttifak için!", ["ORYG"]="For the Alliance!"},
["014:04"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Geri çekilin, sizi akılsız sefaletler!", ["ORYG"]="Back, you mindless wretches!"},
["014:05"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Savaşın kardeşlerim!", ["ORYG"]="Fight on, brothers!"},
["014:06"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ayağa kalkın, Horde'un evlatları!", ["ORYG"]="Rise up, sons of the Horde!"},
["014:07"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Kan ve zafer bizi bekliyor!", ["ORYG"]="Blood and glory await us!"},
["014:08"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Lok'tar ogar! Sürü için!", ["ORYG"]="Lok'tar ogar! For the Horde!"},
["014:09"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="HORDE İÇİN!", ["ORYG"]="FOR THE HORDE!"},
["014:10"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Gelip gelmeyeceğinizi merak ediyordum!", ["ORYG"]="I was wondering if you'd show up!"},
["014:11"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bugün tüm eğlenceyi İttifak'ın yaşamasına izin veremezdim!", ["ORYG"]="I couldn't let the Alliance have ALL the fun today!"},
["016:01"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Baba?", ["ORYG"]="Father?"},
["016:02"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bitti mi?", ["ORYG"]="Is it... over?"},
["016:03"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Nihayet.", ["ORYG"]="At long last."},
["016:04"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Hiçbir kral sonsuza dek hüküm süremez, oğlum.", ["ORYG"]="No king rules forever, my son."},
["016:05"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Önümde sadece karanlığı görüyorum.", ["ORYG"]="I see... only darkness... before me..."},
["016:06"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Efendisinin emri olmadan,", ["ORYG"]="Without its master's command,"},
["016:07"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="huzursuz Bela bu dünya için daha da büyük bir tehdit haline gelecektir.", ["ORYG"]="the restless Scourge will become an even greater threat to this world."},
["016:08"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Kontrol sağlanmalı.", ["ORYG"]="Control must be maintained..."},
["016:09"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Her zaman bir", ["ORYG"]="There must always be..."},
["016:10"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="bir Lich King olmalı.", ["ORYG"]="a Lich King..."},
["016:11"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Böyle bir yükün ağırlığı.", ["ORYG"]="The weight of such a burden..."},
["016:12"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="... Benim olmalı,", ["ORYG"]="... It must be mine,"},
["016:13"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="çünkü başka kimse yok--", ["ORYG"]="for there is no other to--"},
["016:14"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Tirion.", ["ORYG"]="Tirion..."},
["016:15"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ellerinde acımasız bir kader tutuyorsun, kardeşim.", ["ORYG"]="You hold a grim destiny in your hands, brother"},
["016:16"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="... ama bu sizin değil.", ["ORYG"]="... but it is not your own."},
["016:17"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bolvar.", ["ORYG"]="Bolvar..."},
["016:18"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Kutsal olan her şey adına.", ["ORYG"]="By all that's holy..."},
["016:19"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ejderhaların alevi... kaderimi mühürledi...", ["ORYG"]="The dragons' flame... sealed my fate..."},
["016:20"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yaşayanların dünyası artık beni teselli edemez.", ["ORYG"]="The world of the living can no longer comfort me."},
["016:21"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Tacı başıma koy Tirion.", ["ORYG"]="Place the crown upon my head, Tirion."},
["016:22"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Sonsuza dek lanetlilerin hapishanesi olacağım.", ["ORYG"]="Forevermore - I will be the jailor of the damned."},
["016:23"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Hayır, eski dostum. Yapamam.", ["ORYG"]="NO, old friend... I cannot..."},
["016:24"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="YAP ŞUNU, TIRION!", ["ORYG"]="DO IT, TIRION!"},
["016:25"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Senin ve bu cesur kahramanların tamamlamanız gereken kendi kaderiniz var.", ["ORYG"]="You and these brave heroes have your own destinies to fulfill."},
["016:26"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bu son hizmet benim.", ["ORYG"]="This last act of service... is mine."},
["016:27"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Unutulmayacaksın kardeşim.", ["ORYG"]="You will not be forgotten... brother."},
["016:28"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Unutulmalıyım, Tirion!", ["ORYG"]="I MUST be forgotten, Tirion!"},
["016:29"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Eğer dünya korkunun tiranlığından kurtulacaksa, bugün burada yapılanları asla bilmemeliler.", ["ORYG"]="If the world is to live free from the tyranny of fear - they must never know what was done here today."},
["016:30"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Onlara sadece Lich King'in öldüğünü söyle.", ["ORYG"]="Tell them only that the Lich King is dead..."},
["016:31"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ve Bolvar Fordragon'un da onunla birlikte öldüğünü söyle.", ["ORYG"]="and that Bolvar Fordragon died with him..."},
["016:32"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ŞİMDİ GİT.", ["ORYG"]="NOW GO."},
["016:33"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="BURAYI TERK EDIN VE ASLA GERI DÖNMEYIN.", ["ORYG"]="LEAVE THIS PLACE - AND NEVER RETURN."},
["021:01"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Neye dönüştüğüne bir bak.", ["ORYG"]="Look at what you've become."},
["021:02"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="O lanetli yaratıklar.", ["ORYG"]="Those cursed beasts …"},
["021:03"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="... sana sadece sefil bir melezden başka bir şey bırakmadılar.", ["ORYG"]="… they've left you nothing more than just another wretched mongrel."},
["021:04"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Arkadaşlarına ne yaptığını hatırlıyor musun?", ["ORYG"]="Do you even remember what you did to your friends?"},
["021:05"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Senin türün... vahşi doğada kontrolsüzce dolaşıyor...", ["ORYG"]="Your kind … haunting the wilds unchecked …"},
["021:06"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="... ta ki biz seni bulana kadar.", ["ORYG"]="… until we found you."},
["021:07"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Seni hayatta tuttular, çünkü hala kurtarılabileceğine inanıyorlar.", ["ORYG"]="They've kept you alive, because they still believe you can be saved."},
["021:08"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Sormak zorundayım.", ["ORYG"]="To which … I must ask"},
["021:09"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="İçinizde insanlıktan bir parça bile kaldı mı?", ["ORYG"]="Is there even a shred … of humanity left within you?"},
["021:10"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Belki de kalmıştır.", ["ORYG"]="Perhaps."},
["021:11"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yakında öğreneceğiz.", ["ORYG"]="We will find out … soon enough."},
["022:01"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Gövdeye inin sizi değersiz SLAAAAAAAAAAVES!", ["ORYG"]="Get down in the hull you worthless SLAAAAAAAAVES!"},
["022:02"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bunların hepsi sizin suçunuz!  Bu aptal köleleri günler önce Kalimdor'a götürmemiz gerekiyordu!", ["ORYG"]="This is all your fault!  We were supposed to have these stupid slaves to Kalimdor days ago!"},
["022:03"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bunun suçunu ben üstlenmeyeceğim, bizi kaybettiren sensin!", ["ORYG"]="I'm not taking the fall for this one, you're the one who got us lost!"},
["022:04"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ne fark eder ki?  Gallywix ikimizin de kellesini alacak!", ["ORYG"]="What does it matter?  Gallywix is gonna have both our heads!"},
["022:05"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Shh ... bunu duydun mu?", ["ORYG"]="Shh … did you hear that?"},
["022:06"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ahhhhhhhhh!", ["ORYG"]="Ahhhhhhhhh!"},
["022:07"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Kaptan, onlar kim?", ["ORYG"]="Captain, Who are they?"},
["022:08"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Önemli değil.  Bize verilen emir ne pahasına olursa olsun hedefi yakalamak.", ["ORYG"]="It doesn't matter.  Our orders are to capture the horde target at all costs."},
["022:09"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Tanık yok.", ["ORYG"]="No witnesses."},
["022:10"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="AHHHHHH!!! Gemiyi terk edin!  Kaçış kapsüllerine gidin!", ["ORYG"]="AHHHHHHH!!! Abandon ship!  Make for the escape pods!"},
["022:11"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Çıkarın bizi!  Bizi burada bırakmayın! ... lütfen ... ", ["ORYG"]="Let us out!  Don't leave us down here! … please … "},
["022:12"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bizi bırakmayın! Geri dön!  Hayır!", ["ORYG"]="Don't leave us! C-c-come back!  NoOOOoOOoo!"},
["027:01"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="10,000 yıl boyunca hapsedildim.", ["ORYG"]="Imprisoned for 10,000 years."},
["027:02"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Kendi vatanımdan sürgün edildim.", ["ORYG"]="Banished from my own homeland."},
["027:03"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ve şimdi benim diyarıma girmeye cüret ediyorsun.", ["ORYG"]="And now you dare enter MY realm."},
["027:04"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Hazır değilsin.", ["ORYG"]="You are not prepared."},
["027:05"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="HAZIR DEĞILSIN!", ["ORYG"]="YOU ARE NOT PREPARED!"},
["076:01"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Elementlerin uyandığını hissedebiliyorum;", ["ORYG"]="I can feel the elements awakening;"},
["076:02"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Seviniyorlar.", ["ORYG"]="rejoicing..."},
["076:03"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Felaket sona erdi.", ["ORYG"]="the Cataclysm is over."},
["076:04"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yanımızda savaşan şampiyonlar dünyamızın hayatta kalmasını sağladılar.", ["ORYG"]="The champions who fought at our side assured the survival of our world..."},
["076:05"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ama şimdi bunu ölümlü gözlerle görmeliyiz.", ["ORYG"]="but now we must see it, with mortal eyes"},
["076:06"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Biz ejderha yönleri büyük amacımızı yerine getirdik", ["ORYG"]="We dragon aspects have fulfilled our great purpose"},
["076:07"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ve kadim gücümüz.", ["ORYG"]="and our ancient power..."},
["076:08"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="tükeniyor.", ["ORYG"]="is expended."},
["076:09"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ama günümüz sona erse de, hayat devam edecek.", ["ORYG"]="But though our day draws to an end, life endures..."},
["076:10"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ve yeni nesiller doğacak. ", ["ORYG"]="and new generations will be born. "},
["076:11"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bugünün zaferi gölgeye karşı duran herkese aittir.", ["ORYG"]="Today's victory belongs to all who stood against the shadow."},
["076:12"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Sizler Azeroth'un gerçek koruyucularısınız.", ["ORYG"]="You are Azeroth's true Guardians..."},
["076:13"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ve bu dünyanın geleceği sizin ellerinizde.", ["ORYG"]="And the future of this world is in your hands..."},
["076:14"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ölümlüler çağının şafağı sökmeye başladı. ", ["ORYG"]="For the dawning of the age of mortals has begun. "},
["119:01"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Enkazda kapsamlı bir inceleme yaptık, Majesteleri.", ["ORYG"]="We've made a thorough inspection of the wreckage, Your Majesty."},
["119:02"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Amiral Taylor'dan ya da gemisinden hiçbir iz yok.", ["ORYG"]="There is no sign of Admiral Taylor or his ship."},
["119:03"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Emrimde iki yüz gemi var,", ["ORYG"]="Two hundred ships at my disposal,"},
["119:04"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ama oğlumu taşıyan kayıp!", ["ORYG"]="yet the one carrying my SON goes missing!"},
["119:05"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Son mesajları ne? Elinizde ne varsa bana gösterin!", ["ORYG"]="What of their last message? Show me whatever you have!"},
["119:06"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="...rotamızdan saptırıldık...Horde hava filosu...birçok kayıp...", ["ORYG"]="...we have been drawn off course...Horde airfleet...many casualties..."},
["119:07"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bilinmeyen bir adada kazaya uğradık. Ama Beyaz Piyon'a ulaşıldı.", ["ORYG"]="shipwrecked...on an uncharted isle...but the White Pawn is accounted for."},
["119:08"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Tekrar ediyorum: Beyaz Piyon güvende.", ["ORYG"]="Repeat: The White Pawn is safe."},
["119:09"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Anduin.", ["ORYG"]="Anduin..."},
["119:10"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="...sürpriz saldırı! Acil yardım talep ediyorum.", ["ORYG"]="...surprise attack! Requesting immediate--If anyone's receiving--"},
["119:11"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Efendim, Yedinci Filo çoktan gönderildi,", ["ORYG"]="Sir, the Seventh Fleet has already been dispatched,"},
["119:12"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ama haftalar sürebilir--", ["ORYG"]="but it could take weeks before it--"},
["119:13"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Kaybedecek zamanımız yok!", ["ORYG"]="There's no time to waste!"},
["119:14"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bu yeni toprakları güvence altına almak için küçük, seçkin bir kuvvet göndereceğiz.", ["ORYG"]="We'll send a small, elite force to secure this new land"},
["119:15"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ve oğlumu geri getirin!", ["ORYG"]="and bring back my SON!"},
["120:01"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Denizdeki savaşın iyi gittiğini bildirmekten memnuniyet duyuyorum, Savaş Şefi.", ["ORYG"]="I am pleased to report that the battle at sea goes well, Warchief."},
["120:02"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Kuvvetlerimiz Tanaris ve Tol Barad kıyılarında kesin zaferler bildirdi.", ["ORYG"]="Our forces report decisive victories off the coast of Tanaris and Tol Barad."},
["120:03"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="İttifak kanı dökülüyor. Bu beni memnun etti General.", ["ORYG"]="Alliance blood spills. This pleases me, General."},
["120:04"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Dahası da var. Güney filomuzun bir İttifak elçisiyle çarpıştığı haberini aldım.", ["ORYG"]="There is more... I've received word that our southern fleet engaged an Alliance envoy."},
["120:05"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Kraliyet amiral gemisini karaya oturana kadar takip ettik.", ["ORYG"]="We chased the royal flagship until it ran aground..."},
["120:06"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Karaya mı oturdu? Nereye?!", ["ORYG"]="Aground? Where?!"},
["120:07"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Görünüşe göre, yoğun sislerle örtülü, keşfedilmemiş devasa bir kara parçası bulmuşlar...", ["ORYG"]="Apparently, they found a massive uncharted landmass, shrouded, by dense mists..."},
["120:08"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ve sen oraya önce İTTİFAK'ın ulaşmasına izin mi verdin?!  İstila filosunu yönlendirin!", ["ORYG"]="And you let the ALLIANCE get there first?!  Redirect the invasion fleet!"},
["120:09"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="General, siz ve en iyi gazileriniz yolumuzu açacaksınız.", ["ORYG"]="General, YOU and your best veterans will pave our way..."},
["120:10"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Kıyıya saldırın ve bu yeni kıtayı kırmızıya boyayın!", ["ORYG"]="STORM the shore and PAINT THIS NEW CONTINENT RED!"},
["151:01"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Beni hayal kırıklığına uğrattın, Garrosh.", ["ORYG"]="You disappoint me, Garrosh."},
["151:02"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Beni hayal kırıklığına uğrattın, Garrosh.", ["ORYG"]="You disappoint me, Garrosh."},
["151:03"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Babanın mirasına layık değilsin.", ["ORYG"]="You are not worthy of your father’s legacy."},
["151:04"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Onun cezasına sadece sen karar veremezsin.", ["ORYG"]="His punishment is not for you alone to decide."},
["151:05"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Onu almana izin vermeyeceğim.", ["ORYG"]="I won’t let you take him."},
["151:06"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Hepimiz onun zulmünden acı çektik.", ["ORYG"]="We have all suffered from his atrocities."},
["151:07"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Benim halkım, diğerlerinden daha fazla.", ["ORYG"]="My people, more than any other."},
["151:08"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bırakın Pandaria'da yargılansın.", ["ORYG"]="Let him stand trial in Pandaria."},
["151:09"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Orada, herkes için adaleti sağlayacağız.", ["ORYG"]="There, we will mete out justice for all."},
["151:10"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Horde'un gerçek Savaş Şefi'ne ihtiyacı var.", ["ORYG"]="The Horde needs its true Warchief now, more than ever."},
["151:11"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Evet ama bu çılgınlık sırasında Horde'u bir arada tutan sendin.", ["ORYG"]="Yes, but It was you that held the Horde together during this madness."},
["151:12"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Onurumuzu koruyan sendin.", ["ORYG"]="It was you that protected our honor."},
["151:13"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bugünden itibaren Vol'jin, sen önderlik edersen ben de takip edeceğim.", ["ORYG"]="From this day forward, Vol’jin - If you lead, I will follow."},
["151:14"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ben buna layık değilim.", ["ORYG"]="I am not worthy…"},
["151:15"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ama her şeyimi vereceğim.", ["ORYG"]="But I will give my all."},
["151:16"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Horde için.", ["ORYG"]="For the Horde."},
["151:17"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Warchief'inizle konuşacağım!", ["ORYG"]="I will speak to your Warchief!"},
["151:18"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Horde adına konuşuyorum.", ["ORYG"]="I speak for the Horde."},
["151:19"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Pekala.", ["ORYG"]="Very well."},
["151:20"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Horde iğrenç suçlar işledi, Vol'jin.", ["ORYG"]="The Horde has committed heinous crimes, Vol’jin."},
["151:21"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ama aranızdan bazıları Garrosh'un zulmüne karşı savaştı.", ["ORYG"]="But some among you fought against Garrosh’s tyranny."},
["151:22"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bunun için, bu kan dökülmesine son vermeye hazırım.", ["ORYG"]="For that, I am willing to end this bloodshed."},
["151:23"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ama şunu bilin ki.", ["ORYG"]="But know this…"},
