["188:08"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Işıkta biz biriz.", ["ORYG"]="In the light we are one."},
["188:09"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Şimdi anlıyorum ki sen asla bize ait değildin Durotan.", ["ORYG"]="I see now you never belonged with us, Durotan."},
["188:10"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bizim bağımız demirdir.", ["ORYG"]="Our bond is iron"},
["188:11"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ama sen çok kolay kırılıyorsun.", ["ORYG"]="But you are so easily...broken."},
