["188:13"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Kafanı.", ["ORYG"]="Your head."},
["188:14"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Top yerini aldı.", ["ORYG"]="The cannon is in position."},
["188:15"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Emrinizde.", ["ORYG"]="On you command."},
["188:16"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ateşe hazır olun.", ["ORYG"]="Prepare to fire."},
["188:17"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Böyle bir kibir, inanmak", ["ORYG"]="Such arrogance, to believe"},
["188:18"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Tek başına beni yenebileceğini.", ["ORYG"]="that you alone could defeat me."},
["188:19"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Birlikte...", ["ORYG"]="Together..."},
["188:20"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bekle! Yaşıyorlar!", ["ORYG"]="Wait! They're alive!"},
["188:21"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Onları yakaladım.", ["ORYG"]="I've got them."},
["188:22"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Hepiniz öleceksiniz!", ["ORYG"]="You will all die!"},
["188:23"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Sadece sen öleceksin.", ["ORYG"]="Just you."},
["189:01"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Kahramanlıkların sana bu Frostwolf topraklarını kazandırdı.", ["ORYG"]="Your heroic deeds have earned you this Frostwolf land."},
