["189:03"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Komutanım.", ["ORYG"]="Commander."},
["190:01"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Sizi ve ordularınızı Draenor'da pek çok zorlu savaşı kazanırken gördüm.", ["ORYG"]="I have seen you and your armies win many hard fought battles across Draenor."},
