["192:03"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Komutanım.", ["ORYG"]="Commander."},
["193:01"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bana ilham verdiniz Komutan.", ["ORYG"]="You have inspired me, Commander."},
["193:02"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Sizi ve ordularınızı Draenor'da pek çok zorlu savaşı kazanırken gördüm.", ["ORYG"]="I've seen you and your armies win many hard fought battles across Draenor."},
