["295:01"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Gul'dan!", ["ORYG"]="Gul'dan!"},
["295:02"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bir anlaşma yaptınız.", ["ORYG"]="You made a pact."},
["295:03"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bitti.", ["ORYG"]="It's...done."},
["295:04"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Gul'dan... başarısız oldu.", ["ORYG"]="Gul'dan... failed."},
["295:05"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Draenor özgür!", ["ORYG"]="Draenor is free!"},
["295:06"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bittiğini düşünmüyorsun.", ["ORYG"]="You don't think it's over."},
["295:07"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Gul'dan ve ona komuta eden şeytanlar,", ["ORYG"]="Gul'dan and the devils that command him,"},
["295:08"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="o kadar kolay kovulamazlar.", ["ORYG"]="are not so easily banished."},
["295:09"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Korkarım bu sadece başlangıç.", ["ORYG"]="I fear this is only beginning."},
["295:10"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Eğer bize ihtiyacınız olursa", ["ORYG"]="If you ever need us"},
["295:11"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="burada olacağız.", ["ORYG"]="we will be here."},
["295:12"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Tekrar buluşana kadar.", ["ORYG"]="Until we meet again."},
["295:13"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Büyük bir adam bir keresinde bana şöyle demişti:", ["ORYG"]="A great man once told me:"},
["295:14"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Işıkta, biz biriz.", ["ORYG"]="In the light, we are one."},
["295:15"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Gelecek bizimdir.", ["ORYG"]="The future is ours."},
["295:16"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ve Draenor'un yeniden inşa edildiğini göreceğiz.", ["ORYG"]="And we will see Draenor rebuilt"},
["295:17"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Birlikte.", ["ORYG"]="together."},
["304:01"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Burada yüzünü göstermeye nasıl cüret edersin, Warlock.", ["ORYG"]="How dare you show your face here, Warlock."},
["304:02"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Fetih sözü verdin, Grommash.", ["ORYG"]="You promised conquest, Grommash..."},
["304:03"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ama bu klanları mahvettin.", ["ORYG"]="yet brought these clans to ruin."},
["304:04"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Adamların bir hiç uğruna öldü!", ["ORYG"]="Your men have died for nothing!"},
["304:05"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Benim askerlerim onurlarıyla öldüler!", ["ORYG"]="My soldiers died with honor!"},
["304:06"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Öldüler mi?", ["ORYG"]="Did they?"},
["304:07"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Peki ya...", ["ORYG"]="And what about..."},
["304:08"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Oğlun?", ["ORYG"]="your son?"},
["304:09"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Garrosh...", ["ORYG"]="Garrosh..."},
["304:10"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="benim... oğlum...", ["ORYG"]="my... son..."},
["304:11"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Her şeyini kaybettin.", ["ORYG"]="You have lost everything."},
["304:12"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Tek bir seçeneğin var.", ["ORYG"]="There is only one choice."},
["304:13"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="İç ve kaderini gerçekleştir.", ["ORYG"]="Drink, and fulfill your destiny."},
["304:14"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Zehrin.", ["ORYG"]="Your poison..."},
["304:15"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="hepimizi lanetleyecek!", ["ORYG"]="would damn us all!"},
["304:16"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Demir iraden bir efsane.", ["ORYG"]="Your iron will is legend."},
["304:17"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Seni kırmaktan zevk alacağım.", ["ORYG"]="I will enjoy breaking you."},
["304:18"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bu hediyeyi ilk kabul eden kim olacak?", ["ORYG"]="Who will be the first to accept this gift?"},
["304:19"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Hizmet etmek isteyen herkes için benimki gibi bir güç.", ["ORYG"]="Power such as mine for any willing to serve."},
["304:20"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Kilrogg.", ["ORYG"]="Kilrogg..."},
["304:21"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Kaderini gördün.", ["ORYG"]="You have seen your fate."},
["304:22"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ne yapılması gerektiğini biliyorsun.", ["ORYG"]="You know what must be done."},
["304:23"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Kilrogg!", ["ORYG"]="Kilrogg!"},
["304:24"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Evet.", ["ORYG"]="Yes..."},
["304:25"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yeni bir Horde inşa edeceğim.", ["ORYG"]="I will build a new Horde."},
["304:26"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Seni durdurulamaz bir silaha dönüştüreceğim.", ["ORYG"]="I will forge you into an unstoppable weapon."},
["304:27"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yüzlerce dünyanın belası olacaksın.", ["ORYG"]="You will be the scourge of a hundred worlds."},
["304:28"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bir Lejyon'un kudreti.", ["ORYG"]="The might of a Legion."},
["469:01"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Outland: Yıllar Önce", ["ORYG"]="Outland: Years Ago"},
["469:02"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="İllidari", ["ORYG"]="Illidari"},
["469:03"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="İblis Avcılarımı", ["ORYG"]="My Demon Hunters"},
["469:04"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Lejyon'un ardından sayısız dünya yanarken", ["ORYG"]="With countless worlds burning in the Legion’s wake"},
["469:05"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="çağrıya cevap verdin", ["ORYG"]="you answered the call"},
["469:06"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yine de bu ölümlüler", ["ORYG"]="Yet these mortals in their"},
["469:07"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Cehalet", ["ORYG"]="ignorance"},
["469:08"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="kendi kurtuluşlarını yok etmeye geldiler.", ["ORYG"]="have come to destroy their own salvation."},
["469:09"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Zamanımız kısa.", ["ORYG"]="Our time is short."},
["469:10"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bu davetsiz misafirlerle ben ilgileneceğim.", ["ORYG"]="I will deal with these intruders."},
["469:11"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Mardum'a gitmelisin.", ["ORYG"]="You must venture to Mardum"},
["469:12"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ve Sargerite kilit taşını al.", ["ORYG"]="and retrieve the Sargerite keystone."},
["469:13"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Şimdi git.", ["ORYG"]="Now go."},
["469:14"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ama unutma", ["ORYG"]="But remember"},
["469:15"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="başarısız olursan", ["ORYG"]="should you fail"},
["469:16"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="tüm dünyalar yanacak.", ["ORYG"]="all worlds will burn."},
["471:01"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Hayır! Hayır!", ["ORYG"]="No!"},
["471:02"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Lord Illidan düştü!", ["ORYG"]="Lord Illidan has fallen!"},
["471:03"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Illidari! Efendinin intikamını alın!", ["ORYG"]="Illidari! Avenge the master!"},
["471:04"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Onun yozlaşmasının izini taşıyorsun.", ["ORYG"]="You bear the mark of his corruption."},
["471:05"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ve böylece içindeki şeytanın kanı", ["ORYG"]="And so the demon’s blood within you"},
["471:06"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="senin hapishanen olacak.", ["ORYG"]="will be your prison."},
