["474:05"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="yakında beni alacak.", ["ORYG"]="will claim me soon."},
["474:06"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Sonunda, ölüm hepimizi alır.", ["ORYG"]="In the end, death claims us all"},
["474:07"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ama Horde yaşamaya devam edecek.", ["ORYG"]="but the Horde will live on."},
