["474:12"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="bizi kurtaracak kişi olacağını düşündüm.", ["ORYG"]="would be da one to save us."},
["474:13"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ruhlar bana açıklık verdi.", ["ORYG"]="Da spirits have granted me clarity."},
["474:14"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bir vizyon.", ["ORYG"]="A vision"},
["474:15"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bir isim fısıldarlar", ["ORYG"]="dey whisper a name"},
