["474:21"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Vol'jin öldü.", ["ORYG"]="Vol’jin is dead."},
["474:22"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Aranızda kim", ["ORYG"]="Who among you"},
["474:23"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="onun intikamını almama yardım edecek.", ["ORYG"]="will help me avenge him."},
