["478:01"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Hazırlıklı değildiniz.", ["ORYG"]="You were not prepared."},
["478:02"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Düşman dünyamıza geldi.", ["ORYG"]="The enemy came into our world"},
["478:03"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Tek arzuları tüm yaşamı yok etmekti.", ["ORYG"]="their only desire to extinguish all life."},
["478:04"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Sevdiklerimizi katlettiler.", ["ORYG"]="They slaughtered our loved ones."},
["478:05"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Evlerimizi yerle bir ettiler.", ["ORYG"]="They razed our homes"},
["478:06"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ŞEHİRLERİMİZ", ["ORYG"]="our cities"},
["478:07"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ve kutsal yerlerimiz.", ["ORYG"]="and our sacred places."},
["478:08"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Onları durdurmaya çalıştınız.", ["ORYG"]="You tried to stop them"},
["478:09"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ve başarısız oldun.", ["ORYG"]="and you failed."},
["478:10"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ve sen de bana geldin.", ["ORYG"]="And so you came to me"},
["478:11"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Öfke ve kararlılıktan başka bir şey kalmadı.", ["ORYG"]="nothing remaining of you but rage and determination."},
["478:12"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ve bir zamanlar sana eziyet eden şeylerin", ["ORYG"]="And you learned that the things that once tormented you"},
["478:13"]={["START"]=0, ["STOP"]=0, ["NAPIS"]=" sana güç verebilir.", ["ORYG"]=" could give you power."},
["478:14"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Şimdi görüyorsun.", ["ORYG"]="Now you see"},
["478:15"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="hiçbir fedakarlık çok büyük değildir", ["ORYG"]="that there is no sacrifice too great"},
["478:16"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yanan Lejyon'un sonunu getirecekse.", ["ORYG"]="if it brings an end to the Burning Legion."},
["478:17"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ama", ["ORYG"]="But"},
["478:18"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Lord Illidan", ["ORYG"]="Lord Illidan"},
["478:19"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Şeytani enerjiler damarlarımızda dolaşıyor.", ["ORYG"]="demonic energies course through our veins."},
["478:20"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Her düşüncemizi kemiriyorlar.", ["ORYG"]="They gnaw at our every thought."},
["478:21"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bizi savaştığımız canavarlardan farklı kılan ne?", ["ORYG"]="What makes us any different from the monsters we fight?"},
["478:22"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Efendiyi mi sorguluyorsun?", ["ORYG"]="You question the master?"},
["478:23"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Azeroth'takiler gibi boş boş oturmayacağız.", ["ORYG"]="We will not sit idly like those on Azeroth"},
["478:24"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="İblislerin avı olmak için bekliyorlar.", ["ORYG"]="waiting to become the demons' prey."},
["478:25"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bu savaşı Lejyon'un dünyalarına götüreceğiz.", ["ORYG"]="We will take this war to the Legion's worlds"},
["478:26"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ve onları avla!", ["ORYG"]="and prey upon them!"},
["478:27"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ah", ["ORYG"]="Ah"},
["478:28"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="İblis Avcıları.", ["ORYG"]="Demon Hunters."},
["478:29"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Kıyamet Lordu Azgoth'a kendi bölgesinde saldırmaya cüret mi ediyorsunuz?", ["ORYG"]="You dare attack the Doom Lord Azgoth, in his own domain?"},
["478:30"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Göreviniz başarısız oldu.", ["ORYG"]="Your mission has failed."},
["478:31"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Davanız onunla birlikte ölecek!", ["ORYG"]="Your cause dies with him!"},
["478:32"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Avcıdan çok iblis kokuyorsun.", ["ORYG"]="You smell more of demon than hunter."},
["478:33"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bize iyi hizmet edeceksin.", ["ORYG"]="You would serve us well."},
["478:34"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Asla!", ["ORYG"]="Never!"},
["478:35"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Sen", ["ORYG"]="You"},
["478:36"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="İblisler ve bizim aramızdaki farkı bilmek ister misiniz?", ["ORYG"]="wish to know the difference between the demons and us?"},
["478:37"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Onlar dünyamızı yok etmek için her şeyi yaparlar.", ["ORYG"]="They will stop at nothing to destroy our world."},
["478:38"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ve biz de onu kurtarmak için her şeyimizi feda edeceğiz.", ["ORYG"]="And we will sacrifice everything to save it."},
["478:39"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Lejyon bu zaferden haberdar olacak.", ["ORYG"]="The Legion will know of this victory"},
["478:40"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ve senden korkacaklar", ["ORYG"]="and they will fear you"},
["478:41"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Illidari'm.", ["ORYG"]="my Illidari."},
["478:42"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Şimdi", ["ORYG"]="Now"},
["478:43"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="hazırsınız!", ["ORYG"]="you are prepared!"},
["485:01"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="10,000 yıl önce", ["ORYG"]="10,000 years ago"},
["485:02"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Şehrim ışıl ışıldı.", ["ORYG"]="My city was radiant..."},
["485:03"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Gece Elf İmparatorluğu'nun Mücevheri", ["ORYG"]="The Jewel of the Night Elf Empire"},
["485:04"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Suramar", ["ORYG"]="Suramar"},
["485:05"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Halkımız yüzyıllar boyunca refah içinde yaşadı.", ["ORYG"]="Our people prospered for centuries ..."},
["485:06"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Lejyon gelene kadar.", ["ORYG"]="Until the Legion came."},
["485:07"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Sundukları güçle büyülendiler", ["ORYG"]="Entranced by the power they offered"},
["485:08"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Kraliçemiz bize ihanet etti.", ["ORYG"]="our queen betrayed us ..."},
["485:09"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="dünyanın yıkımına.", ["ORYG"]="to the ruin of the world."},
["485:10"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yıkım yaklaştıkça", ["ORYG"]="As destruction drew ever closer"},
["485:11"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="umutsuz bir seçim yapıldı...", ["ORYG"]="a desperate choice was made ..."},
["485:12"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Güçlü bir kalkan yaratmak için", ["ORYG"]="To conjure a powerful shield"},
["485:13"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="sevgili şehrimizi kurtaracaktı.", ["ORYG"]="that would save our beloved city."},
["485:14"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="İşe yaradı.", ["ORYG"]="It worked."},
["485:15"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yüzyıllar geçti.", ["ORYG"]="Centuries passed."},
["485:16"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ay ışığı olmadan", ["ORYG"]="Without moonlight"},
["485:17"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Güneş ışığı olmadan", ["ORYG"]="Without sunlight"},
["485:18"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Hayatta kalmak için Nightwell'e başvurduk.", ["ORYG"]="To survive, we turned to the Nightwell"},
["485:19"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Şehrin kalbinde büyük bir güç kaynağı.", ["ORYG"]="a font of great power in the city's heart."},
["485:20"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yavaş yavaş...", ["ORYG"]="Slowly ..."},
["485:21"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bizi değiştirdi.", ["ORYG"]="It changed us"},
["485:22"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ve nihayetinde...", ["ORYG"]="and ultimately ..."},
["485:23"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Lejyon'u bir kez daha kapılarımıza çekti.", ["ORYG"]="drew the Legion once more to our gates."},
["485:24"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bize bir takas önerdiler.", ["ORYG"]="They offered us a trade."},
["485:25"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Nightwell", ["ORYG"]="The Nightwell"},
["485:26"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="hayatlarımız için.", ["ORYG"]="for our lives."},
["485:27"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yaşlılar teslimiyetlerini planlarken", ["ORYG"]="As the Elders planned their surrender"},
["485:28"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="bazılarımız ...", ["ORYG"]="some of us ..."},
["485:29"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="isyan etti.", ["ORYG"]="rebelled."},
["485:30"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Başarısız olduk.", ["ORYG"]="We failed."},
["485:31"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Şimdi Şeytanlar Suramar'ı ele geçirdi.", ["ORYG"]="Now the Devils have taken Suramar."},
["485:32"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ve Nightwell'in lanetiyle", ["ORYG"]="And by the curse of the Nightwell"},
["485:33"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Solup gitmeye lanetlendim...", ["ORYG"]="I am damned to Wither away ..."},
["485:34"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Benim ...", ["ORYG"]="As my ..."},
["485:35"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Şehrim ...", ["ORYG"]="City ..."},
["485:36"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yanıyor.", ["ORYG"]="Burns."},
