["487:10"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ve Windrunner'ın okçuları gökyüzünü temizlesin!", ["ORYG"]="And get Windrunner’s archers to clear the skies!"},
["487:11"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Hayır!", ["ORYG"]="No"},
