["489:01"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Azeroth için.", ["ORYG"]="Azeroth ..."},
["489:02"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Dua ediyorum ki bu, Işığın Ordusu'nun son savunması", ["ORYG"]="I pray that this, the final plea of the Army of the Light"},
["489:03"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="size sağlam bir şekilde ulaştı.", ["ORYG"]="has reached you intact."},
["489:04"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bin yıllık savaş zirveye ulaştı.", ["ORYG"]="The thousand years' war has reached its peak"},
["489:05"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ama kabus henüz bitmedi.", ["ORYG"]="but the nightmare is far from over."},
["489:06"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bu gemi nihai fedakarlığımızı temsil ediyor.", ["ORYG"]="This vessel represents our ultimate sacrifice."},
["489:07"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Peygambere ulaşmalı.", ["ORYG"]="It must reach the prophet."},
["489:08"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Anahtar o.", ["ORYG"]="He ... is the key."},
["489:09"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Hiçbirimiz bu yükü istemedik.", ["ORYG"]="None of us asked for this burden"},
["489:10"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ama kaderin hükmü bu.", ["ORYG"]="but it is what fate has deemed."},
["489:11"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Başarılı olursan, ışık devam edebilir.", ["ORYG"]="Succeed, and the light may yet endure."},
["489:12"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Başarısız olursan, tüm dünyalar", ["ORYG"]="Fail, and all worlds ..."},
["489:13"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="yanar.", ["ORYG"]="will burn."},
["489:14"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Başarısız olmayacağız", ["ORYG"]="We will not fail"},
["489:15"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Turalyon.", ["ORYG"]="Turalyon."},
["490:01"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Görevden alındınız: Illidan", ["ORYG"]="You are relieved of duty: Illidan"},
["490:02"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Beni kovdun Cenarius!", ["ORYG"]="You have cast me out Cenarius!"},
["490:03"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Öfken yanlış yerde ...", ["ORYG"]="Your anger is misplaced ..."},
["490:04"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Hepsini öldürdün Illidan!", ["ORYG"]="You've killed them all Illidan!"},
["490:05"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="NE YAPTIN SEN?!", ["ORYG"]="WHAT HAVE YOU DONE?!"},
["490:06"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bu yolda yürümek fedakarlık gerektirir, Illidan.", ["ORYG"]="To walk this path requires sacrifice, Illidan ..."},
["490:07"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Senin henüz anlayamadığın bir şey.", ["ORYG"]="something you have yet, to understand."},
["490:08"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Tyrande.", ["ORYG"]="Tyrande ..."},
