["635:01"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Şampiyonlar, Nighthold'daki zaferiniz", ["ORYG"]="Champions, your victory at the Nighthold"},
["635:02"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="bize bu savaşı sona erdirmenin anahtarını verdi.", ["ORYG"]="has granted us the key to ending this war."},
["635:03"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yaratılış Sütunları'nın bir araya gelmesiyle", ["ORYG"]="With the Pillars of Creation assembled"},
["635:04"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="sonunda gücümüz var", ["ORYG"]="we finally have the power"},
["635:05"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="İblisleri dünyamızdan koparmak için.", ["ORYG"]="to cut the demons off from our world."},
["635:06"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Gul'dan başarısız oldu, Lejyon da öyle olacak.", ["ORYG"]="Gul’dan failed, and so shall the Legion."},
["635:07"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Gul'dan.", ["ORYG"]="Gul’dan…"},
["635:08"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="...sadece onların piyonuydu.", ["ORYG"]="… was merely their pawn."},
["635:09"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Zafer kesinleşene kadar", ["ORYG"]="Until victory is assured"},
["635:10"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="uyanık kalmalıyız", ["ORYG"]="we must remain vigilant"},
["635:11"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Lejyon'un gerçek efendileri için", ["ORYG"]="for the Legion’s true masters"},
["635:12"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="henüz kendilerini göstermediler.", ["ORYG"]="have yet to reveal themselves."},
["635:13"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bunların arasında", ["ORYG"]="Among them"},
["635:14"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="avlayan bir canavar", ["ORYG"]="a monster who hunted"},
["635:15"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yıldızların ötesindeki halkım.", ["ORYG"]="my people across the stars…"},
["635:16"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Kil'jaeden.", ["ORYG"]="Kil’jaeden."},
["635:17"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Fel ateşini damarlarıma aldığım gün", ["ORYG"]="The day I took the fel fire into my veins"},
["635:18"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Kaderimi gördüm.", ["ORYG"]="I saw my destiny."},
["635:19"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Büyük bir haçlı seferi", ["ORYG"]="A grand crusade"},
["635:20"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="yaratılışın sonuna ulaşacaktı.", ["ORYG"]="that would reach the ends of creation."},
["635:21"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bana gösterdiğin vizyon buydu.", ["ORYG"]="That was the vision you showed me."},
["635:22"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Haçlı Seferimiz galip gelecektir.", ["ORYG"]="Our Crusade will prevail."},
["635:23"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yaptığımız her şey", ["ORYG"]="Everything we have done"},
["635:24"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="senin tasarımınla oldu.", ["ORYG"]="has been by your design."},
["635:25"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ve bunun için göstermemiz gereken tek şey başarısızlık.", ["ORYG"]="And all we have to show for it is failure."},
["635:26"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Belki de kaderimizi gözden kaçırdın.", ["ORYG"]="Perhaps you’ve lost sight of our destiny."},
["635:27"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Belki de kararlılığınızı abartmışımdır.", ["ORYG"]="Perhaps I overestimated your resolve."},
["635:28"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bu kaderin bedelini dünyamla ödedim.", ["ORYG"]="I paid for that destiny with my world."},
["635:29"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bittiğini görmenin zamanı geldi.", ["ORYG"]="The time has come to see it done."},
["635:30"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yak onu... küle çevir.", ["ORYG"]="Burn it... to ash."},
["656:01"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Kaderlerimiz artık bir.", ["ORYG"]="Our fates are now one."},
["656:02"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Argus senin mezarın olacak.", ["ORYG"]="Argus will be your tomb."},
["656:03"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="En azından savaşarak ölmüş olacağız.", ["ORYG"]="At least we will have died fighting."},
["656:04"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Savaşımız henüz bitmedi.", ["ORYG"]="Our war isn’t over yet."},
["656:05"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Tüm dünyaların anahtarı elimizdeyken değil.", ["ORYG"]="Not while we hold the key to all worlds."},
["656:06"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Khadgar, bizi eve götür!", ["ORYG"]="Khadgar, take us home!"},
["656:07"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ben hep...", ["ORYG"]="I was always..."},
["656:08"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="...seni kıskanmışımdır.", ["ORYG"]="...envious of you."},
["656:09"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yeteneğini.", ["ORYG"]="Your gift."},
["656:10"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="İnancını.", ["ORYG"]="Your faith."},
["656:11"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Vizyonunu.", ["ORYG"]="Your vision."},
["656:12"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Hiç inanmadım.", ["ORYG"]="I never believed..."},
["656:13"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="...Sargeras'ın durdurulabileceğine.", ["ORYG"]="...that Sargeras could be stopped."},
["656:14"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Belki de yanıldığımı kanıtlayacaksın.", ["ORYG"]="Perhaps you will prove me wrong."},
["656:15"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Herkes hazırlansın! Hazır olun!", ["ORYG"]="Everyone! Get ready!"},
["656:16"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Herkes iyi mi?", ["ORYG"]="Is everyone alright?"},
["656:17"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ne yaptın sen?", ["ORYG"]="What have you done?"},
["656:18"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bazen kaderin eli.", ["ORYG"]="Sometimes the hand of fate..."},
["656:19"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="...zorlanmalıdır.", ["ORYG"]="...must be forced."},
["678:01"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Tüm kuvvetler gemide ve hazır.", ["ORYG"]="All forces are on board and accounted for."},
["678:02"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Vindicaar hazır olacak.", ["ORYG"]="The Vindicaar will be ready"},
["678:03"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="kısa süre içinde yola çıkacağız.", ["ORYG"]="to depart shortly."},
["678:04"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Argus'a ulaştıktan sonra", ["ORYG"]="After we reach Argus"},
["678:05"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Işığın Ordusu ile buluşacağız.", ["ORYG"]="we will meet with the Army of the Light"},
["678:06"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ve istilamıza başlayacağız.", ["ORYG"]="and begin our invasion."},
["678:07"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Anlıyor mu?", ["ORYG"]="Does he understand"},
["678:08"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ondan gerçekten ne istediğinizi biliyor musunuz?", ["ORYG"]="what you're truly asking of him?"},
["678:09"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Herhangi biri mi?", ["ORYG"]="Do any of them?"},
["678:10"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Işığın yolunu takip ediyoruz", ["ORYG"]="We follow the path of the Light"},
["678:11"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="nereye götürürse götürsün.", ["ORYG"]="no matter where it leads."},
["678:12"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="İnancın her zaman senin zayıflığın oldu.", ["ORYG"]="Your faith has always been your weakness."},
["678:13"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="En yakın müttefiklerin karanlığa düştüğünde", ["ORYG"]="When your closest allies fell to darkness"},
["678:14"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Onları durdurmadın.", ["ORYG"]="you didn’t stop them."},
["678:15"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Lejyon dünyanızı süpürdüğünde", ["ORYG"]="When the Legion swept over your world"},
["678:16"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ve halkınızı aldı..", ["ORYG"]="and took your people..."},
["678:17"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="karşı koymadınız.", ["ORYG"]="you didn’t make a stand."},
["678:18"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Tek yaptığınız ikna olmuş bir şekilde izlemekti.", ["ORYG"]="All you did was watch convinced"},
["678:19"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Işığın iradesini takip ediyordunuz.", ["ORYG"]="you were following the Light’s will."},
["678:20"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Gerçek şu ki, halkınızı hayal kırıklığına uğrattınız.", ["ORYG"]="The truth is, you failed your people."},
["678:21"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Onların kanı senin ellerinde.", ["ORYG"]="Their blood is on your hands."},
["678:22"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ne yaptığımı asla anlayamayacaksın.", ["ORYG"]="You will never understand what I did"},
["678:23"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Halkımı kurtarmak için.", ["ORYG"]="to save my people."},
["678:24"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Işık seni geride tutuyor.", ["ORYG"]="The Light is holding you back."},
["678:25"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Kendi yolunu çizmenin zamanı geldi.", ["ORYG"]="It’s time to forge your own path."},
["678:26"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Kahin, biz hazırız.", ["ORYG"]="Prophet, we are ready."},
["678:27"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Devam edin.", ["ORYG"]="Proceed."},
["678:28"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Işık Ordusu nerede?", ["ORYG"]="Where is your Army of the Light?"},
["678:29"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Xenedar.", ["ORYG"]="The Xenedar..."},
["678:30"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bir terslik var.", ["ORYG"]="Something is wrong."},
["678:31"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Korkaklar saklandıkları yerden çıktılar.", ["ORYG"]="The cowards have come out of hiding."},
["678:32"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="İndirin onları!", ["ORYG"]="Bring them down!"},
["678:33"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Lejyon yakında tekrar ateş edecek!", ["ORYG"]="The Legion will fire again soon!"},
["678:34"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Emirleriniz nedir, Kahin?", ["ORYG"]="What are your orders, Prophet?"},
["678:35"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Duruşumuzu yapacağız.", ["ORYG"]="We make our stand."},
["678:36"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Argus için son savaş.", ["ORYG"]="The last battle for Argus..."},
["678:37"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="...başladı.", ["ORYG"]="...has begun."},
["680:01"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Biz kutsanmışız.", ["ORYG"]="We are blessed"},
["680:02"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="bir kez daha huzurunda olmaktan mutluluk duyuyorum, Xe'ra.", ["ORYG"]="to be in your presence once more, Xe’ra."},
["680:03"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Turalyon.", ["ORYG"]="Turalyon…"},
["680:04"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Seçilmiş kişiyi buldunuz.", ["ORYG"]="You have found the chosen one."},
["680:05"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Illidan.", ["ORYG"]="Illidan."},
["680:06"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Doğduğundan beri, gözlerindeki ışık", ["ORYG"]="From birth, the light in your eyes"},
["680:07"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="gelecek için umut vaat ediyordu.", ["ORYG"]="held such promise for the future."},
["680:08"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Doğuştan gelen bu hakkı uzun zaman önce feda ettim.", ["ORYG"]="I sacrificed that birthright long ago."},
["680:09"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Kaybettiğin şeyi geri almak istemiyor musun?", ["ORYG"]="Do you not wish to reclaim what was lost?"},
["680:10"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Tekrar bir bütün olmayı?", ["ORYG"]="To be whole again?"},
["680:11"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Lejyon'un sonu.", ["ORYG"]="The Legion’s end..."},
["680:12"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="aradığım tek şey.", ["ORYG"]="is all I seek."},
["680:13"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Çocuğum benim.", ["ORYG"]="My child."},
["680:14"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Çok az şey için çok şey verdin.", ["ORYG"]="You’ve given so much, for so little."},
["680:15"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Gerçek potansiyelin, kurtuluşun", ["ORYG"]="Your true potential, your redemption"},
["680:16"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="önünüzde uzanıyor.", ["ORYG"]="lies before you."},
["680:17"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bırak parçalanmış formunu", ["ORYG"]="Let go of your shattered form"},
["680:18"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ve Işığın gücünü kucaklamak.", ["ORYG"]="and embrace the Light’s power."},
["680:19"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Daha önce de güç için özgürlüğümü takas etmiştim.", ["ORYG"]="I’ve traded my freedom for power before."},
["680:20"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Kehanet.", ["ORYG"]="The prophecy..."},
["680:21"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="yerine getirilmeli.", ["ORYG"]="must be fulfilled."},
["680:22"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Eski hayatın geçti.", ["ORYG"]="Your old life has passed."},
["680:23"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Işık sana yeni bir hayat kuracak.", ["ORYG"]="The Light will forge you a new one."},
["680:24"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bu senin değil!", ["ORYG"]="It is not yours to take!"},
["680:25"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Işık yaralarını iyileştirecek.", ["ORYG"]="The Light will heal your scars."},
["680:26"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ben yaralarımım!", ["ORYG"]="I am my scars!"},
["680:27"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Işık senin kaderin.", ["ORYG"]="The Light is your destiny."},
["680:28"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Benim kaderim benim kaderim!", ["ORYG"]="My destiny is my own!"},
["680:29"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Hepimizi mahkum ettin!", ["ORYG"]="You've doomed us all!"},
["680:30"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Hain!", ["ORYG"]="Betrayer!"},
["680:31"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="İnancın seni kör etmiş.", ["ORYG"]="Your faith has blinded you."},
["680:32"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Seçilmiş biri olamaz.", ["ORYG"]="There can be no chosen one."},
["680:33"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Sadece biz...", ["ORYG"]="Only we..."},
["680:34"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="kendimizi kurtarabiliriz.", ["ORYG"]="can save ourselves."},
["686:01"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Pantheon'un koltuğu.", ["ORYG"]="The seat of the Pantheon."},
["686:02"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Çaldığınız şey", ["ORYG"]="That which you have stolen"},
["686:03"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="senin felaketin olacak.", ["ORYG"]="will be your undoing."},
["686:04"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Kalk, Argus.", ["ORYG"]="Rise, Argus."},
["686:05"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yüksel, benim kırık dünyam.", ["ORYG"]="Rise, my broken world."},
["686:06"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ölümlüler.", ["ORYG"]="Mortals..."},
["686:07"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Savaşma zamanı geldi", ["ORYG"]="The time has come to fight"},
["686:08"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="dünyanızın kaderi için.", ["ORYG"]="for the fate of your world."},
["688:01"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="İyi iş çıkardınız ölümlüler.", ["ORYG"]="You have done well, mortals."},
["689:01"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="İyi iş çıkardınız ölümlüler.", ["ORYG"]="You have done well, mortals."},
["689:02"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Artık zamanı geldi.", ["ORYG"]="It is time."},
["689:03"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Gücümüzü toplamalıyız.", ["ORYG"]="We must gather our strength."},
["689:04"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Evinize dönün, Azeroth'un çocukları.", ["ORYG"]="Return home, children of Azeroth."},
["689:05"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Illidan! Elimizden geleni yaptık.", ["ORYG"]="Illidan! We’ve done all we can."},
["689:06"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Her seçeneği,", ["ORYG"]="Every choice,"},
["689:07"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="her fedakarlık beni bu ana getirdi", ["ORYG"]="every sacrifice has led me to this moment"},
["689:08"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="onunla bir kez daha yüzleşmek için.", ["ORYG"]="to face him once again."},
["689:09"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Sen...", ["ORYG"]="You..."},
["689:10"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="bizimle gelmiyorsun...", ["ORYG"]="are not coming with us..."},
["689:11"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Av olmadan avcı bir hiçtir.", ["ORYG"]="The hunter is nothing without the hunt."},
["689:12"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bu kaderi görmedin mi, Peygamber?", ["ORYG"]="Did you not see this fate, Prophet?"},
["689:13"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Kader.", ["ORYG"]="Fate..."},
["689:14"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Hayatta kalmamız asla kaderin elinde değildi.", ["ORYG"]="Our survival was never in fate's hands."},
["689:15"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Işık seninle olsun, Illidan Stormrage.", ["ORYG"]="Light be with you, Illidan Stormrage."},
["689:16"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Kardeşim,", ["ORYG"]="Brother,"},
["689:17"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Haçlı seferiniz sona erdi!", ["ORYG"]="your crusade is over!"},
["689:18"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Hayır.", ["ORYG"]="No."},
["689:19"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Sonunda...", ["ORYG"]="At last..."},
["852:01"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bizimki bir nefret döngüsü.", ["ORYG"]="Ours is a cycle of hatred."},
["852:02"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="İttifaklar kuruldu ve bozuldu.", ["ORYG"]="Alliances forged and broken."},
["852:03"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bedelini ödedik", ["ORYG"]="We have paid the price"},
["852:04"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="bu dünyayı paylaştığımız için.", ["ORYG"]="for sharing this world."},
["852:05"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ve biz unuttuk", ["ORYG"]="and we have forgotten"},
["852:06"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bizi güçlü kılan şey.", ["ORYG"]="what makes us strong."},
["852:07"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Safları sıklaştırın!", ["ORYG"]="Close ranks!"},
["852:08"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bir olarak ilerleyin!", ["ORYG"]="Advance as one!"},
["852:09"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Lordaeron bizim olacak!", ["ORYG"]="Lordaeron will be ours!"},
["852:10"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Kralım, onu köşeye sıkıştırdık.", ["ORYG"]="My king, we have her cornered."},
["852:11"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ateşe devam!", ["ORYG"]="Keep firing!"},
["852:12"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Horde için!", ["ORYG"]="For the Horde!"},
["852:13"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="İlerleyin!", ["ORYG"]="Push forward!"},
["852:14"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Anduin!", ["ORYG"]="Anduin!"},
["852:15"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Tek vücut olun!", ["ORYG"]="Stand as one!"},
["852:16"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="İttifak için!", ["ORYG"]="For the Alliance!"},
["853:01"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Sahili emniyete alın.", ["ORYG"]="Secure the beach."},
["853:02"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ağacı istila etmeye hazırlanın.", ["ORYG"]="Prepare to invade the tree."},
["853:03"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Neden?", ["ORYG"]="Why?"},
["853:04"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Zaten kazandınız.", ["ORYG"]="You’ve already won."},
["853:05"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ağaçta sadece masumlar kaldı.", ["ORYG"]="Only innocents remain in the tree."},
["853:06"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bu bir savaş.", ["ORYG"]="This is war."},
["853:07"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Hayır...", ["ORYG"]="No..."},
["853:08"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bu...", ["ORYG"]="This..."},
["853:09"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="nefret...", ["ORYG"]="is hatred..."},
["853:10"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Öfke.", ["ORYG"]="rage."},
["853:11"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Windrunner, sen.", ["ORYG"]="Windrunner, you were..."},
["853:12"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="halkının savunucusuydun.", ["ORYG"]="defender of your people."},
["853:13"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Hatırlamıyor musun?", ["ORYG"]="Do you not remember?"},
["853:14"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Hatırlıyorum.", ["ORYG"]="I remember..."},
["853:15"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="bir aptal.", ["ORYG"]="a fool."},
["853:16"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Alın onu! Kaçın!", ["ORYG"]="Take her! Run!"},
["853:17"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Hayat acıdır.", ["ORYG"]="Life is pain."},
["853:18"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Umut başarısız olur.", ["ORYG"]="Hope fails."},
["853:19"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Şimdi anlıyorsun.", ["ORYG"]="Now you understand."},
["853:20"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yas tutma...", ["ORYG"]="Don’t grieve..."},
["853:21"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yakında sevdiklerine kavuşacaksın.", ["ORYG"]="you’ll soon join your loved ones."},
["853:22"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Senin için üzülüyorum.", ["ORYG"]="I grieve for you."},
["853:23"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Hayatı kendine düşman edinmişsin.", ["ORYG"]="You’ve made life your enemy."},
["853:24"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ve bu asla kazanamayacağın bir savaş.", ["ORYG"]="And that is a war you’ll never win."},
["853:25"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bizi öldürebilirsin.", ["ORYG"]="You can kill us..."},
["853:26"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ama umudu öldüremezsin.", ["ORYG"]="but you cannot kill hope."},
["853:27"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Öldüremez miyim?", ["ORYG"]="Can’t I?"},
["853:28"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yak onu.", ["ORYG"]="Burn it."},
["853:29"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yak onu!", ["ORYG"]="Burn it!"},
["857:01"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Görünüyor", ["ORYG"]="It appears"},
["857:02"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="İttifak köpekleri izimizi kaybetti.", ["ORYG"]="the Alliance dogs have lost our scent."},
["857:03"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Güzel, güzel.", ["ORYG"]="Good, good."},
["857:04"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yolculuğumuz neredeyse sona erdi.", ["ORYG"]="Our journey is almost over."},
["857:05"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Umarım", ["ORYG"]="I hope"},
["857:06"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Warchief'in inancı iyi yerleştirilmiş.", ["ORYG"]="the Warchief’s faith is well-placed."},
["857:07"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Çok güçlü görünüyor.", ["ORYG"]="She seems very powerful."},
["857:08"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Kesin.", ["ORYG"]="Certain."},
["857:09"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Kontrollü.", ["ORYG"]="In control."},
["857:10"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Kraliçeme hizmet etmek bir onurdur.", ["ORYG"]="It is an honor to serve my queen."},
["857:11"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Prensesim de güçlü bir iradeye sahip.", ["ORYG"]="My princess is also strong-willed"},
["857:12"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ve kendinden emin.", ["ORYG"]="and sure of herself."},
["857:13"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Kralımız onu her zaman.", ["ORYG"]="Our king has always found her to be..."},
["857:14"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="meydan okuyor.", ["ORYG"]="challenging."},
["857:15"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ey Kudretli Rezan,", ["ORYG"]="O Mighty Rezan,"},
["857:16"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Her zamanki gibi,", ["ORYG"]="as always,"},
["857:17"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yardımını istediğimde gelirsin.", ["ORYG"]="you come when I ask your aid."},
["857:18"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Konuş, ben de dinleyeyim.", ["ORYG"]="Speak, and I will listen."},
["857:19"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Horde'un yardımını istedim.", ["ORYG"]="I have sought the aid of the Horde."},
["857:20"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ama babam kabul etmeyebilir", ["ORYG"]="But my father may not agree"},
["857:21"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="benim eylemlerimle.", ["ORYG"]="with my actions."},
["857:22"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bana tavsiyede bulun!", ["ORYG"]="Advise me!"},
["857:23"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Sen kralların ve kraliçelerin Loa'sısın!", ["ORYG"]="You are the Loa of kings and queens!"},
["857:24"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Gözlerim çok şey görüyor.", ["ORYG"]="My eyes see much."},
["857:25"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Cesaretini görüyorlar,", ["ORYG"]="They see your boldness,"},
["857:26"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="senin gücün,", ["ORYG"]="your power,"},
["857:27"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ve her ikisinden de korkan düşmanlar.", ["ORYG"]="and enemies who fear both."},
["857:28"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ve senin ölümünü isteyenler.", ["ORYG"]="And those who seek your demise..."},
["857:29"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="buradalar.", ["ORYG"]="are here."},
["857:30"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Siper almalıyız! Şu sis bankasına doğru gidin!", ["ORYG"]="We need cover! Head for that fog bank!"},
["857:31"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yelkenler öldü. Rüzgarımız yok!", ["ORYG"]="The sails are dead. We’ve got no wind!"},
["857:32"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Su alıyoruz!", ["ORYG"]="We’re taking on water!"},
["857:33"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Eve geldik.", ["ORYG"]="We are home."},
["859:01"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yani...", ["ORYG"]="So..."},
["859:02"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="asi kizim geri̇ döndü", ["ORYG"]="my wayward daughter returns"},
["859:03"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="İhanet ettiği krallığa.", ["ORYG"]="to the kingdom she betrayed."},
["859:04"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Neden?", ["ORYG"]="Why?"},
["859:05"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Kul Tiras'tan yardım istemeye geldim.", ["ORYG"]="I have come to ask Kul Tiras for aid"},
["859:06"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="İttifak adına.", ["ORYG"]="on behalf of the Alliance."},
["859:07"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="İttifak mı?", ["ORYG"]="The Alliance?"},
["859:08"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="HA!", ["ORYG"]="HA!"},
["859:09"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Onlar neredeydi", ["ORYG"]="Where were they"},
["859:10"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="yardımları için yalvardığımızda?", ["ORYG"]="when we begged for their help?"},
["859:11"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Kocalarımız ve oğullarımız,", ["ORYG"]="When our husbands, and sons,"},
["859:12"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ve kardeşler katledildi", ["ORYG"]="and brothers were slaughtered"},
["859:13"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Theramore'da?", ["ORYG"]="at Theramore?"},
["859:14"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yaptıklarım için İttifak'ı suçlama.", ["ORYG"]="Do not blame the Alliance for my actions."},
["859:15"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yani kabul ediyorsun.", ["ORYG"]="So you admit it."},
["859:16"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Sorumlu olduğunu kabul ediyorsun.", ["ORYG"]="You admit that you were responsible"},
["859:17"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="adamlarımızın ölümü için!", ["ORYG"]="for the deaths of our men!"},
["859:18"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Öyleydim.", ["ORYG"]="I was."},
["859:19"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ama elimden gelen her şeyi yapacağım.", ["ORYG"]="But I will do anything in my power"},
["859:20"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Kul Tiras'ın acılarını dindirmek için!", ["ORYG"]="to ease the suffering of Kul Tiras!"},
["859:21"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Katherine... kanunlarımızı uygula.", ["ORYG"]="Katherine...enforce our laws."},
["859:22"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Vatana ihanetin cezası ölümdür.", ["ORYG"]="The punishment for treason...is death."},
["859:23"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bu kararı kabul ediyor musun?", ["ORYG"]="Do you accept the judgment"},
["859:24"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="anavatanınızın?", ["ORYG"]="of your homeland?"},
["859:25"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Kararınızı kabul ediyorum.", ["ORYG"]="I accept your judgment"},
["859:26"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="...anne.", ["ORYG"]="...mother."},
["859:27"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Agh!", ["ORYG"]="Agh!"},
["859:28"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Sen benim kızım değilsin.", ["ORYG"]="You are no daughter of mine."},
["859:29"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ne yaparsan yap.", ["ORYG"]="Do what you will."},
["859:30"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="O benim için hiçbir şey.", ["ORYG"]="She is nothing to me."},
["860:01"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ahoy, ahoy, denizlerin tatlı kızı", ["ORYG"]="Ahoy, ahoy, sweet Daughter of the Seas"},
["860:02"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ahoy, bu çocuk benim", ["ORYG"]="Ahoy, this child be mine"},
["860:03"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Amiralin kızı", ["ORYG"]="The Admiral’s girl"},
["860:04"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Onun tüm dünyası", ["ORYG"]="His whole entire world"},
["860:05"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Her ne kadar", ["ORYG"]="For as long"},
["860:06"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yıldızların parladığı gibi", ["ORYG"]="As stars do shine"},
["860:07"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Geri döneceğine söz verir misin?", ["ORYG"]="Promise you’ll come back?"},
["860:08"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Her fırtınayı atlatacağım,", ["ORYG"]="I’ll weather every storm,"},
["860:09"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Eğer beni beklediğini bilirsem.", ["ORYG"]="if I know you are waiting for me."},
["860:10"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Gitme zamanı, Jaina!", ["ORYG"]="Time to go, Jaina!"},
["860:11"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Seni seviyorum, baba.", ["ORYG"]="I love you, Papa."},
["860:12"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yukarı gel, tatlım.", ["ORYG"]="Come topside, sweetheart."},
["860:13"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Sevgili annen.", ["ORYG"]="Your loving mother..."},
["860:14"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="seni asla affetmeyecek.", ["ORYG"]="will never forgive you."},
["860:15"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Katil!", ["ORYG"]="Murderer!"},
["860:16"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Leydi Jaina?", ["ORYG"]="Lady Jaina?"},
["860:17"]={["START"]=0, ["STOP"]=0, ["NAPIS"]=" Geldik.", ["ORYG"]=" We’ve arrived."},
["860:18"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Teşekkürler, Kaptan.", ["ORYG"]="Thank you, Captain."},
["861:01"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Dikkat, dikkat Denizlerin Kızı", ["ORYG"]="Beware, beware the Daughter of the Seas"},
["861:02"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Dikkat et, ağladığını duydum.", ["ORYG"]="Beware, I heard him cry"},
["861:03"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Sözleri okyanus esintisiyle taşındı", ["ORYG"]="His words carried upon the ocean breeze"},
["861:04"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Gelgitin altında batarken", ["ORYG"]="As he sank beneath the tide"},
["861:05"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Kalimdor'un o kana bulanmış kıyıları", ["ORYG"]="Those blood-soaked shores of Kalimdor"},
["861:06"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Denizcilerin savaştığı ve öldüğü yer", ["ORYG"]="Where sailors fought and died"},
["861:07"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Amiral Theramore'da düştü.", ["ORYG"]="The admiral fell at Theramore"},
["861:08"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Çünkü onun yanından ayrıldı.", ["ORYG"]="Because she left his side"},
["861:09"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Neden bu?", ["ORYG"]="Why this?"},
["861:10"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Neden bu, ey Denizlerin Kızı?", ["ORYG"]="Why this, oh Daughter of the Seas?"},
["861:11"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Neden bu?", ["ORYG"]="Why this?"},
["861:12"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Deniz kıyısındaki günlerini unuttun mu?", ["ORYG"]="Did you forget your seaside days?"},
["861:13"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Her zaman ulusumuzun gururu", ["ORYG"]="Always the pride of our nation’s eyes"},
["861:14"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Nasıl yoldan çıkabilirdi ki?", ["ORYG"]="How could she go astray?"},
["861:15"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Okyanusun derinliklerine kaçtığında", ["ORYG"]="When she did flee across the ocean deep"},
["861:16"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Amiral batıyı takip etti.", ["ORYG"]="The admiral followed west"},
["861:17"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yelkenden başka ne", ["ORYG"]="What else but sail"},
["861:18"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bir kızın hayatını kurtarmak için", ["ORYG"]="To save a daughter’s life"},
["861:19"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ve hala nefes alması için dua mı ediyor?", ["ORYG"]="And pray she still drew breath?"},
["861:20"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ama orada buldu", ["ORYG"]="But there he found"},
["861:21"]={["START"]=0, ["STOP"]=0, ["NAPIS"]=" o uzak kıyılarda", ["ORYG"]=" upon those distant shores"},
["861:22"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Düşmanlar yükselişte!", ["ORYG"]="Enemies ‘pon the rise!"},
["861:23"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ama o vahşi düşmanlarla karşılaştığında", ["ORYG"]="But when he faced those savage foes"},
["861:24"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Kızı bir kenara çekildi", ["ORYG"]="His daughter stood aside"},
["861:25"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ve dalgaların derinliklerine gömüldü", ["ORYG"]="And buried deep beneath the waves"},
["861:26"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Aile tarafından ihanete uğradı", ["ORYG"]="Betrayed by family"},
["861:27"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Son nefesinde ulusuna haykırdı", ["ORYG"]="To his nation, with his last breath, cried"},
["861:28"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Denizlerin Kızına Dikkat Edin", ["ORYG"]="Beware the Daughter of the Seas"},
["861:29"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Şimdi dinliyorum.", ["ORYG"]="I’m listening now..."},
["861:30"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Baba.", ["ORYG"]="father."},
["861:31"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Duydum, ay ışığının aydınlattığı denizin ötesinden duydum.", ["ORYG"]="I heard, I heard across a moonlit sea"},
["861:32"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Beni uyaran yaşlı ses", ["ORYG"]="The old voice warning me"},
["861:33"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Dikkat, dikkat Denizlerin Kızı", ["ORYG"]="Beware, beware the Daughter of the Seas"},
["861:34"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Dikkat...", ["ORYG"]="Beware..."},
["861:35"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Sakın...", ["ORYG"]="beware..."},
["861:36"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="benden.", ["ORYG"]="of me."},
["862:01"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Çok fazla kayıp var.", ["ORYG"]="So many lost..."},
["862:02"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Biliyorum.", ["ORYG"]="I know."},
["862:03"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ben de Rezan'ı özledim.", ["ORYG"]="I miss Rezan too."},
["862:04"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Oh, Tze'na...", ["ORYG"]="Oh, Tze’na..."},
["862:05"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Şimdi ne yapacağız?", ["ORYG"]="what do we do now?"},
["862:06"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Kemiklerin tozu.", ["ORYG"]="The dust of bones..."},
["862:07"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ölümün Loa'sı için.", ["ORYG"]="for the Loa of death."},
["862:08"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Şey...", ["ORYG"]="Well..."},
["862:09"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="bu bir sürpriz.", ["ORYG"]="this is a surprise."},
["862:10"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Oldukça iyi görünüyorsunuz, Majesteleri.", ["ORYG"]="You looking pretty good, Your Majesty."},
["862:11"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Peki... neden beni görmeye geldin?", ["ORYG"]="So...why have you come to see me?"},
["862:12"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yardımınıza ihtiyacım var.", ["ORYG"]="I need your aid."},
["862:13"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Anlıyorum.", ["ORYG"]="I see."},
["862:14"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Benimle bir anlaşma yapmak istiyorsun.", ["ORYG"]="You want to make a deal with me."},
["862:15"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Devam et, devam et.", ["ORYG"]="Go on, go on."},
["862:16"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Benim Loa'm ol.", ["ORYG"]="Become my Loa."},
["862:17"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Krallığımı geri kazanmam için bana güç ver,", ["ORYG"]="Grant me the power to recover my kingdom,"},
["862:18"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ve seni tüm Loa'ların üstüne çıkaracağım!", ["ORYG"]="and I will elevate you above all Loa!"},
["862:19"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Evet, evet, böylece krallığını geri alırsın.", ["ORYG"]="Yes, yes, so you get your kingdom back."},
["862:20"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Hepsi çok güzel.", ["ORYG"]="All very nice."},
["862:21"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ama yakında yaşlı Bwonsamdi'den bıkacaksın.", ["ORYG"]="But soon you’ll tire of old Bwonsamdi."},
["862:22"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yaşayan Loa'ya geri döneceksin.", ["ORYG"]="You’ll go back to the living Loa."},
["862:23"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yağmuru getirenlere.", ["ORYG"]="The ones who bring the rain."},
["862:24"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ekinlerin büyümesini sağlar... solup ölmesini değil.", ["ORYG"]="Makes the crops grow...not wither and die."},
["862:25"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Hayır, hayır, hayır.", ["ORYG"]="No, no, no."},
["862:26"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Daha fazlasına ihtiyacım var.", ["ORYG"]="I need more..."},
["862:27"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="daha fazlasına ihtiyacım var.", ["ORYG"]="than just your word."},
["862:28"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Eğer bunu benim için yaparsan.", ["ORYG"]="If you do this for me..."},
["862:29"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Soyumu sana bağlayacağım.", ["ORYG"]="I will bind my bloodline to you."},
["862:30"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Senden sonra gelen herkes", ["ORYG"]="All who succeed you"},
["862:31"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="bu anlaşmaya uyacak mısın?", ["ORYG"]="will keep this bargain?"},
["862:32"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Hayatta bana hizmet etmek için.", ["ORYG"]="To serve me in life..."},
["862:33"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ve ölümde?", ["ORYG"]="and in death?"},
["862:34"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Sonsuza kadar.", ["ORYG"]="Forever."},
["862:35"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bir anlaşmamız var.", ["ORYG"]="We got a deal."},
["862:36"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Baba...", ["ORYG"]="Father..."},
["862:37"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Az önce bir şey hissettim.", ["ORYG"]="I felt something, a moment ago."},
["862:38"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bir şey mi oldu?", ["ORYG"]="Has something happened?"},
["862:39"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Endişelenme kızım.", ["ORYG"]="Do not worry my daugther."},
["862:40"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ben her şeyi hallettim.", ["ORYG"]="I’ve taken care of everything."},
["863:01"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Çok geç kaldın, Rastakhan.", ["ORYG"]="You are too late, Rastakhan."},
["863:02"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yüksel.", ["ORYG"]="Rise."},
["863:03"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yüksel Mythrax.", ["ORYG"]="Rise Mythrax."},
["863:04"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Kalk.", ["ORYG"]="Rise."},
["863:05"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bwonsamdi!", ["ORYG"]="Bwonsamdi!"},
["863:06"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bir anlaşma yapmıştık.", ["ORYG"]="We had a deal."},
["863:07"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bana gücünü ver!", ["ORYG"]="Grant me your power!"},
["863:08"]={["START"]=0, ["STOP"]=0, ["NAPIS"]=" Mythrax, şimdi yap!", ["ORYG"]=" Mythrax, do it now!"},
["863:09"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Mührü yok et!", ["ORYG"]="Destroy the seal!"},
["863:10"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Aptal.", ["ORYG"]="Fool."},
["863:11"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Uzun süre hüküm sürebilirsin...", ["ORYG"]="Long may you reign..."},
["863:12"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="kül imparatorluğun üzerinde.", ["ORYG"]="over your empire of ash."},
["863:13"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Şuna bir bakın.", ["ORYG"]="Look at this."},
["863:14"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Tebrikler, Majesteleri.", ["ORYG"]="Congratulations, Your Majesty."},
["863:15"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Krallık...", ["ORYG"]="The kingdom..."},
["863:16"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="bizimdir.", ["ORYG"]="is ours."},
