["874:01"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Hepsi mi?", ["ORYG"]="All of it?"},
["874:02"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Tüm sevkiyat.", ["ORYG"]="The entire shipment."},
["874:03"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Son tahıl çuvalına kadar.", ["ORYG"]="Down to the last sack of grain."},
["874:04"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Tek kurtulan bu.", ["ORYG"]="This one’s the only survivor."},
["874:05"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bwonsamdi.", ["ORYG"]="Bwonsamdi..."},
["874:06"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Beni henüz götürme.", ["ORYG"]="do not take me yet."},
["874:07"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ne oldu?", ["ORYG"]="What happened?"},
["874:08"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Savaş cephesine erzak götürüyorduk.", ["ORYG"]="We were bringing supplies to the warfront."},
["874:09"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Tıpkı diğer zamanlarda olduğu gibi.", ["ORYG"]="Just like all the other times."},
["874:10"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Hızlanın!", ["ORYG"]="Pick up the pace!"},
["874:11"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bu malzemeleri almalıyız.", ["ORYG"]="We've got to get these supplies"},
["874:12"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Şafakta askerlerimize!", ["ORYG"]="to our soldiers by dawn!"},
["874:13"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ne oldu?", ["ORYG"]="What is it?"},
["874:14"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Söyle ona.", ["ORYG"]="Tell her..."},
["874:15"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="biz geliyoruz.", ["ORYG"]="we are coming."},
["874:16"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bwonsamdi.", ["ORYG"]="Bwonsamdi..."},
["874:17"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="beni henüz götürme.", ["ORYG"]="do not take me yet."},
["874:18"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bu masala inanmamızı mı bekliyor?", ["ORYG"]="He expects us to believe this tale?"},
["874:19"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Hiçbir Gece Elfi bunları yapamaz!", ["ORYG"]="No single Night Elf could do all that!"},
["874:20"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yapabilecek birini tanıyorum.", ["ORYG"]="I know one who could."},
["874:21"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bu toprakları Horde için.", ["ORYG"]="We will hold this ground..."},
["874:22"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Horde için.", ["ORYG"]="for the Horde."},
["876:01"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Komutanım!  Bakın!", ["ORYG"]="Commander!  Look!"},
["876:02"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Hahaha!", ["ORYG"]="Hahaha!"},
["876:03"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Balıklar ağımıza atlıyor!", ["ORYG"]="Fish jumpin’ right into our net!"},
["876:04"]={["START"]=0, ["STOP"]=0, ["NAPIS"]=" Hadi, hadi!", ["ORYG"]=" Go, go!"},
["876:05"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Balistalar her an ateş edebilir.", ["ORYG"]="Those ballistae will be firing any second."},
["876:06"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yaklaşmaya devam edin, Kaptan.", ["ORYG"]="Continue our approach, Captain."},
["876:07"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Emredersiniz, Lord Amiral.", ["ORYG"]="Aye, Lord Admiral."},
["876:08"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Leydi Proudmoore.", ["ORYG"]="Lady Proudmoore."},
["876:09"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Görev başarılı oldu.", ["ORYG"]="The mission was a success."},
["876:10"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Gizli ajanlarımız bölgeden ayrıldı.", ["ORYG"]="Our stealth agents are clear of the area."},
["876:11"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Teşekkür ederim, Spymaster.", ["ORYG"]="Thank you, Spymaster."},
["876:12"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yüce Tinker, hazır mısın?", ["ORYG"]=" High Tinker—are you ready?"},
["876:13"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Sürprizimizi aktive edeceğim.", ["ORYG"]="I’ll activate our surprise"},
["876:14"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Menzile girer girmez.", ["ORYG"]="just as soon as we are in range."},
["876:15"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Şimdi.", ["ORYG"]="Now."},
["876:16"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Sabit.", ["ORYG"]="Steady …"},
["876:17"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="GELİYOR!", ["ORYG"]="INCOMING!"},
["876:18"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="High Tinker!", ["ORYG"]="High Tinker!"},
["876:19"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Tamamdır!", ["ORYG"]="Got it!"},
["876:20"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Gelbin ... hayır", ["ORYG"]="Gelbin … no"},
["876:21"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="DİKKAT!!", ["ORYG"]="LOOK OUT!!"},
["876:22"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Tam yol ileri!", ["ORYG"]="Full speed ahead!"},
["876:23"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="İttifak! İleri!", ["ORYG"]="Alliance! Forward!"},
["879:01"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Leydi Jaina.", ["ORYG"]="Lady Jaina."},
["879:02"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Uzun zamandır", ["ORYG"]="Long has it been"},
["879:03"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Theramore'da barışçıl bir şekilde konuştuğumuzdan beri.", ["ORYG"]="since we spoke peacefully in Theramore."},
["879:04"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Theramore gitti.", ["ORYG"]="Theramore is gone."},
["879:05"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Beni buraya anıları tazelemek için çağırmadın.", ["ORYG"]="You did not ask me here to reminisce."},
["879:06"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Hayır, istemedim.", ["ORYG"]="No."},
["879:07"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Kaybolan birini geri getirmeye geldim.", ["ORYG"]="I have come to return one who was lost."},
["879:08"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Derek'i.", ["ORYG"]="Derek..."},
["879:09"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Öz kardeşim.", ["ORYG"]="my own brother."},
["879:10"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Senin için daha iyisini düşünmüştüm Baine.", ["ORYG"]="I had thought better of you, Baine."},
["879:11"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Söyle bakalım.", ["ORYG"]="So tell me."},
["879:12"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Banshee'nin kuklası mı?", ["ORYG"]="Is he the banshee’s puppet?"},
["879:13"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Blight ile mi dolu?", ["ORYG"]="Crammed full of blight?"},
["879:14"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bu sefer bomba o mu?", ["ORYG"]="Is he the bomb this time?"},
["879:15"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Evet.", ["ORYG"]="Yes."},
["879:16"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Plan buydu.", ["ORYG"]="That was the plan."},
["879:17"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ama...", ["ORYG"]="But..."},
["879:18"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Baine beni daha önce Sylvanas'tan almıştı,", ["ORYG"]="Baine took me from Sylvanas before,"},
["879:19"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Onun iradesine boyun eğmeden önce.", ["ORYG"]="before I was twisted to her will."},
["879:20"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ben hâlâ senin kardeşinim, Jaina.", ["ORYG"]="I’m still your brother, Jaina."},
["879:21"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yıldızlar parladığı sürece.", ["ORYG"]="For as long as stars do shine."},
["879:22"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Neden?", ["ORYG"]="Why?"},
["879:23"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Horde'un içinde bir hastalık var.", ["ORYG"]="The Horde has a sickness in it."},
["879:24"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Toprak Ana ölürken biz savaşıyoruz.", ["ORYG"]="We wage war, while the Earth Mother dies."},
["879:25"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Neyin gerçekten önemli olduğunu unuttuk,", ["ORYG"]="We have forgotten what truly matters,"},
["879:26"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ve kalbim buna daha fazla dayanamıyor.", ["ORYG"]="and my heart can bear it no longer."},
["879:27"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Sylvanas bunun için seni öldürecek.", ["ORYG"]="Sylvanas will kill you for this."},
["879:28"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ve...", ["ORYG"]="And..."},
["879:29"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="seninle yetinmeyebilir.", ["ORYG"]="she may not stop with you."},
["879:30"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Hiçbir hayat yaşamaya değmez,", ["ORYG"]="No life is worth living,"},
["879:31"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="eğer doğamıza sadık olamazsak.", ["ORYG"]="if we cannot be true to our nature."},
["879:32"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Eve dönüyorum,", ["ORYG"]="I return home,"},
["879:33"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ailemle teselli bulmaya çalışıyorum.", ["ORYG"]="to take what solace I can in my family."},
["879:34"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Umarım sen de kendi ailenle teselli bulursun.", ["ORYG"]="I hope you take solace in yours."},
["883:01"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Onları takip edin! Kaçmalarına izin veremeyiz!", ["ORYG"]="Keep on them! We cannot let them escape!"},
["883:02"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Kraliçem... geldiler.", ["ORYG"]="My queen...they have arrived."},
["883:03"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Harika!", ["ORYG"]="Wonderful!"},
["883:04"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Tidestone'u ayarla, olur mu?", ["ORYG"]="Set the tidestone, won’t you?"},
["884:01"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Kurtarın bizi! Yardım edin!", ["ORYG"]="Save us! Help!"},
["884:02"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Kraliçem, kurtarın bizi!", ["ORYG"]="My queen, save us!"},
["884:03"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bırakın...", ["ORYG"]="Let go..."},
["884:04"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Hayır!", ["ORYG"]="No!"},
["884:05"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ben kraliçeyim.", ["ORYG"]="I am queen."},
["884:06"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bu...", ["ORYG"]="This..."},
["884:07"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="benim kurduğum imparatorluk!", ["ORYG"]="is the empire I built!"},
["884:08"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bitti artık.", ["ORYG"]="It is over..."},
["884:09"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bize ihanet ettin.", ["ORYG"]="You betrayed us."},
["884:10"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Her şeyi yok ettin.", ["ORYG"]="You destroyed everything."},
["884:11"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Hayır... halkım.", ["ORYG"]="No... my people."},
["884:12"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Kurtar bizi kraliçem.", ["ORYG"]="Save us my queen."},
["884:13"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bu senin hatan!", ["ORYG"]="This is your fault!"},
["884:14"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bize ihanet ettin.", ["ORYG"]="You betrayed us."},
["884:15"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bu benim suçum mu?", ["ORYG"]="This is my fault?"},
["884:16"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Hayır! Hayır!", ["ORYG"]="No!"},
["884:17"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Hayır! Bu...", ["ORYG"]="No! This..."},
["884:18"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bu benim yaptığım anlaşma değildi!", ["ORYG"]="This was not the deal I made!"},
["884:19"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Anlaşma. Anlaşmaları severim.", ["ORYG"]="Deal. I like deals."},
["884:20"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Kimsin sen?", ["ORYG"]="Who are you?"},
["884:21"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Göster kendini. Hemen!", ["ORYG"]="Show yourself. At once!"},
["884:22"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bin yıllığına,", ["ORYG"]="For a thousand years,"},
["884:23"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bu dalgaların altında bağlı,", ["ORYG"]="bound beneath these waves,"},
["884:24"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Seni izledim.", ["ORYG"]="I have watched you."},
["884:25"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Özünü tattım.", ["ORYG"]="I have tasted your essence."},
["884:26"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Sen!", ["ORYG"]="You!"},
["884:27"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Çok uzun sürmeyecek.", ["ORYG"]="It won't be long now."},
["884:28"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ölümün yakın.", ["ORYG"]="Your death is near."},
["884:29"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Seni sadece ben yaşatabilirim.", ["ORYG"]="Only I can sustain you."},
["884:30"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bırak.", ["ORYG"]="Let go."},
["884:31"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bana hizmet et.", ["ORYG"]="Serve me."},
["884:32"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Sana mı?", ["ORYG"]="You?"},
["884:33"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Sen bir hiçsin.", ["ORYG"]="You are nothing."},
["884:34"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Hiçbir şey mi?", ["ORYG"]="Nothing?"},
["884:35"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ben bir tanrıyım.", ["ORYG"]="I am a god."},
["884:36"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Sen bu topraklarda yürümeden önce, ben hüküm sürüyordum.", ["ORYG"]="Before you walked this land, I ruled."},
["884:37"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Muhteşem.", ["ORYG"]="Magnificent."},
["884:38"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bana hizmet et.", ["ORYG"]="Serve me."},
["884:39"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ve imparatorluğumu yeniden inşa edeceğiz.", ["ORYG"]="And we will rebuild my empire."},
["884:40"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Hayır. Hayır mı?", ["ORYG"]="No."},
["884:41"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Hayır mı?", ["ORYG"]="No?"},
["884:42"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Buna cüret edersen.", ["ORYG"]="You dare..."},
["884:43"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="öleceksin!", ["ORYG"]="you will die!"},
["884:44"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bir kraliçe!", ["ORYG"]="A queen!"},
["884:45"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Köle değil.", ["ORYG"]="Not a slave."},
["884:46"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bin yıldır beni izliyorsun.", ["ORYG"]="You've watched me for a thousand years."},
["884:47"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yani ne istediğimi biliyorsun.", ["ORYG"]="So you know what I want."},
["884:48"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Halkımı al.", ["ORYG"]="Take my people."},
["884:49"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Onlarla bir ordu kuracağım.", ["ORYG"]="With them, I will raise an army."},
["884:50"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Düşmanlarını fethet, bir imparatorluk kur.", ["ORYG"]="Conquer your enemies, build an empire..."},
["884:51"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Kraliçe olarak.", ["ORYG"]="as queen."},
["884:52"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ya da.", ["ORYG"]="Or..."},
["884:53"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ölmeme izin ver ve sen burada kal.", ["ORYG"]="let me die and you will remain here..."},
["884:54"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="bir tutsak olarak.", ["ORYG"]="a prisoner."},
["884:55"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Tanrı...", ["ORYG"]="The god..."},
["884:56"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="hiçbir şeyin tanrısı.", ["ORYG"]="of nothing."},
["884:57"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Kalk Azshara.", ["ORYG"]="Arise Azshara."},
["884:58"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Kalk kraliçem.", ["ORYG"]="Arise my queen."},
["884:59"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Muhteşem.", ["ORYG"]="Magnificent."},
["885:01"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Teşekkür ederim.", ["ORYG"]="Thank you."},
["885:02"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Baine ölseydi", ["ORYG"]="Baine would've died"},
["885:03"]={["START"]=0, ["STOP"]=0, ["NAPIS"]=" senin yardımın olmadan.", ["ORYG"]=" without your aid."},
["885:04"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bunun olmasına izin veremezdim.", ["ORYG"]="I couldn't let that happen."},
["885:05"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ben de veremezdim.", ["ORYG"]="Nor could I."},
["885:06"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Onu hayal kırıklığına uğratmayı reddediyorum.", ["ORYG"]="I refuse to fail him"},
["885:07"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Babasını hayal kırıklığına uğrattığım gibi.", ["ORYG"]="like I... failed his father."},
["885:08"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Keşke her şeyi değiştirebilseydim.", ["ORYG"]="I wish I could change it all."},
["885:09"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Cairne.", ["ORYG"]="Cairne..."},
["885:10"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Garrosh.", ["ORYG"]="Garrosh..."},
["885:11"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Theramore...", ["ORYG"]="Theramore..."},
["885:12"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bazen", ["ORYG"]="Sometimes"},
["885:13"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Sanki ben yapmışım gibi geliyor.", ["ORYG"]="it feels like I did"},
["885:14"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="her şey yanlış.", ["ORYG"]="everything wrong."},
["885:15"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Hepimizin elinde kan var.", ["ORYG"]="We all have blood on our hands."},
["885:16"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ve şimdi...", ["ORYG"]="And now..."},
["885:17"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Sylvanas gelecek.", ["ORYG"]="Sylvanas will come."},
["885:18"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Thunderbluff yanacak", ["ORYG"]="Thunderbluff will burn"},
["885:19"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Tıpkı Teldrassil gibi.", ["ORYG"]="just like Teldrassil."},
["885:20"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bir zamanlar", ["ORYG"]="Once before"},
["885:21"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="sen ve ben yan yana durduk", ["ORYG"]="you and I stood side by side"},
["885:22"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Hyjal Dağı'nın yamaçlarında.", ["ORYG"]="on the slopes of Mount Hyjal."},
["885:23"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="O dünya ağacı yıkılmadı.", ["ORYG"]="That world tree did not fall."},
["885:24"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Çünkü Horde ve İttifak", ["ORYG"]="Because the Horde and the Alliance"},
["885:25"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="birlikte çalıştık.", ["ORYG"]="worked together."},
["885:26"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Horde.", ["ORYG"]="Horde..."},
["885:27"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="İttifak.", ["ORYG"]="Alliance..."},
["885:28"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bu kavşağa geldik", ["ORYG"]="We've come to this crossroad"},
["885:29"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="tekrar ve tekrar, Jaina.", ["ORYG"]="again and again, Jaina."},
["885:30"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Her zaman dağılıyor.", ["ORYG"]="It always falls apart."},
["885:31"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bu sefer farklı olan ne?", ["ORYG"]="What's different this time?"},
["885:32"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Öyleyiz.", ["ORYG"]="We are."},
["885:33"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Gitmeliyim.", ["ORYG"]="I should go."},
["885:34"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Anduin bilmek isteyecektir.", ["ORYG"]="Anduin will want to know"},
["885:35"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Baine'in güvende olduğunu.", ["ORYG"]="that Baine is safe."},
["885:36"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Kralına söyle", ["ORYG"]="Tell your king"},
["885:37"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="O yalnız değil.", ["ORYG"]="he is not alone."},
["886:01"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Tüm gözler açılacak...", ["ORYG"]="All eyes shall be opened..."},
