["894:05"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Endişeli hissediyoruz, değil mi?", ["ORYG"]="Feeling anxious, are we?"},
["894:06"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Senin için ne kadar sinir bozucu olmalı.", ["ORYG"]="How frustrating it must be for you..."},
["894:07"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="hala kilitli", ["ORYG"]="still locked away"},
["894:08"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="çok güçsüz", ["ORYG"]="so powerless"},
