["894:12"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Görmek üzeresin", ["ORYG"]="You’re about to see"},
["894:13"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="En iyi yaptığım şeyi.", ["ORYG"]="what I do best."},
