["894:15"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yelkenleri açın! Yelkenleri açın!", ["ORYG"]="Set the sails! Set the sails!"},
["894:16"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Kaçamayız!", ["ORYG"]="We can't escape!"},
["894:17"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Nazjatar'a hoş geldiniz.", ["ORYG"]="Welcome to Nazjatar."},
["894:18"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ben de sizi bekliyordum.", ["ORYG"]="I’ve been waiting for you."},
["903:01"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Anduin.", ["ORYG"]="Anduin."},
["903:02"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Sylvanas'ın hareketleri hepimizi tehdit etti.", ["ORYG"]="Sylvanas' actions have threatened us all"},
["903:03"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ve her geçen gün gücü artıyor.", ["ORYG"]="and day by day, her power grows."},
["903:04"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Eğer dünyamız hayatta kalacaksa", ["ORYG"]="If our world is to survive"},
["903:05"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Saldırmalıyız.", ["ORYG"]="we must strike"},
["903:06"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="hala yapabiliyorken.", ["ORYG"]="while we still can."},
["903:07"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Benimle buluş", ["ORYG"]="Meet with me"},
["903:08"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ve konuşacağız.", ["ORYG"]="and we will speak."},
["903:09"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Çok az.", ["ORYG"]="So few..."},
["903:10"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Kaç tane sağlayabilirsin?", ["ORYG"]="How many can you provide?"},
["903:11"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Son bir saldırı için yeterli.", ["ORYG"]="Enough for one final assault."},
["903:12"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Eğer bu başarısız olursa.", ["ORYG"]="If that fails..."},
["903:13"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="işimiz biter.", ["ORYG"]="we're done."},
["903:14"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Eğer saltanatına son verirsek", ["ORYG"]="If we end her reign"},
["903:15"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ne tür bir savaş şefi olacaksın?", ["ORYG"]="what kind of warchief will you be?"},
["903:16"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Katıldığım Horde", ["ORYG"]="The Horde I joined"},
["903:17"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="kan içinde doğdu.", ["ORYG"]="was birthed in blood."},
["903:18"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yozlaşmayla lekelendi.", ["ORYG"]="Tainted by corruption."},
["903:19"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Karanlık Geçit'e giden yol", ["ORYG"]="The road that led to the Dark Portal"},
["903:20"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="uzun ve genişti", ["ORYG"]="was long and wide"},
["903:21"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Masumların kemikleriyle döşeli.", ["ORYG"]="paved with the bones of innocents."},
["903:22"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Biz buna Zafer Yolu dedik.", ["ORYG"]="we called it the Path of Glory."},
["903:23"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bu büyük bir yalandı.", ["ORYG"]="That was the great lie upon which"},
["903:24"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Horde kuruldu.", ["ORYG"]="the Horde was founded..."},
["903:25"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yaptığımız her şeyin onurlu olduğunu.", ["ORYG"]="that anything we did was honorable."},
["903:26"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Thrall, Vol'jin.", ["ORYG"]="Thrall, Vol'jin..."},
["903:27"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="onlar gerçek varisler değillerdi.", ["ORYG"]="they were not the true heirs"},
["903:28"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Blackhand'in kanlı mirasına.", ["ORYG"]="to Blackhand's bloody legacy."},
["903:29"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Sylvanas Windrunner.", ["ORYG"]="Sylvanas Windrunner is."},
["903:30"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Hayır, hayır.", ["ORYG"]="No."},
["903:31"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Hayır, bu Horde.", ["ORYG"]="No, this is the Horde."},
["903:32"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Senin liderliğinde.", ["ORYG"]="Led by you."},
["903:33"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Onuru olan biri....", ["ORYG"]="Someone who has...."},
["903:34"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Onur.", ["ORYG"]="Honor..."},
["903:35"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ben hiç onur nedir bilmedim.", ["ORYG"]="I've never known honor."},
["903:36"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Daha fazlasını hak ediyorlar.", ["ORYG"]="They deserve more."},
["903:37"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ama Hordelar zincirlenmeye mahkum.", ["ORYG"]="But the Horde is doomed to be shackled"},
["903:38"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="geçmişin zincirleri tarafından.", ["ORYG"]="by the chains of the past."},
["903:39"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Horde'un özel bir iddiası yok", ["ORYG"]="The Horde has no exclusive claim"},
["903:40"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="pişmanlıklara.", ["ORYG"]="to regrets."},
["903:41"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Arthas, Daelin.", ["ORYG"]="Arthas, Daelin..."},
["903:42"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Geçmişin hayaletleri bize de musallat oldu.", ["ORYG"]="The ghosts of the past haunt us as well."},
["903:43"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Uçurumu dolduramadık", ["ORYG"]="We could not fill the chasm"},
["903:44"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Horde ve Alliance arasında", ["ORYG"]="between the Horde and Alliance"},
["903:45"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Eğer 1000 yıl çalışsaydık.", ["ORYG"]="if we labored 1000 years."},
["903:46"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bunu biliyorsun.", ["ORYG"]="You know this."},
["903:47"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="O zaman ne için savaşıyoruz?", ["ORYG"]="Then what are we fighting for?"},
["903:48"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Askerler!", ["ORYG"]="Soldiers!"},
["903:49"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ayağa kalkın!", ["ORYG"]="On your feet!"},
["903:50"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Hemen kampı dağıtmaya başlayın!", ["ORYG"]="Start breaking camp immediately!"},
["903:51"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Lord Saurfang?", ["ORYG"]="Lord Saurfang?"},
["903:52"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Zekhan...", ["ORYG"]="Zekhan..."},
["903:53"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Evimiz nerede?", ["ORYG"]="Where is our home?"},
["903:54"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Orgrimmar mı?", ["ORYG"]="Orgrimmar?"},
["903:55"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bizim şehrimiz değil.", ["ORYG"]="Not our city"},
["903:56"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Evimiz.", ["ORYG"]="our home."},
["903:57"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Azeroth.", ["ORYG"]="Azeroth."},
["903:58"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ya bizimki?", ["ORYG"]="And ours?"},
["903:59"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Azeroth.", ["ORYG"]="Azeroth."},
["903:60"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Şu anda.", ["ORYG"]="Right now..."},
["903:61"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="bu dünyada sadece iki güç var", ["ORYG"]="there are only two forces in this world"},
["903:62"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bu önemli.", ["ORYG"]="that matter."},
["903:63"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Dünyamıza zarar vermeye kararlı biri", ["ORYG"]="One bent on harming our world"},
["903:64"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ve onu koruyacak bir tane.", ["ORYG"]="And one that will protect her."},
["903:65"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Peki ne yapıyoruz?", ["ORYG"]="So... what are we doing?"},
["903:66"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Döngüyü kırıyoruz.", ["ORYG"]="Breaking the cycle."},
["904:01"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Varok.", ["ORYG"]="Varok..."},
["904:02"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Vakit geldi.", ["ORYG"]="it's time."},
["904:03"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Orgrimmar'ı savunanlar", ["ORYG"]="Those who defend Orgrimmar"},
["904:04"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Horde'lar da var.", ["ORYG"]="are Horde as well."},
["904:05"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Kardeşlerimiz.", ["ORYG"]="Our brothers and sisters."},
["904:06"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bu savaşçılar savaşmaya yemin ettiler.", ["ORYG"]="These warriors have sworn to fight."},
["904:07"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Sizin için.", ["ORYG"]="For you."},
["928:01"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yani bana demek istiyorsun ki", ["ORYG"]="You mean to tell me"},
["928:02"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Casuslarınızdan hiçbiri dönmedi mi?", ["ORYG"]="none of your spies have returned?"},
["928:03"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="N'Zoth dışarıda.", ["ORYG"]="N'Zoth is out there"},
["928:04"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ve şimdi cevaplara ihtiyacımız var!", ["ORYG"]="and we need answers now!"},
["928:05"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Elimizden geleni yapıyoruz.", ["ORYG"]="We are doing all we can."},
["928:06"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Konuşmacı Magni geliyor,", ["ORYG"]="Speaker Magni is coming,"},
["928:07"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yeni bir danışmanla birlikte.", ["ORYG"]="along with a new... advisor."},
["928:08"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bizim için bilgi sahibi olduğunu iddia ediyor.", ["ORYG"]="He claims to have information for us."},
["928:09"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Işığın yanında, yeni bir danışman.", ["ORYG"]="By the light, a new advisor."},
["928:10"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Wrathion.", ["ORYG"]="Wrathion."},
["928:11"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Anduin!", ["ORYG"]="Anduin!"},
["928:12"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Çok uzun zaman oldu!", ["ORYG"]="It's been so long!"},
["928:13"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ejderhalar.", ["ORYG"]="Dragons."},
["928:14"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Sanırım bunu hak ettim.", ["ORYG"]="I suppose I deserved that."},
["928:15"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bundan daha fazlasını hak ediyorsun.", ["ORYG"]="Oh, you deserve more than that."},
["928:16"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Babam senin yüzünden öldü!", ["ORYG"]="My father is dead because of you!"},
["928:17"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ve babam öldü.", ["ORYG"]="And my father is dead"},
["928:18"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Eski Tanrılar yüzünden.", ["ORYG"]="because of the Old Gods."},
["928:19"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Delikanlı, bize yardım etmeye geldi.", ["ORYG"]="Lad, he's come to help us."},
["928:20"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Toprak Muhafızı Neltharion", ["ORYG"]="Neltharion the Earth-Warder"},
["928:21"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="bir zamanlar Azeroth'un koruyucusuydu.", ["ORYG"]="was once the protector of Azeroth."},
["928:22"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ama N'Zoth asil bir zihni deliliğe çevirdi,", ["ORYG"]="But N'Zoth turned a noble mind to madness,"},
["928:23"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ve şimdi babam", ["ORYG"]="and now my father"},
["928:24"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="sadece Deathwing olarak hatırlanıyor.", ["ORYG"]="is only remembered as Deathwing."},
["928:25"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ve, en ufak bir arzum olmadığı için", ["ORYG"]="And, as I haven't the least desire"},
["928:26"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="bu kaderi paylaşmak için,", ["ORYG"]="to share that fate,"},
["928:27"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bundan nasıl kaçınacağımı araştırıyordum.", ["ORYG"]="I've been studying how to avoid it."},
["928:28"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Sadece söyle bana.", ["ORYG"]="Just tell me"},
["928:29"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bu saldırıya nasıl hazırlanacağımızı.", ["ORYG"]="how to prepare for this attack."},
["928:30"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ordularımız--", ["ORYG"]="Our armies--"},
["928:31"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="İşe yaramaz.", ["ORYG"]="Will be useless."},
["928:32"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="N'Zoth buraya saldıracak.", ["ORYG"]="N'Zoth will strike here."},
["928:33"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Duyguları manipüle edecek,", ["ORYG"]="He'll manipulate emotions,"},
["928:34"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="insanların farklı şekillerde hareket etmesini sağlamak", ["ORYG"]="get people to act in ways"},
["928:35"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="doğalarına aykırıdır.", ["ORYG"]="contrary to their nature."},
["928:36"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Duyularınıza güvenemeyeceksiniz,", ["ORYG"]="You won't be able to trust your senses,"},
["928:37"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Anılarını,", ["ORYG"]="your memories,"},
["928:38"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="arkadaşlarınız.", ["ORYG"]="your friends."},
["928:39"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Sonuçta, gerçek olan nedir?", ["ORYG"]="After all, what is real"},
["928:40"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="algılarımız güvenilmezse?", ["ORYG"]="if our perceptions cannot be trusted?"},
["928:41"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Anduin?", ["ORYG"]="Anduin?"},
["928:42"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Anduin!", ["ORYG"]="Anduin!"},
["928:43"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Görmüyor musun, eski dostum?", ["ORYG"]="Don't you see, old friend?"},
["928:44"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Çoktan başladı.", ["ORYG"]="It's already begun."},
["928:45"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Pekala, danışman.", ["ORYG"]="Very well, advisor."},
["928:46"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Onu nasıl durduracağımızı söyle.", ["ORYG"]="Tell us how to stop him."},
