["932:01.1"]={["START"]=1, ["STOP"]=0, ["NAPIS"]="[rüzgar ıslığı]ru", ["ORYG"]="[wind whistling]"},
["932:02"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="HIRILTILI NEFES ALMA", ["ORYG"]="RASPY BREATHING"},
["932:03"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="AYAK SESLERI YAKLAŞIYOR", ["ORYG"]="FOOTSTEPS APPROACHING"},
["932:04"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="METALIK KAZIMA", ["ORYG"]="METALLIC SCRAPING"},
["932:05"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="HIRILTILI NEFES ALMA", ["ORYG"]="RASPY BREATHING"},
["932:06"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Işık... ruhumu kurtar.", ["ORYG"]="UTHER: Light... save my soul."},
["932:07"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="# GRAND ORCHESTRAL MUSIC", ["ORYG"]="# GRAND ORCHESTRAL MUSIC"},
["932:08"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="DEVOS: Uther...", ["ORYG"]="DEVOS: Uther..."},
["932:09"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="UTHER: Nerede... Neredeyim ben?", ["ORYG"]="UTHER: Where... Where am I?"},
["932:10"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bastion'a hoş geldin.", ["ORYG"]="DEVOS: Welcome... to Bastion."},
["932:11"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Gerçekten özverili bir hayat sürdün,", ["ORYG"]="You led a truly selfless life,"},
["932:12"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ve bunun için,", ["ORYG"]="and for that,"},
["932:13"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="sen seçildin.", ["ORYG"]="you have been chosen."},
["932:14"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Seçilmiş mi?", ["ORYG"]="UTHER: Chosen?"},
["932:15"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="DEVOS: Ölümlü yüklerinizden kurtulmak için", ["ORYG"]="DEVOS: To shed your mortal burdens"},
["932:16"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ve yükselmişlerin saflarına katıl,", ["ORYG"]="and join the ranks of the ascended,"},
["932:17"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ölülerin ruhlarını taşımak için", ["ORYG"]="serving to ferry the souls of the dead"},
["932:18"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Gölgeler Diyarı'na.", ["ORYG"]="unto the Shadowlands."},
["932:19"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ben Işığa hizmet ediyorum.", ["ORYG"]="UTHER: I serve the Light."},
["932:20"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ve işim henüz bitmedi.", ["ORYG"]="And my work is not done."},
["932:21"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yok edilmesi gereken bir kötülük var.", ["ORYG"]="There is an evil that must be s--"},
["932:22"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Burada kötülük yok.", ["ORYG"]="DEVOS: There is no evil here."},
["932:23"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Karanlık mühürlendi", ["ORYG"]="The darkness was sealed"},
["932:24"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Maw'ın içinde uzun zaman önce.", ["ORYG"]="within the Maw long ago."},
["932:25"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yanılıyorsun.", ["ORYG"]="UTHER: You're wrong."},
["932:26"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Evimi yok etti,", ["ORYG"]="He destroyed my home,"},
["932:27"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="halkımı ve kralımı öldürdü.", ["ORYG"]="murdered my people and my king."},
["932:28"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Cezalandırılmalı.", ["ORYG"]="He must be punished."},
["932:29"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Sen artık bir Aday'sın.", ["ORYG"]="DEVOS: You are an Aspirant now."},
["932:30"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yeni amacını kabul etmelisin,", ["ORYG"]="You must accept your new purpose,"},
["932:31"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ve kendini temizle", ["ORYG"]="and purge yourself"},
["932:32"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="bu intikam arzusunun.", ["ORYG"]="of this desire for vengeance."},
["932:33"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="UTHER: Arzu ettiğim şey... adalet.", ["ORYG"]="UTHER: What I desire... is justice."},
["932:34"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="THENIOS: Devos,", ["ORYG"]="THENIOS: Devos,"},
["932:35"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bu ruhu neden eğitiyorsun?", ["ORYG"]="why are you training this soul?"},
["932:36"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bir Paragon olarak bu senin makamının altında.", ["ORYG"]="It is beneath your station as a Paragon."},
["932:37"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bırakamaz.", ["ORYG"]="DEVOS: He cannot let go."},
["932:38"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Devam ediyor.", ["ORYG"]="He continues"},
["932:39"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="onun ölümü için intikam talep etmek.", ["ORYG"]="to demand retribution for his death."},
["932:40"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="THENIOS: Ve bu sizi ilgilendiriyor mu?", ["ORYG"]="THENIOS: And this concerns you?"},
["932:41"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Birçok ruhun yükselmesi çağlar sürer.", ["ORYG"]="Many souls take eons to ascend."},
["932:42"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="DEVOS: Evet, ama bu öyle görünüyor ki.", ["ORYG"]="DEVOS: Yes, but this one seems..."},
["932:43"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="kırık, Thenios,", ["ORYG"]="broken, Thenios,"},
["932:44"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Gördüğüm hiçbir ruha benzemiyor.", ["ORYG"]="unlike any soul I have seen."},
["932:45"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Merak etmeye başladım.", ["ORYG"]="I have begun to wonder"},
["932:46"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bastion'a layık görülüp görülmediği.", ["ORYG"]="whether he was deemed worthy of Bastion..."},
["932:47"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="yanlışlıkla.", ["ORYG"]="by mistake."},
["932:48"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Dikkatli ol, Devos.", ["ORYG"]="THENIOS: Be careful, Devos."},
["932:49"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Archon'un duymasına izin vermem", ["ORYG"]="I would not let the Archon hear"},
["932:50"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Böyle bir düşünce.", ["ORYG"]="such a thought."},
["932:51"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Zamanla unutacaktır.", ["ORYG"]="In time, he will forget."},
["932:52"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yolumuza güvenin.", ["ORYG"]="Trust our ways."},
["932:53"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yolumuza güvenin.", ["ORYG"]="Trust the path."},
["932:54"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Devos.", ["ORYG"]="UTHER: Devos..."},
["932:55"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ne kadar süre eğitim almalıyız?", ["ORYG"]="how long must we train?"},
["932:56"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yükselmeye hazır olana kadar.", ["ORYG"]="DEVOS: Until you are ready to ascend."},
["932:57"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="UTHER: Ve beni tutan şey", ["ORYG"]="UTHER: And what is keeping me"},
["932:58"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="yükselişten?", ["ORYG"]="from ascension?"},
["932:59"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="DEVOS: Hiçbir şey", ["ORYG"]="DEVOS: Nothing"},
["932:60"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ama ölümlü hayatının anısı.", ["ORYG"]="but the memory of your mortal life."},
["932:61"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Nasıl unutabilirim", ["ORYG"]="UTHER: How can I forget"},
["932:62"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="hala onun kılıcını hissedebiliyorken?", ["ORYG"]="when I can still feel his blade?"},
["932:63"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="DEVOS: (GASPS) Ruhun... yaralandı mı?", ["ORYG"]="DEVOS: (GASPS) Your soul... is wounded?"},
["932:64"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bunu sana kim yaptı?", ["ORYG"]="Who did this to you?"},
["932:65"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="UTHER: O benim öğrencimdi.", ["ORYG"]="UTHER: He was my student."},
["932:66"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Hepimize ihanet etti.", ["ORYG"]="He betrayed us all."},
["932:67"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="DEVOS: Göster bana.", ["ORYG"]="DEVOS: Show me."},
["932:68"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="UTHER ÇIĞLIK ATAR", ["ORYG"]="UTHER SCREAMS"},
["932:69"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="DEVOS GASPS", ["ORYG"]="DEVOS GASPS"},
["932:70"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="PARAGONLAR KONUŞUYOR", ["ORYG"]="PARAGONS CHATTERING"},
["932:71"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Kılıcındaki rünler", ["ORYG"]="DEVOS: The runes on his blade"},
["932:72"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="açıktı!", ["ORYG"]="were unmistakable!"},
["932:73"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bu karanlık ajan serbestçe dolaşıyor", ["ORYG"]="This dark agent runs free"},
["932:74"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ölümlü bir dünyada", ["ORYG"]="on a mortal world"},
["932:75"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Maw'ın gücü ellerindeyken!", ["ORYG"]="with the power of the Maw itself in hand!"},
["932:76"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Krallığımız tehlikede!", ["ORYG"]="Our realm is imperiled!"},
["932:77"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="İmkansız!", ["ORYG"]="THENIOS: Impossible!"},
["932:78"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Maw'dan kaçılamaz.", ["ORYG"]="The Maw is inescapable."},
["932:79"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yola geri dönmelisin.", ["ORYG"]="You must return to the path."},
["932:80"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="DEVOS: Eğer hayatını temizlemiş olsaydı,", ["ORYG"]="DEVOS: If he had purged his life,"},
["932:81"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="asla bilemezdik", ["ORYG"]="we never would have known"},
["932:82"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="bu felaketin!", ["ORYG"]="of this calamity!"},
["932:83"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yol kusurlu!", ["ORYG"]="The path is flawed!"},
["932:84"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yeter!", ["ORYG"]="ARCHON: Enough!"},
["932:85"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Gölgeler Diyarı'nın düzeni", ["ORYG"]="The order of the Shadowlands depends"},
["932:86"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ebedi görevimizin icrası üzerine.", ["ORYG"]="on the execution of our eternal charge."},
["932:87"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bu yoldan vazgeçeceksin.", ["ORYG"]="You will abandon this course."},
["932:88"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Emrettiğiniz gibi... Archon'um.", ["ORYG"]="DEVOS: As you command... my Archon."},
["932:89"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Uther!", ["ORYG"]="DEVOS: Uther!"},
["932:90"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yükselme zamanın geldi.", ["ORYG"]="The time of your ascension has come."},
["932:91"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ben... hazır olmadığımı sanıyordum.", ["ORYG"]="UTHER: I... thought I was not ready."},
["932:92"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="DEVOS: Onun cezalandırıldığını görmek istiyor musun?", ["ORYG"]="DEVOS: Do you wish to see him punished?"},
["932:93"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="İstiyorum.", ["ORYG"]="UTHER: I do."},
["932:94"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="DEVOS: O zaman kendini hazırla.", ["ORYG"]="DEVOS: Then prepare yourself."},
["932:95"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Düştüğü an.", ["ORYG"]="The moment he falls..."},
["932:96"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="onu alacağız.", ["ORYG"]="we will claim him."},
["932:97"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="RÜZGAR UĞULDUYOR", ["ORYG"]="WIND HOWLING"},
["932:98"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ARTHAS: Görüyorum...", ["ORYG"]="ARTHAS: I see..."},
["932:99"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="sadece karanlığı.", ["ORYG"]="only darkness..."},
["932:100"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="önümde..", ["ORYG"]="before me."},
["932:101"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="DEVOS: Şimdi, onu Maw'a atın!!", ["ORYG"]="DEVOS: Now, cast him into the Maw!"},
["932:102"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Onu hizmet ettiği karanlığa geri gönderin!!", ["ORYG"]="Return him to the darkness he served!"},
["932:103"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Sonsuz acısı onu bekliyor.!", ["ORYG"]="His eternal suffering awaits."},
["932:104"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="UTHER: O....", ["ORYG"]="UTHER: He was..."},
["932:105"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="benim öğrencimdi..", ["ORYG"]="my student."},
["932:106"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="DEVOS: Ne yaptığını hatırla.", ["ORYG"]="DEVOS: Remember what he did"},
["932:107"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ve intikamını al..", ["ORYG"]="and take your vengeance."},
["932:108"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="İntikam değil..", ["ORYG"]="UTHER: Not vengeance."},
["932:109"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Adalet..", ["ORYG"]="Justice."},
["932:110"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="# EPIK ORKESTRA MÜZIĞIA", ["ORYG"]="# EPIC ORCHESTRAL MUSIC"},
["933:01"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ORC ÇIĞLIKLARI", ["ORYG"]="ORC SCREAMS"},
["933:02"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ORC PANTİNG", ["ORYG"]="ORC PANTING"},
["933:03"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ORC ÇIĞLIKLARI", ["ORYG"]="ORC SCREAMS"},
["934:01"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ben hayattayken Draka'ydım,", ["ORYG"]="DRAKA: In life, I was Draka,"},
["934:02"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Frostwolf klanından.", ["ORYG"]="of the Frostwolf clan."},
["934:03"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bir savaşçı... Her şeyini veren...", ["ORYG"]="A warrior... who gave everything..."},
["934:04"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ORC ROARS", ["ORYG"]="ORC ROARS"},
["934:05"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="DRAKA GROANS", ["ORYG"]="DRAKA GROANS"},
["934:06"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="DRAKA: ...en önemli şeyi korumak için.", ["ORYG"]="DRAKA: ...to protect what mattered most."},
["934:07"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="BEBEK AĞLAR, DRAKA INLER", ["ORYG"]="BABY CRIES, DRAKA GROANS"},
["934:08"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="DRAKA: Ama savaşmayı bitirmemiştim.", ["ORYG"]="DRAKA: But I was not done fighting."},
["934:09"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="DRAKA: Maldraxxus,", ["ORYG"]="DRAKA: Maldraxxus,"},
["934:10"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Beş evin ordularının", ["ORYG"]="where the armies of the five houses"},
["934:11"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="bir zamanlar yan yana dururlardı,", ["ORYG"]="once stood side by side,"},
["934:12"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ölüm diyarını korumak için.", ["ORYG"]="to protect the realm of death."},
["934:13"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Burada Gözler Evi'ne hizmet ettim.", ["ORYG"]="It was here I served the House of Eyes."},
["934:14"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bir savaşçının ruhu için garip bir uyum.", ["ORYG"]="A strange fit for a warrior's soul."},
["934:15"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Tekrar.", ["ORYG"]="MARGRAVE AKAREK: Again."},
["934:16"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Onların yolları benimkiler gibi değildi.", ["ORYG"]="DRAKA: Their ways were not mine."},
["934:17"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Daha hızlı!", ["ORYG"]="MARGRAVE AKAREK: Faster!"},
["934:18"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Tekrar!", ["ORYG"]="MARGRAVE AKAREK: Again!"},
["934:19"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="DRAKA: Sonunda, bu hayattan sonraki hayat", ["ORYG"]="DRAKA: Eventually, this life after life"},
["934:20"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="doğru hissetmeye başladı.", ["ORYG"]="began to feel right."},
["934:21"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="DRAKA GRUNTS", ["ORYG"]="DRAKA GRUNTS"},
["934:22"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="MARGRAVE AKAREK: Vebalar Evi", ["ORYG"]="MARGRAVE AKAREK: The House of Plagues"},
["934:23"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="harabeye döndü.", ["ORYG"]="lies in ruins."},
["934:24"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Maldraxxus'un beşte biri yok oldu.", ["ORYG"]="One fifth of Maldraxxus wiped out."},
["934:25"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="DRAKA: İnanması zor", ["ORYG"]="DRAKA: It is hard to believe"},
["934:26"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bu kadar dikkatsiz olabilirler.", ["ORYG"]="they could be so careless."},
["934:27"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Belki de değillerdi.", ["ORYG"]="MARGRAVE AKAREK: Perhaps they weren't."},
["934:28"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Şimdi ne olursa olsun,", ["ORYG"]="No matter what happens now,"},
["934:29"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Maldraxxus amacına sadık kalmalı.", ["ORYG"]="Maldraxxus must stay true to its purpose."},
["934:30"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Eğer görevimizde başarısız olursak,", ["ORYG"]="For if we fail in our duty,"},
["934:31"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Gölgeler Diyarı düşecek.", ["ORYG"]="the Shadowlands will fall."},
["934:32"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Seçilmişler Evi'nin", ["ORYG"]="I believe the House of the Chosen"},
["934:33"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="hala bizimle.", ["ORYG"]="still stands with us."},
["934:34"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ve bunu teslim edeceğine güveniyorum.", ["ORYG"]="And I trust you to deliver this"},
["934:35"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Margrave Krexus'a.", ["ORYG"]="to Margrave Krexus."},
["934:36"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Şimdi gidin.", ["ORYG"]="Now, go."},
["934:37"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ve Draka... dikkatli ol.", ["ORYG"]="And Draka... be watchful."},
["934:38"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="DRAKA PANTING", ["ORYG"]="DRAKA PANTING"},
["934:39"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="# EPIK ORKESTRA MÜZIĞI", ["ORYG"]="# EPIC ORCHESTRAL MUSIC"},
["934:40"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="DRAKA: Kardeşlerim,", ["ORYG"]="DRAKA: My brothers,"},
["934:41"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Acil bir işim var!", ["ORYG"]="I am on urgent business!"},
["934:42"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="UZAK PATLAMA", ["ORYG"]="DISTANT EXPLOSION"},
["934:43"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="(Lordum!", ["ORYG"]="(GASPS) My lord!"},
["934:44"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Acele edin! Hayatta kalanlar olabilir!", ["ORYG"]="Hurry! There could be survivors!"},
["934:45"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="DRAKA GRUNTS", ["ORYG"]="DRAKA GRUNTS"},
["934:46"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="DRAKA GROANS", ["ORYG"]="DRAKA GROANS"},
["934:47"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="DRAKA HOMURDANIYOR, CESETLER GÜMBÜRDÜYOR", ["ORYG"]="DRAKA GRUNTS, BODIES THUD"},
["934:48"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="DRAKA YUMUŞAKÇA HOMURDANIYOR", ["ORYG"]="DRAKA GRUNTS SOFTLY"},
["934:49"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="DRAKA YELKENLERİ", ["ORYG"]="DRAKA YELLS"},
["934:50"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="MARGRAVE KREXUS: Yani,", ["ORYG"]="MARGRAVE KREXUS: So,"},
["934:51"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bunlar bahsettiğin hainler.", ["ORYG"]="these are the traitors you spoke of"},
["934:52"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="DRAKA: Böyle bir ur'gora'nın", ["ORYG"]="DRAKA: I would not let such ur'gora"},
["934:53"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="beni engelle", ["ORYG"]="prevent me"},
["934:54"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Lordumun son mesajını iletmekten.", ["ORYG"]="from delivering my lord's final message."},
["934:55"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="MARGRAVE KREXUS: Bunun gibi çileler", ["ORYG"]="MARGRAVE KREXUS: Ordeals such as this"},
["934:56"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ya kılıcı kıracak ya da güçlendirecek.", ["ORYG"]="either break the sword or strengthen it."},
["934:57"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Hmm.", ["ORYG"]="Hmm."},
["934:58"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Maldraxxus'u kurtarmanın anahtarını sunuyorum.", ["ORYG"]="\"I offer the key to saving Maldraxxus.\""},
["934:59"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Üzgünüm, Margrave.", ["ORYG"]="DRAKA: I am sorry, Margrave."},
["934:60"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bana anahtar vermedi.", ["ORYG"]="He gave me no... key."},
["934:61"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="MARGRAVE KREXUS: Boyun eğmeyen bir savaşçı", ["ORYG"]="MARGRAVE KREXUS: An unyielding warrior"},
["934:62"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Usta bir casusun yetenekleriyle mi?", ["ORYG"]="with the skills of a master spy?"},
["934:63"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Birçok şeyin anahtarı.", ["ORYG"]="A key to many things."},
["934:64"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Gel, düşmanlarımız yakında açıkça saldıracak.", ["ORYG"]="Come, our enemies will strike openly soon."},
["934:65"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Hazırlanmalıyız.", ["ORYG"]="We must prepare."},
["934:66"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ben Draka,", ["ORYG"]="DRAKA: I am Draka,"},
["934:67"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="bir zamanlar Frostwolf klanından,", ["ORYG"]="once of the Frostwolf clan,"},
["934:68"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Şimdi Seçilmişler Evi'nin Barones'i.", ["ORYG"]="now Baroness of the House of the Chosen."},
["934:69"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ve en önemlisi,", ["ORYG"]="And most of all,"},
["934:70"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Maldraxxus'un bir koruyucusu.", ["ORYG"]="a protector of Maldraxxus."},
["935:01"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="# KASVETLI ORKESTRA MÜZIĞI", ["ORYG"]="# SOMBER ORCHESTRAL MUSIC"},
["935:02"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="HIRILTI YOĞUNLAŞIYOR", ["ORYG"]="SNARLING INTENSIFIES"},
["935:03"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="URSOC ROARS", ["ORYG"]="URSOC ROARS"},
["935:04"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Vahşi doğa öfkem karşısında titrer!", ["ORYG"]="The Wilds tremble before my fury!"},
["935:05"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="KÜKRER", ["ORYG"]="ROARS"},
["935:06"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="THUD", ["ORYG"]="THUD"},
["935:07"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="URSOC GROANS", ["ORYG"]="URSOC GROANS"},
["935:08"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Kabusun peçesi kalktı.", ["ORYG"]="The Nightmare's veil... is lifted."},
["935:09"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="# KASVETLI ORKESTRA MÜZIĞI", ["ORYG"]="# SOMBER ORCHESTRAL MUSIC"},
["935:10"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Sonunda döndüm.", ["ORYG"]="I return at last..."},
["935:11"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="uzun uykuya...", ["ORYG"]="to the long slumber..."},
["935:12"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="RÜZGAR UĞULDUYOR", ["ORYG"]="WIND HOWLING"},
["935:13"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="...ötesindeki büyük ormana..", ["ORYG"]="...to the great forest beyond..."},
["935:14"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="vahşi doğaya tekrar hizmet edene kadar.", ["ORYG"]="until I may serve the Wilds again."},
["935:15"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="# ENCHANTING ORCHESTRAL MUSIC", ["ORYG"]="# ENCHANTING ORCHESTRAL MUSIC"},
["935:16"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ARA'LON: Koruluğuma hoş geldin... dostum.", ["ORYG"]="ARA'LON: Welcome to my grove... friend."},
["935:17"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="RÜZGAR ISLIKLARI", ["ORYG"]="WIND WHISTLING"},
["935:18"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="(Kraliçem!", ["ORYG"]="(GASPS) My Queen!"},
["935:19"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bu ruhları koruyacağım", ["ORYG"]="I shall protect these souls"},
["935:20"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="kışları boyunca.", ["ORYG"]="through their winter."},
["935:21"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Baharlarında yeniden doğduklarını göreceğim.", ["ORYG"]="I shall see them reborn in their spring..."},
["935:22"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Hangi sınavla karşılaşırsam karşılaşayım.", ["ORYG"]="no matter what trial I face."},
["935:23"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yemin ederim, Kraliçem.", ["ORYG"]="I swear it, my Queen."},
["935:24"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yemin ederim.", ["ORYG"]="I swear it."},
["935:25"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="İyi dinlenin.", ["ORYG"]="Rest well..."},
["935:26"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ve rüya gör.", ["ORYG"]="and dream."},
["935:27"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ARA'LON SIGHS", ["ORYG"]="ARA'LON SIGHS"},
["935:28"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Mevsimden mevsime bu kuraklık.", ["ORYG"]="Season after season of this drought."},
["935:29"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="(İşte.", ["ORYG"]="(SIGHS) Here."},
["935:30"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="İşte. Çok az, biliyorum.", ["ORYG"]="Here. It's so little, I know."},
["935:31"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="YAPRAKLAR HIŞIRDIYOR", ["ORYG"]="FOLIAGE RUSTLING"},
["935:32"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ARA'LON NEFES NEFESE", ["ORYG"]="ARA'LON PANTING"},
["935:33"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="YUMUŞAKÇA GAZ ÇIKARIR", ["ORYG"]="GASPS SOFTLY"},
["935:34"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bu yapılmalı.", ["ORYG"]="SYLVAR #1: It must be done."},
["935:35"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bu korudaki her şeyi geri alın.", ["ORYG"]="Reclaim everything from this grove."},
["935:36"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Her şeyi.", ["ORYG"]="Everything."},
["935:37"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Hayır. Hayır! Hayır!", ["ORYG"]="ARA'LON: No. No! No!"},
["935:38"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Hayır! Hayır! Hayır!", ["ORYG"]="No! No!"},
["935:39"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="SYLVAR SNARLING", ["ORYG"]="SYLVAR SNARLING"},
["935:40"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Burası benim koruluğum!", ["ORYG"]="ARA'LON: This is my grove!"},
["935:41"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Onları yok edemezsin!", ["ORYG"]="You will not destroy them!"},
["935:42"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ara'lon!", ["ORYG"]="SYLVAR #1: Ara'lon!"},
["935:43"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Biz senin düşmanın değiliz.", ["ORYG"]="We are not your enemy."},
["935:44"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Koruluğumu tehdit eden herkes", ["ORYG"]="ARA'LON: Anyone who threatens my grove"},
["935:45"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="benim düşmanım.", ["ORYG"]="is my enemy."},
["935:46"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yemin ettim!", ["ORYG"]="I swore an oath!"},
["935:47"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ARA'LON GASPS", ["ORYG"]="ARA'LON GASPS"},
["935:48"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Kraliçem.", ["ORYG"]="My Queen..."},
["935:49"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="İnancımı korudum... bunca zaman", ["ORYG"]="I kept faith... all this time"},
["935:50"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="bizi kurtaracağını söyledin.", ["ORYG"]="that you would save us."},
["935:51"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ve şimdi sen...", ["ORYG"]="And now you send..."},
["935:52"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="leş yiyicileri koruma mı?", ["ORYG"]="scavengers to my grove?"},
["935:53"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="(Neden?", ["ORYG"]="(PANTING) Why?"},
["935:54"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ARA'LON GASPS", ["ORYG"]="ARA'LON GASPS"},
["935:55"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="AĞAÇLAR ÇATLIYOR", ["ORYG"]="TREES CRACKING"},
["935:56"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ne olacağını gördün.", ["ORYG"]="HUNTMASTER: You saw what is to come."},
["935:57"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ARA'LON: Ardenweald... ölüyor.", ["ORYG"]="ARA'LON: (GASPS) Ardenweald is... dying."},
["935:58"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Kurtarılmalı.", ["ORYG"]="HUNTMASTER: It must be saved."},
["935:59"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Kraliçe Vahşi Av'ı çağırdı.", ["ORYG"]="The Queen has called the Wild Hunt."},
["935:60"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Korunuzu itlaf ettik.", ["ORYG"]="SYLVAR #2: We have culled your grove"},
["935:61"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Böylece diğerleri yaşayabilir.", ["ORYG"]="so that others might live."},
["935:62"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bir ruh feda edecek misin?", ["ORYG"]="HUNTMASTER: Will you sacrifice one soul"},
["935:63"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="tüm orman için mi?", ["ORYG"]="for the forest entire?"},
["935:64"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yoksa yeminini tutacak mısın?", ["ORYG"]="Or will you keep your oath?"},
["935:65"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Kalbin temiz.", ["ORYG"]="WINTER QUEEN: Your heart is pure."},
["935:66"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Seçimine saygı duyacağım.", ["ORYG"]="I will honor your choice."},
["935:67"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="UZAK, BOĞUK HIRILTILAR", ["ORYG"]="DISTANT, MUFFLED SNARLING"},
["935:68"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Son bir kez,", ["ORYG"]="ARA'LON: One last time,"},
["935:69"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Wilds'a hizmet ediyorsun.", ["ORYG"]="you serve the Wilds."},
["935:70"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Unutulmayacaksın.", ["ORYG"]="You will not be forgotten."},
["935:71"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Affet beni... dostum.", ["ORYG"]="Forgive me... friend."},
["935:72"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="# KASVETLI ORKESTRA MÜZIĞI", ["ORYG"]="# SOMBER ORCHESTRAL MUSIC"},
["935:73"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ARA'LON: Senin için avlanacağım, Kraliçem.", ["ORYG"]="ARA'LON: I will hunt for you, my Queen."},
