["937:26"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Sylvanas!", ["ORYG"]="Sylvanas!"},
["937:27"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ve o geldiğinde, sonumuz başlayacak.", ["ORYG"]="And when she comes, our end begins."},
["941:01"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Kraliçem! Lütfen bize yardım edin.", ["ORYG"]="MOONBERRY: My queen! Please help us."},
["941:02"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bu... kız kardeşime ait.", ["ORYG"]="This... is of my sister."},
["941:03"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bunu bana neden getirdin?", ["ORYG"]="Why have you brought it to me?"},
["941:04"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bu... elimizden kayıp gidiyor.", ["ORYG"]="This one... is slipping away."},
["941:05"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Görevimiz acımasız.", ["ORYG"]="Our duty is grim."},
["941:06"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Birçoğu kayboldu.", ["ORYG"]="Many have been lost."},
["941:07"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Neden onun hayvanını kurtarmalıyım?", ["ORYG"]="Why should I save her pet?"},
["941:08"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Onun yanında rüya görenler", ["ORYG"]="Those who have dreamed by its side"},
["941:09"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="bir neşe ve huzurla uyanmak", ["ORYG"]="awaken with a joy and peace"},
["941:10"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="bir mucize fısıldıyor.", ["ORYG"]="that whispers of wonder."},
["941:11"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Eğer ölürse,", ["ORYG"]="If she dies,"},
["941:12"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="O zaman zümrüt olan her şey onunla birlikte ölür.", ["ORYG"]="then all that is emerald dies with her."},
["941:13"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bazıları feda edilmeli.", ["ORYG"]="Some must be sacrificed."},
["941:14"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ama bazıları da kurtarılmalı.", ["ORYG"]="But some must be saved."},
["941:15"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Eğer bunu unutursak,", ["ORYG"]="If we forget that,"},
["941:16"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="geriye kalan tek şey boş kabuklar olacak", ["ORYG"]="all that will remain will be empty shells"},
["941:17"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ve hüzün.", ["ORYG"]="and sorrow."},
