["942:07"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="CHUCKLES", ["ORYG"]="CHUCKLES"},
["942:08"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ah, şimdi...", ["ORYG"]="Ah, now..."},
["942:09"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Şimdi ilginçleşmeye başladı. (CHUCKLES)", ["ORYG"]="Now it's getting interesting. (CHUCKLES)"},
["942:10"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="GRUNTS", ["ORYG"]="GRUNTS"},
["942:11"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="# DRAMATIK ORKESTRA MÜZIĞI", ["ORYG"]="# DRAMATIC ORCHESTRAL MUSIC"},
["942:12"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="SNARLING", ["ORYG"]="SNARLING"},
["942:13"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="SAVAŞ HOMURTULARI DEVAM EDIYOR", ["ORYG"]="FIGHTING GRUNTS CONTINUE"},
["942:14"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="GROANS", ["ORYG"]="GROANS"},
["942:15"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="CHUCKLES", ["ORYG"]="CHUCKLES"},
["942:16"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Gücün.", ["ORYG"]="Your power..."},
["942:17"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="(...büyüdü.", ["ORYG"]="(CHUCKLES) ...has grown."},
["942:18"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="GRUNTS", ["ORYG"]="GRUNTS"},
["942:19"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Kız nerede?", ["ORYG"]="Where is she?"},
["942:20"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Onunla birlikte tabii ki.", ["ORYG"]="With him, of course."},
["942:21"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="En karanlık yerde.", ["ORYG"]="In the darkest place."},
["942:22"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Kül olan her ruhla birlikte", ["ORYG"]="Along with every soul burned to ash"},
["942:23"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="değerli ağacında--", ["ORYG"]="in your precious tree--"},
["942:24"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Nerede bu kız?", ["ORYG"]="Where is she?"},
["942:25"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="GÜLÜYOR", ["ORYG"]="LAUGHS"},
["942:26"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Devam et.", ["ORYG"]="Go on."},
["942:27"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Öldür beni.", ["ORYG"]="Kill me."},
["942:28"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Beni doğruca leydime göndereceksin. (GRUNTS)", ["ORYG"]="You'll send me right to my lady. (GRUNTS)"},
["942:29"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Perdenin ötesinde paramparça oldu.", ["ORYG"]="Beyond the veil she shattered."},
["942:30"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="CHUCKLES", ["ORYG"]="CHUCKLES"},
["942:31"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Oh, Tyrande!", ["ORYG"]="Oh, Tyrande!"},
["942:32"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Baş Rahibe.", ["ORYG"]="High Priestess."},
["942:33"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Gece Savaşçısı.", ["ORYG"]="Night Warrior."},
["942:34"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Tamamen güçsüz", ["ORYG"]="Completely powerless"},
["942:35"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="durdurmak için-- (GASPS)", ["ORYG"]="to stop the com-- (GASPS)"},
["942:36"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Teldrassil için.", ["ORYG"]="For Teldrassil."},
["943:01"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ARCHON: Perdenin ötesinde", ["ORYG"]="ARCHON: Beyond the veil"},
["943:02"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Gölgeler Diyarı'nda yatıyor...", ["ORYG"]="lies the Shadowlands..."},
["944:01"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="# DRAMATIK ORKESTRA MÜZIĞI", ["ORYG"]="# DRAMATIC ORCHESTRAL MUSIC"},
["944:02"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="GARGOYLES SCREECHING", ["ORYG"]="GARGOYLES SCREECHING"},
["944:03"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="VENTHYR ÇIĞLIK ATIYOR", ["ORYG"]="VENTHYR SCREAMS"},
["944:04"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="VENTHYR 2 ÇIĞLIK ATIYOR", ["ORYG"]="VENTHYR 2 SCREAMS"},
["944:05"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="GARGOYLE SCREECHES", ["ORYG"]="GARGOYLE SCREECHES"},
["944:06"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="RENATHAL YELLS", ["ORYG"]="RENATHAL YELLS"},
["944:07"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Denathrius!", ["ORYG"]="Denathrius!"},
["944:08"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="RENATHAL NEFES NEFESE", ["ORYG"]="RENATHAL PANTING"},
["944:09"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="RENATHAL HOMURDANIYOR", ["ORYG"]="RENATHAL GRUNTING"},
["944:10"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="HOMURDANMA DEVAM EDIYOR", ["ORYG"]="GRUNTING CONTINUES"},
["944:11"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="RENATHAL DÜZENSIZ NEFES ALIYOR", ["ORYG"]="RENATHAL BREATHING RAGGEDLY"},
["944:12"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="RENATHAL INLIYOR", ["ORYG"]="RENATHAL GROANS"},
["944:13"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bu senin cesur son direnişin miydi?", ["ORYG"]="This was your valiant last stand?"},
["944:14"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="RENATHAL NEFES NEFESE", ["ORYG"]="RENATHAL PANTING"},
["944:15"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="RENATAL GAZLAR", ["ORYG"]="RENATHAL GASPS"},
["944:16"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Çok uzun zamandır,", ["ORYG"]="For so very long,"},
["944:17"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="kibirli ruhları cezalandırdınız.", ["ORYG"]="you've punished arrogant souls."},
["944:18"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ama öğrenmek yerine", ["ORYG"]="But instead of learning"},
["944:19"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="onların acılarından,", ["ORYG"]="from their suffering,"},
["944:20"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="sen de onlardan biri oldun.", ["ORYG"]="you've become one of them."},
["944:21"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Sadece itaat etmen gerekiyordu.", ["ORYG"]="You just needed to obey."},
["944:22"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ne kadar şanslısın.", ["ORYG"]="How fortunate you are"},
["944:23"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ihtişamına tanık olmak için", ["ORYG"]="to witness the splendor"},
["944:24"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ortaya çıkmak üzere olan şeyin.", ["ORYG"]="of what is about to unfold."},
["944:25"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Anima'nın her değerli damlası,", ["ORYG"]="Every precious drop of anima,"},
["944:26"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="çok özenle sıkılmış", ["ORYG"]="so painstakingly wrung"},
["944:27"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="daha düşük varlıkların işkence görmüş ruhlarından,", ["ORYG"]="from the tortured souls of lesser beings,"},
["944:28"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="şimdi yolu açıyor", ["ORYG"]="now paves the path"},
["944:29"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Sürgün Edilmiş Kişi için", ["ORYG"]="for the Banished One"},
["944:30"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Kendisine ait olanı geri almak için.", ["ORYG"]="to reclaim what was his."},
["944:31"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ve özgürlüğü güvence altına alındığında,", ["ORYG"]="And once his liberation is secured,"},
["944:32"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="onun iradesiyle olacak", ["ORYG"]="it shall be by his will"},
["944:33"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="her şeyin yıkanıp gittiğini.", ["ORYG"]="that all is washed away."},
["944:34"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ortaya çıkacak tek güç", ["ORYG"]="The only power that will emerge"},
["944:35"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="bu değişim selinden ölümdür.", ["ORYG"]="from this torrent of change is Death."},
["944:36"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ölüm ve onun zaferini şekillendirenler.", ["ORYG"]="Death, and those who shaped its victory."},
["944:37"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Biri seni durduracak, Denathrius!", ["ORYG"]="Someone will stop you, Denathrius!"},
["944:38"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ben bile-- (CHOKES)", ["ORYG"]="Even if I-- (CHOKES)"},
["944:39"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Şşşt. Konuşma.", ["ORYG"]="Shh. Do not speak."},
["944:40"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Gözlemleyin.", ["ORYG"]="Observe."},
["944:41"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="RENATHAL BOĞULUYOR", ["ORYG"]="RENATHAL CHOKING"},
["944:42"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="RENATHAL ZAYIFÇA NEFES ALIR", ["ORYG"]="RENATHAL INHALES WEAKLY"},
["944:43"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="RENATHAL INLIYOR", ["ORYG"]="RENATHAL GROANS"},
["944:44"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bu dersi hatırlayın.", ["ORYG"]="Remember this lesson."},
["945:01"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="# BÜYÜLEYICI ORKESTRA MÜZIĞI", ["ORYG"]="# ENCHANTING ORCHESTRAL MUSIC"},
["945:01.1"]={["START"]=1, ["STOP"]=0, ["NAPIS"]="[büyüleyici orkestra müziği]a]", ["ORYG"]="[enchanting orchestral music]"},
["945:02"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="TAL-INARA: Sayılamayan çağlar boyunca,", ["ORYG"]="TAL-INARA: For uncounted eons,"},
["945:02.1"]={["START"]=1, ["STOP"]=0, ["NAPIS"]="[Tal-Inara] Sayılamayan çağlar boyunca,y,", ["ORYG"]="[Tal-Inara] For uncounted eons,"},
["945:03"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Gölgeler Diyarı mükemmel bir düzen içindeydi.", ["ORYG"]="the Shadowlands was in perfect order."},
["945:04"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Sonsuz sonraki yaşamlar,", ["ORYG"]="Infinite afterlives,"},
["945:05"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Oribos, Ebedi Şehir ile,", ["ORYG"]="with Oribos, the Eternal City,"},
["945:06"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="parlayan kalp gibi.", ["ORYG"]="as the shining heart."},
["945:07"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Her ölümlü ruh Hakem'in huzuruna çıktı.", ["ORYG"]="Every mortal soul came before the Arbiter."},
["945:08"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ve o, her zaman bilge,", ["ORYG"]="And she, ever wise,"},
["945:09"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="deneyimli tüm", ["ORYG"]="experienced all"},
["945:10"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="bir ruhu şekillendirmiştir.", ["ORYG"]="that had shaped a soul in life."},
["945:11"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bu bilgiyle,", ["ORYG"]="With this knowledge,"},
["945:12"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="bütün ruhları", ["ORYG"]="she consigned every soul"},
["945:13"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Hak ettiği öbür dünyaya.", ["ORYG"]="to the afterlife it justly deserved."},
["945:14"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ta ki.", ["ORYG"]="Until..."},
["945:15"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="HAKEM ÇIĞLIKLARI", ["ORYG"]="ARBITER SHRIEKS"},
["945:15.1"]={["START"]=1, ["STOP"]=0, ["NAPIS"]="[Arbiter Shrieks]a]", ["ORYG"]="[Arbiter Shrieks]"},
["945:16"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="O korkunç anda,", ["ORYG"]="TAL-INARA: In that dread moment,"},
["945:16.1"]={["START"]=1, ["STOP"]=0, ["NAPIS"]="[O korkunç anda,e,", ["ORYG"]="[Tal-Inara] In that dread moment,"},
["945:17"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="mükemmel düzenimiz paramparça oldu.", ["ORYG"]="our perfect order was shattered."},
["945:18"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ve böylece her ruh,", ["ORYG"]="And so it is that every soul,"},
["945:19"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="hem nazik hem de zalim,", ["ORYG"]="kind and cruel alike,"},
["945:20"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="hak ettiği öbür dünyadan mahrum bırakılır,", ["ORYG"]="is denied its rightful afterlife,"},
["945:21"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ve bunun yerine lanetlendi", ["ORYG"]="and instead is damned"},
["945:22"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Maw'ın kaçınılmaz işkencesine.", ["ORYG"]="to the inescapable torment of the Maw."},
["946:01"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="# UĞURSUZ ORKESTRA MÜZIĞI", ["ORYG"]="# OMINOUS ORCHESTRAL MUSIC"},
["946:01.1"]={["START"]=1, ["STOP"]=0, ["NAPIS"]="[uğursuz orkestra müzi̇ği̇]a]", ["ORYG"]="[ominous orchestral music]"},
["946:02"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yapmayacağım. Bir daha olmaz.", ["ORYG"]="JAINA: I won't. Not again."},
["946:02.1"]={["START"]=1, ["STOP"]=0, ["NAPIS"]="[Yapmayacağım. Bir daha olmaz.u.", ["ORYG"]="[Jaina] I won't. Not again."},
["946:03"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Hayır. Hayır!", ["ORYG"]="No. No!"},
["946:04"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Boyun eğmeyeceğim!", ["ORYG"]="I will not yield!"},
["946:05"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Aklım bana ait!", ["ORYG"]="My mind is my own!"},
["946:06"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Beni duyuyor musun?", ["ORYG"]="Do you hear me?"},
["946:07"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="JAINA ÇIĞLIK ATIYOR", ["ORYG"]="JAINA SCREAMS"},
["946:07.1"]={["START"]=1, ["STOP"]=0, ["NAPIS"]="[Jaina Çığlıkları]y]", ["ORYG"]="[Jaina Screams]"},
["946:08"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="THRALL GRUNTS", ["ORYG"]="THRALL GRUNTS"},
["946:08.1"]={["START"]=1, ["STOP"]=0, ["NAPIS"]="[Thrall Grunts]a]", ["ORYG"]="[Thrall Grunts]"},
["946:09"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="THRALL YELLS", ["ORYG"]="THRALL YELLS"},
["946:09.1"]={["START"]=1, ["STOP"]=0, ["NAPIS"]="[Thrall bağırır]a]", ["ORYG"]="[Thrall yells]"},
["946:10"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="THRALL: Her kimsen,", ["ORYG"]="THRALL: Whoever you are,"},
["946:10.1"]={["START"]=1, ["STOP"]=0, ["NAPIS"]="[Her kimsen,", ["ORYG"]="[Thrall] Whoever you are,"},
["946:11"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ne istersen,", ["ORYG"]="whatever you want,"},
["946:12"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Seninle savaşacağım!", ["ORYG"]="I will fight you!"},
["946:13"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Beni kıramayacaksın!", ["ORYG"]="You will not break me!"},
["946:14"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="THRALL YELLS", ["ORYG"]="THRALL YELLS"},
["946:14.1"]={["START"]=1, ["STOP"]=0, ["NAPIS"]="[Thrall bağırır]a]", ["ORYG"]="[Thrall yells]"},
["946:15"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="SYLVANAS: İhlal ettiler", ["ORYG"]="SYLVANAS: They have breached"},
["946:15.1"]={["START"]=1, ["STOP"]=0, ["NAPIS"]="[Sylvanas] İhlal ettiler", ["ORYG"]="[Sylvanas] They have breached"},
["946:16"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Primus'un Koltuğu", ["ORYG"]="the Seat of the Primus"},
["946:17"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ve uyarısını keşfetti.", ["ORYG"]="and discovered his warning."},
["946:18"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Talihsizlik,", ["ORYG"]="JAILER: Unfortunate,"},
["946:18.1"]={["START"]=1, ["STOP"]=0, ["NAPIS"]="[Talihsizlik,e,", ["ORYG"]="[Jailer] Unfortunate,"},
["946:19"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ama pek bir önemi yok.", ["ORYG"]="but of little consequence."},
["946:20"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Gözlerimiz her yerde.", ["ORYG"]="Our eyes are everywhere."},
["946:21"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bu baş belasıyla ilgilenilecek.", ["ORYG"]="This nuisance will be dealt with."},
["946:22"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="# MUSIC CRESCENDOS", ["ORYG"]="# MUSIC CRESCENDOS"},
["946:22.1"]={["START"]=1, ["STOP"]=0, ["NAPIS"]="[müzik crescendos]a]", ["ORYG"]="[music crescendos]"},
["947:01"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="# UĞURSUZ ORKESTRA MÜZIĞI", ["ORYG"]="# OMINOUS ORCHESTRAL MUSIC"},
["947:01.1"]={["START"]=1, ["STOP"]=0, ["NAPIS"]="[uğursuz orkestra müzi̇ği̇]A>", ["ORYG"]="[ominous orchestral music]"},
["947:02"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="AĞIR KAPI AÇIKLIĞI", ["ORYG"]="HEAVY DOOR OPENING"},
["947:02.1"]={["START"]=1, ["STOP"]=0, ["NAPIS"]="[ağır kapı açılışı]i>", ["ORYG"]="[heavy door opening]"},
["947:03"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="KAPI ÇARPARAK KAPANIR", ["ORYG"]="DOOR SLAMS SHUT"},
["947:03.1"]={["START"]=1, ["STOP"]=0, ["NAPIS"]="[KAPI KAPANIR]i>", ["ORYG"]="[door slams shut]"},
["947:04"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Umarım yerleşmişsinizdir.", ["ORYG"]="I do hope you've settled in."},
["947:05"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Konaklama biraz...", ["ORYG"]="The accommodations are a bit..."},
["947:06"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="seyrek, biliyorum.", ["ORYG"]="sparse, I know."},
["947:07"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Diğerleri nerede? Onlar güvende mi?", ["ORYG"]="Where are the others? Are they safe?"},
["947:08"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Güvende mi?", ["ORYG"]="Safe?"},
["947:09"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Hayır.", ["ORYG"]="No."},
["947:10"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Hiçbirinin güvende olduğunu söyleyemem.", ["ORYG"]="I wouldn't say any of them are... safe."},
["947:11"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Oyunlarından bıktım artık.", ["ORYG"]="I am so tired of your games."},
["947:12"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Nasıl istersen.", ["ORYG"]="As you wish."},
["947:13"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Artık sır yok.", ["ORYG"]="No more secrets."},
["947:14"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Artık yalan yok.", ["ORYG"]="No more lies."},
["947:15"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Sen kullanacağımız bir silahsın.", ["ORYG"]="You are a weapon we will use"},
["947:16"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="amaçlarımıza ulaşmak için.", ["ORYG"]="to achieve our ends."},
["947:17"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ölümün bir aracı olmayacağım.", ["ORYG"]="I will not become an instrument of death."},
["947:18"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yani yaşamı tercih ediyorsun, öyle mi?", ["ORYG"]="So you favor... life, is that it?"},
["947:19"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="O anlık titreşim.", ["ORYG"]="That momentary flicker."},
["947:20"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Her zalim saniye", ["ORYG"]="Every cruel second"},
["947:21"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="kaçınılmaz olanı erteleyerek geçirdi", ["ORYG"]="spent delaying the inevitable"},
