["952:02"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Nihayet,", ["ORYG"]="At long last,"},
["953:01"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bu ne cüret?", ["ORYG"]="WINTER QUEEN: How dare you"},
["953:01.1"]={["START"]=1, ["STOP"]=0, ["NAPIS"]="[Bu ne cüret", ["ORYG"]="[Winter Queen] How dare you"},
["953:02"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Buraya gel, kardeşim,", ["ORYG"]="come here, sister,"},
["953:03"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yardım çığlıklarımız duyulmadıktan sonra,", ["ORYG"]="after our cries for aid went unheard,"},
["953:04"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Cevapsız.", ["ORYG"]="unanswered."},
["953:05"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Çığlıklarını duydum,", ["ORYG"]="ELUNE'S VOICE: I heard your cries,"},
["953:05.1"]={["START"]=1, ["STOP"]=0, ["NAPIS"]="[Elune'nin sesi] Çığlıklarınızı duydum,i,", ["ORYG"]="[Elune's voice] I heard your cries,"},
["953:06"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Acını hissettim,", ["ORYG"]="felt your pain,"},
["953:07"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ve trajedinin ardından,", ["ORYG"]="and in the wake of tragedy,"},
["953:08"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ruhların çağlayanını gönderdi", ["ORYG"]="sent forth the cascade of souls"},
["953:09"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="seni ayakta tutmak için.", ["ORYG"]="to sustain you."},
["953:10"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Oh, Büyük Ağaç...", ["ORYG"]="Oh, the Great Tree..."},
["953:11"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Orada yok olan herkes", ["ORYG"]="All who perished there"},
["953:12"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Maw tarafından sahiplenildi.", ["ORYG"]="were claimed by the Maw."},
["953:13"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="O zaman ben de", ["ORYG"]="ELUNE'S VOICE: Then I have condemned"},
["953:13.1"]={["START"]=1, ["STOP"]=0, ["NAPIS"]="[O zaman mahkum ettimam", ["ORYG"]="[Elune's voice] Then I have condemned"},
["953:14"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="benim gözde çocuklarım.", ["ORYG"]="my favored children."},
["953:15"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bizim elimizle,", ["ORYG"]="By our hand,"},
["953:16"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ruhlarına rehberlik edebiliriz", ["ORYG"]="we may yet guide their souls"},
["953:17"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="baharlarına kadar.", ["ORYG"]="unto their spring."},
["953:18"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bununla başlayalım.", ["ORYG"]="Starting with this one."},
["953:19"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Tyrande beni çağırdı.", ["ORYG"]="ELUNE'S VOICE: Tyrande invoked me."},
["953:19.1"]={["START"]=1, ["STOP"]=0, ["NAPIS"]="[Elune'nin sesi] Tyrande beni çağırdı.a.", ["ORYG"]="[Elune's voice] Tyrande invoked me."},
["953:20"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bir seçim yapmalı.", ["ORYG"]="She must choose."},
["953:21"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="İntikam mı, yenilenme mi?", ["ORYG"]="Vengeance or renewal?"},
["953:22"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="# EPİK KORO ŞARKISI", ["ORYG"]="# EPIC CHORAL SINGING"},
["953:22.1"]={["START"]=1, ["STOP"]=0, ["NAPIS"]="[epi̇k koro şarkisi]a]", ["ORYG"]="[epic choral singing]"},
["953:23"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="# DRAMATIK ORKESTRA MÜZIĞI", ["ORYG"]="# DRAMATIC ORCHESTRAL MUSIC"},
["953:23.1"]={["START"]=1, ["STOP"]=0, ["NAPIS"]="[dramatik orkestra müziği]a]", ["ORYG"]="[dramatic orchestral music]"},
["954:01"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="[heyecan verici orkestra müziği]", ["ORYG"]="[stirring orchestral music]"},
["954:02"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="[crackling]", ["ORYG"]="[crackling]"},
["955:01"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="[Uther] Sylvanas'ın ruhu", ["ORYG"]="[Uther] Sylvanas's soul"},
["955:02"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="kırıldı,", ["ORYG"]="has been fractured,"},
["955:03"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="öldüğü andan itibaren.", ["ORYG"]="from the moment of her death…"},
["955:04"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Şimdiye kadar.", ["ORYG"]="until now."},
["955:05"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="[Yak onu!", ["ORYG"]="[Sylvanas] Burn it!"},
["955:06"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="[Sylvanas] Burası onların eviydi...", ["ORYG"]="[Sylvanas] This was their home…"},
["955:07"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ve sen hepsini katlettin!", ["ORYG"]="and you slaughtered all of them!"},
["955:08"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Nasıl olur da", ["ORYG"]="How could you take"},
["955:09"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Tüm o masum hayatlar?", ["ORYG"]="all those innocent lives?"},
["955:10"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bu ölüm ve yaşamın ötesinde bir şeydi!", ["ORYG"]="This was beyond life and death!"},
["955:11"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Gerçek özgürlüğe giden başka bir yol yoktu.", ["ORYG"]="There was no other path to true freedom."},
["955:12"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bunu nasıl göremezsin?", ["ORYG"]="How can you not see that?"},
["955:13"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Senin ne olduğunu görüyorum.", ["ORYG"]="I see what you are."},
["955:14"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Katil. Canavar.", ["ORYG"]="Murderer. Monster."},
["955:15"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Kasap!", ["ORYG"]="Butcher!"},
["955:16"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Neden bu işkenceden kaçamıyorum?", ["ORYG"]="Why can I not escape this torment?"},
["955:17"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="[snarls]", ["ORYG"]="[snarls]"},
["955:18"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Gardiyan aralarındaki bağı kopardı,", ["ORYG"]="The Jailer has severed their bond,"},
["955:19"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ve onu kınadı", ["ORYG"]="and condemned her"},
["955:20"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="zulmünü sonsuza dek yeniden yaşamak için.", ["ORYG"]="to endlessly relive her atrocities."},
["955:21"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ruhu bölünmüş kaldığı sürece,", ["ORYG"]="So long as her soul remains divided,"},
["955:22"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Uyanamıyor.", ["ORYG"]="she cannot wake."},
["955:23"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Belki de uyanmamalı.", ["ORYG"]="Maybe she shouldn't."},
["955:24"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bir tek o", ["ORYG"]="She's the only one"},
["955:25"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Jailer'ın planını bilen biri,", ["ORYG"]="who knows the Jailer's plan,"},
["955:26"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ve Anduin'i nasıl kurtarabileceğimizi.", ["ORYG"]="and how we might save Anduin."},
["955:27"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Anduin'i dönüştüren oydu.", ["ORYG"]="She's the one that turned Anduin."},
["955:28"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Jaina haklı.", ["ORYG"]="Jaina is right."},
["955:29"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ona nasıl güvenebiliriz?", ["ORYG"]="How can we possibly trust her?"},
["955:30"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="[Onun yarası çok daha derin...", ["ORYG"]="[Uther] Her wound runs so much deeper…"},
["955:31"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="benimkinden.", ["ORYG"]="than mine."},
["955:32"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="[yaklaşan ayak sesleri]", ["ORYG"]="[approaching footsteps]"},
["955:33"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="İyi karşılaşmalar, Korucu General.", ["ORYG"]="Well met, Ranger-General."},
["955:34"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bu da ne?", ["ORYG"]="W-What is this?"},
["955:35"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Kimsin sen?", ["ORYG"]="Who are you?"},
["955:36"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Seninle aynı kaderi paylaşan biri,", ["ORYG"]="Someone who shared your fate,"},
["955:37"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="bıçakla öldürüldü", ["ORYG"]="felled by the blade"},
["955:38"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="aynı prensin.", ["ORYG"]="of the very same prince."},
["955:39"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Arthas.", ["ORYG"]="Arthas."},
["955:40"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="O canavarı durdurmaya çalışırken öldüm,", ["ORYG"]="I died trying to stop that monster,"},
["955:41"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="sadece lanetli uyanmak için", ["ORYG"]="only to wake up haunted"},
["955:42"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="yüzümle.", ["ORYG"]="by one with my face."},
["955:43"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="O banshee.", ["ORYG"]="That banshee…"},
["955:44"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="sensin.", ["ORYG"]="is you."},
["955:45"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Hayır. Bunu kabul edemem.", ["ORYG"]="No."},
["955:46"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bunu kabul edemem.", ["ORYG"]="I cannot accept that."},
["955:47"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="[Onun yolu seninkinin bittiği yerde başladı,", ["ORYG"]="[Uther] Her path began where yours ended,"},
["955:48"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ve verdiği kararları gördün.", ["ORYG"]="and you've seen the decisions she made."},
["955:49"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Binlerce hayat boyunca asla", ["ORYG"]="Never in a thousand lifetimes"},
["955:50"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="savunduğum her şeye ihanet eder miydim!", ["ORYG"]="would I betray everything I stood for!"},
["955:51"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Anlaman mümkün değil.", ["ORYG"]="You can't possibly understand."},
["955:52"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="[Uther iç çeker]", ["ORYG"]="[Uther sighs]"},
["955:53"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Gardiyan aldatıcı bir şekilde kurnazdır.", ["ORYG"]="The Jailer is deceptively cunning."},
["955:54"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Onun piyonu olduğumu fark ettiğimde,", ["ORYG"]="When I realized I had become his pawn,"},
["955:55"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="neredeyse beni yok ediyordu.", ["ORYG"]="it nearly destroyed me."},
["955:56"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Hiç şüphesi yoktu.", ["ORYG"]="He had no doubts"},
["955:57"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="seni de yok edecekti.", ["ORYG"]="it would destroy you as well."},
["955:58"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Haklı mıydı?", ["ORYG"]="Was he right?"},
["955:59"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yoksa onun paramparça mirasını kabullenecek misin?", ["ORYG"]="Or will you accept her shattered legacy"},
["955:60"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ve bize onu nasıl durduracağımızı söyler misin?", ["ORYG"]="and tell us how to stop him?"},
["955:61"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="[Sylvanas] Onun suçları...", ["ORYG"]="[Sylvanas] Her crimes…"},
["955:62"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="affedilemez.", ["ORYG"]="are unforgiveable."},
["955:63"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Evet.", ["ORYG"]="Yes."},
["955:64"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ve o...", ["ORYG"]="And she…"},
["955:65"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yak onu!", ["ORYG"]="Burn it!"},
["955:66"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="...Sonuçlarıyla yüzleşmeliyim.", ["ORYG"]="…I must face the consequences."},
["955:67"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Geçmişi değiştiremeyiz,", ["ORYG"]="We cannot change the past,"},
["955:68"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ve asla affedilmeyebiliriz", ["ORYG"]="and we may never find forgiveness"},
["955:69"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="gelecekte...", ["ORYG"]="in the future…"},
["955:70"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ama hareketsizlik hepimize zarar verir.", ["ORYG"]="but inaction damns us all."},
["955:71"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Zaman kısa, Korucu General.", ["ORYG"]="Time is short, Ranger-General."},
["955:72"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Seçiminizi yapın.", ["ORYG"]="Make your choice."},
["955:73"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Elimden geleni yaptım.", ["ORYG"]="I've done all I can."},
["955:74"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="[kasvetli̇ orkestral müzi̇k]", ["ORYG"]="[somber orchestral music]"},
["955:75"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="[music fades out]", ["ORYG"]="[music fades out]"},
["956:01"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="[Anlamıyor musun?", ["ORYG"]="[Jailer/Anduin] Do you not understand?"},
["956:02"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bu bana bağlı.", ["ORYG"]="This one is bound to me."},
["956:03"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="[gürleme]", ["ORYG"]="[rumbling]"},
["956:04"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="[Sylvanas] Anduin!", ["ORYG"]="[Sylvanas] Anduin!"},
["956:05"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="[Son amacını yerine getir:", ["ORYG"]="[Jailer] Fulfill your final purpose:"},
["956:06"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="İmha.", ["ORYG"]="Annihilation."},
["956:07"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Kılıcımı taşıyan herkesin kaderi.", ["ORYG"]="The fate of all who carry my blade."},
["956:08"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="[Anduin homurdanıyor]", ["ORYG"]="[Anduin grunts]"},
["956:09"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="[Oğlum.", ["ORYG"]="[Varian] My son."},
["956:10"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="[Anduin gasps]", ["ORYG"]="[Anduin gasps]"},
["956:11"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bu kılıç karanlığa ait değil.", ["ORYG"]="This blade does not belong to darkness."},
["956:12"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Cesaretle dövüldü.", ["ORYG"]="It was forged by valor."},
["956:13"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="[Varok] Ve ayrıca.", ["ORYG"]="[Varok] And also..."},
["956:14"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="onurla.", ["ORYG"]="by honor."},
["956:15"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="[Varian] Onun mirası,", ["ORYG"]="[Varian] Its legacy,"},
["956:16"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ve bizimkiler, seninle,", ["ORYG"]="and ours, are with you,"},
["956:17"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Burada bile.", ["ORYG"]="even here."},
["956:18"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="[Varok] Şimdi, bitmesine izin ver.", ["ORYG"]="[Varok] Now, let it be finished."},
["956:19"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="[Anduin çığlık atıyor]", ["ORYG"]="[Anduin screams]"},
["956:20"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="[metalik çınlama]", ["ORYG"]="[metallic clang]"},
["956:21"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Arthas.", ["ORYG"]="Arthas..."},
["956:22"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ondan geriye kalan tek şey bu mu?", ["ORYG"]="Is this all that remains of him?"},
["956:23"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yaralı ruhunun son parıltısı,", ["ORYG"]="The last flicker of his scarred spirit,"},
["956:24"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Jailer'ın ocaklarında tüketildi.", ["ORYG"]="consumed in the forges of the Jailer."},
["956:25"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Taç yok.", ["ORYG"]="No crown."},
["956:26"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Taht yok.", ["ORYG"]="No throne."},
["956:27"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yargılanacak bir ruh bile kalmadı.", ["ORYG"]="Not even a soul left for judgement."},
["956:28"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Senden nefret ettim,", ["ORYG"]="I hated you,"},
["956:29"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="seni avladı,", ["ORYG"]="hunted you,"},
["956:30"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ve her bencil hareketinle.", ["ORYG"]="and with each selfish act..."},
["956:31"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="sen oldun.", ["ORYG"]="became you."},
["956:32"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bu benim taşımam gereken bir yük.", ["ORYG"]="That is my burden to bear."},
["956:33"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ama senin mirasın.", ["ORYG"]="But your legacy..."},
["956:34"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="sona erdi.", ["ORYG"]="is at an end."},
["956:35"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Git o zaman, Arthas Menethil.", ["ORYG"]="Begone, then, Arthas Menethil."},
["956:36"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Adının son fısıltısı da solsun.", ["ORYG"]="May the last whisper of your name fade..."},
["956:37"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ve unutulsun.", ["ORYG"]="and be forgotten."},
["957:01"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Hepsi gücü talep etmek için", ["ORYG"]="All to claim the power"},
["957:02"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="dünyanızda uyuyor.", ["ORYG"]="slumbering within your world."},
["957:03"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Azeroth'un ruhu,", ["ORYG"]="The soul of Azeroth,"},
["957:04"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yaralı,", ["ORYG"]="wounded,"},
["957:05"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="savunmasız,", ["ORYG"]="vulnerable,"},
["957:06"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yine de potansiyel ile dolup taşıyor.", ["ORYG"]="yet teeming with potential."},
["957:07"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Kullanacağım potansiyel", ["ORYG"]="Potential that I will use"},
["957:08"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bu kusurlu gerçekliği ortadan kaldırmak için.", ["ORYG"]="to eradicate this flawed reality."},
["957:09"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ölüm, dünyanızın ruhunu talep ediyor.", ["ORYG"]="Death claims the soul of your world."},
["957:10"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Şimdi şahit olun ölümlüler,", ["ORYG"]="Now bear witness, mortals,"},
["957:11"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="sonsuzluğun sonuna kadar.", ["ORYG"]="to eternity's end."},
["958:01"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="[homurdanıyor]", ["ORYG"]="[grunts]"},
["958:02"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bu olmamalı.", ["ORYG"]="This must not be..."},
["958:03"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Hakem olarak görevinize ihanet ettiniz,", ["ORYG"]="You have betrayed your duty as Arbiter,"},
["958:04"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ve sonsuza dek bağlı kalacak.", ["ORYG"]="and shall be bound forevermore."},
["958:05"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Senin deliliğin", ["ORYG"]="Your madness has threatened"},
["958:06"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="yaşam ve ölüm döngüsünün tamamı.", ["ORYG"]="the cycle of life and death entire."},
["958:07"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="[Denathrius] Arayabilirdin", ["ORYG"]="[Denathrius] You could have sought"},
["958:08"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="başka bir yol, kardeşim.", ["ORYG"]="another way, brother."},
["958:09"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Neler yapabileceğimizi bir düşünsene.", ["ORYG"]="Imagine what we could have"},
["958:10"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="birlikte başardı.", ["ORYG"]="accomplished together."},
["958:11"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="[Neden, Zovaal?", ["ORYG"]="[The Primus] Why, Zovaal?"},
["958:12"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Seni bu sona sürükleyen neydi?", ["ORYG"]="What drove you to this end?"},
["958:13"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ölüme mahkum olanı koruyorsun.", ["ORYG"]="You preserve that which is doomed."},
["958:14"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bölünmüş bir kozmos hayatta kalamaz", ["ORYG"]="A cosmos divided will not survive"},
["958:15"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="GELECEK OLAN.", ["ORYG"]="what is to come."},
["958:16"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="[kasvetli̇ koro müzi̇ği̇]", ["ORYG"]="[somber choral music]"},
["961:01"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="[ıslık çalan rüzgar]", ["ORYG"]="[whistling wind]"},
["961:02"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="[epik müzik]", ["ORYG"]="[epic music]"},
["961:03"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Fırtınanın sahibesi.", ["ORYG"]="Oh mistress of the storm."},
["961:04"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="İlkel güçler ayağa kalktı", ["ORYG"]="The primal powers have risen"},
["961:05"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="seni özgür bırakmak için.", ["ORYG"]="to set you free."},
["961:06"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Grah!", ["ORYG"]="Grah!"},
["961:07"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="[acı içinde homurdanıyor]", ["ORYG"]="[grunts in pain]"},
["961:08"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="[groans]", ["ORYG"]="[groans]"},
["961:09"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="[homurdanıyor]", ["ORYG"]="[grunts]"},
["961:10"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="[exhales]", ["ORYG"]="[exhales]"},
["961:11"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="[taşlar çatırdıyor]", ["ORYG"]="[crunching rocks]"},
["961:12"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="[ağır ayak sesleri]", ["ORYG"]="[heavy footsteps]"},
["961:13"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="[Evet.", ["ORYG"]="[Raszageth] Yes..."},
["961:14"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="elementler şarkı söyler.", ["ORYG"]="the elements sing."},
["961:15"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bu dünya için yeni bir çağı müjdeliyorlar.", ["ORYG"]="They herald a new age for this world."},
["961:16"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="[şimşek çıtırtıları]", ["ORYG"]="[lightning crackles]"},
["961:17"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="[Raszageth] Akrabalarımı buldunuz mu?", ["ORYG"]="[Raszageth] Have you found my kin?"},
["961:18"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Nerede hapsedildiklerini biliyoruz,", ["ORYG"]="We know where they are imprisoned,"},
["961:19"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Fırtına Yiyen.", ["ORYG"]="Storm-Eater."},
["961:20"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="[Raszageth] Yakında bağları", ["ORYG"]="[Raszageth] Soon their bonds"},
["961:21"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="kırılacak.", ["ORYG"]="will be broken."},
["961:22"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ah, peki bu nedir?", ["ORYG"]="Ah, and what is this?"},
["961:23"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Neltharian'ın Soyu.", ["ORYG"]="The Brood of Neltharian."},
["961:24"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ölümünün yankılandığını hissettim", ["ORYG"]="I felt his demise reverberate"},
["961:25"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="yeryüzünde.", ["ORYG"]="through the earth..."},
["961:26"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ve bundan zevk aldı.", ["ORYG"]="and reveled in it."},
["961:27"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Belki de onun kaderini paylaşmak istersiniz?", ["ORYG"]="Perhaps you wish to share his fate?"},
["961:28"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="[Wrathion] Olmayı dilemiştim", ["ORYG"]="[Wrathion] I had wished to become"},
["961:29"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Olması gerektiği gibi.", ["ORYG"]="what he was meant to be."},
["961:30"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Olması gereken şey.", ["ORYG"]="What he should have been."},
["961:31"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="[Raszageth] Anlamıyorsun", ["ORYG"]="[Raszageth] You do not fathom"},
["961:32"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ejderha ırkının olması gerektiği gibi.", ["ORYG"]="what dragonkind was meant to be."},
["961:33"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ama olacaksın.", ["ORYG"]="But you will."},
["961:34"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="[kükreme devam edi̇yor]", ["ORYG"]="[roaring continues]"},
["961:35"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="[Raszageth] Git.", ["ORYG"]="[Raszageth] Go."},
["961:36"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Onlara bu dünyayı tarayacağımızı söyle", ["ORYG"]="Tell them we will scour this world"},
["961:37"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Titanların lekesinin.", ["ORYG"]="of the titans’ stain."},
["961:38"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Fırtına habercisi olsun", ["ORYG"]="Let the storm be the harbinger"},
["961:39"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="dönüşümüzün!", ["ORYG"]="of our return!"},
["962:01"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="[ağır ayak sesleri]", ["ORYG"]="[heavy footsteps]"},
["962:02"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="[Seni görmeyi beklemiyordum", ["ORYG"]="[Khadgar] I did not expect to see you"},
["962:03"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="çok yakında tekrar, dostum,", ["ORYG"]="again so soon, my friend,"},
["962:04"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="cevap verdikten sonra", ["ORYG"]="after you’d answered"},
["962:05"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Adaların Çağrısı.", ["ORYG"]="the call of the isles."},
["962:06"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bir şey oldu, Khadgar.", ["ORYG"]="Something has happened, Khadgar."},
["962:07"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Korkunç bir şey.", ["ORYG"]="Something terrible."},
["962:08"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Kalecgos.", ["ORYG"]="Kalecgos..."},
["962:09"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Anlat bana.", ["ORYG"]="Tell me."},
["962:10"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Her şey çok çabuk oldu,", ["ORYG"]="It all happened so quickly,"},
["962:11"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ve Wrathion, genç olduğu kadar.", ["ORYG"]="and Wrathion, young as he is..."},
["962:12"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="cesurca ya da belki aptalca,", ["ORYG"]="bravely, or perhaps foolishly,"},
["962:13"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="durdurmaya çalıştı.", ["ORYG"]="tried to stop it..."},
["962:14"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ama çok geç kalmıştı.", ["ORYG"]="but he was too late."},
["962:15"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="[çatırdayan şimşek]", ["ORYG"]="[crackling lightning]"},
["962:16"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="[ağır ayak sesleri]", ["ORYG"]="[heavy footsteps]"},
["962:17"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="[Kalecgos] Fırtına", ["ORYG"]="[Kalecgos] The tempest"},
["962:18"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="çoktan serbest bırakılmıştı.", ["ORYG"]="had already been unleashed."},
["962:19"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="[Yaşamama izin verdi,", ["ORYG"]="[Wrathion] She let me live,"},
["962:20"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="bir mesajla.", ["ORYG"]="with a message."},
["962:21"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Dünyayı temizlemek için geliyorlar.", ["ORYG"]="They are coming to cleanse the world"},
["962:22"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Titanların lekesi.", ["ORYG"]="of the titans' stain."},
["962:23"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Alexstrasza.", ["ORYG"]="Alexstrasza..."},
["962:24"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Kim o?", ["ORYG"]="Who is she?"},
["962:25"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Nedir o?", ["ORYG"]="What is she?"},
["962:26"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="[Alexstrasza] O...", ["ORYG"]="[Alexstrasza] She..."},
["962:27"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Raszageth'tir.", ["ORYG"]="is Raszageth."},
["962:28"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="İlkel enkarne olanların en genci.", ["ORYG"]="Youngest of the primal incarnates."},
["962:29"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Enkarne mi?", ["ORYG"]="Incarnates?"},
["962:30"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Dört tehlikeli taraftar", ["ORYG"]="Four dangerous adherents"},
["962:31"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="temel güçlerin.", ["ORYG"]="of the elemental forces."},
["962:32"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yönlerin şafağında,", ["ORYG"]="At the dawn of the aspects,"},
["962:33"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="uçuşlarımız titanların hediyelerini kucakladı.", ["ORYG"]="our flights embraced the titans' gifts."},
["962:34"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Onlar kabul etmedi.", ["ORYG"]="They... did not."},
["962:35"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ardından gelen savaş hayal bile edilemezdi,", ["ORYG"]="The war that followed was unimaginable,"},
["962:36"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ve tüm gücümüzü bir araya getirdi", ["ORYG"]="and it took all of our strength combined"},
["962:37"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="onları kovmak için.", ["ORYG"]="to banish them."},
["962:38"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Eğer çok tehlikelilerse,", ["ORYG"]="If they were so dangerous,"},
["962:39"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Neden yok edilmediler?!", ["ORYG"]="why were they not destroyed?!"},
["962:40"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bunu yapmaya cesaretim yoktu.", ["ORYG"]="I hadn’t the heart to do it."},
["962:41"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bir zamanlar debriyaj arkadaşıydık.", ["ORYG"]="We were once as clutchmates."},
["962:42"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Zaman, öyle görünüyor,", ["ORYG"]="Time, it seems,"},
["962:43"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="öfkelerini dindirmedi.", ["ORYG"]="has not quelled their fury."},
["962:44"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bir de bize bakın.", ["ORYG"]="And look at us."},
["962:45"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Şimdi akrabalarını serbest bırakmalı mı?", ["ORYG"]="Should she free her kin now,"},
["962:46"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Onları durduracak gücümüz yok.", ["ORYG"]="we haven’t the strength to stop them."},
["962:47"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ve eğer Iridikron'un açlığı serbest bırakılırsa.", ["ORYG"]="And if Iridikron’s hunger is unleashed..."},
["962:48"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="O zaman başka seçeneğimiz yok.", ["ORYG"]="Then we have no choice."},
["962:49"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Eğer bir kez daha koruyucu olacaksak,", ["ORYG"]="If we are to be protectors once more,"},
["962:50"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ejderha uçuşlarımızın yönleri", ["ORYG"]="the aspects of our dragonflights"},
["962:51"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="yeniden yapılmalı.", ["ORYG"]="must be made anew."},
["962:52"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Kraliçemiz kararlı, Khadgar,", ["ORYG"]="Our queen is determined, Khadgar,"},
["962:53"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ama daha yeni başladık", ["ORYG"]="but we’ve only just begun"},
["962:54"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="tekrar kim olduğumuzu bulmak için.", ["ORYG"]="to find who we are again."},
["962:55"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ve korkarım ki yardım olmadan", ["ORYG"]="And I fear that without help"},
["962:56"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="asla şansımız olmayabilir", ["ORYG"]="we may never get the chance"},
["962:57"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="geleceğimizin güvence altına alındığını görmek için.", ["ORYG"]="to see our future secured."},
["962:58"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Hmm...", ["ORYG"]="Hmm..."},
["962:59"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="O zaman ölümlü ırklar da", ["ORYG"]="Then it seems the mortal races too"},
["962:60"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="çağrıya cevap vermeli", ["ORYG"]="must answer the call"},
["962:61"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ve önümüzdeki fırtınalarla yüzleşin.", ["ORYG"]="and face the storms ahead."},
["969:01"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Pençeler! Ön tarafa!", ["ORYG"]="Talons! To the fore!"},
["969:02"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Benimle kalın. Yan tarafa! Kımıldayın!", ["ORYG"]="Stay with me. On the flank! Move!"},
["969:03"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Ebon Scales! Geri çekilin!", ["ORYG"]="Ebon Scales! Fall back!"},
["969:04"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Geri çekilin!", ["ORYG"]="Retreat!"},
["969:05"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="[bağırır]", ["ORYG"]="[yells]"},
["969:06"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="[sessizlik]", ["ORYG"]="[silence]"},
["969:07"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="[yankılanan ses] Uyu...", ["ORYG"]="[echoing voice] Sleep..."},
["979:01"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Dur!", ["ORYG"]="Halt!"},
["979:02"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Shikaar bölgesine izinsiz giriyorsunuz!", ["ORYG"]="You trespass in Shikaar territory!"},
["979:03"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Kim olduğunu açıkla...", ["ORYG"]="Explain what you... are..."},
["979:04"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="burada... ne yapıyorsun.", ["ORYG"]="doing... here."},
["979:05"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Artık devam edebilir miyiz?", ["ORYG"]="Can we get on with it?"},
["979:06"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Onu burada bulacağımızı söylemiştin.", ["ORYG"]="You said we'd find it here."},
["979:07"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bulduk.", ["ORYG"]="We have."},
["979:08"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Anladığım kadarıyla,", ["ORYG"]="From what I have transcribed,"},
["979:09"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Neltharion'un Aberrus'a giden gizli bir yolu vardı.", ["ORYG"]="Neltharion had a hidden path to Aberrus"},
["979:10"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Bu tepenin hemen altında.", ["ORYG"]="just below this ridge."},
["979:11"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Toprak ve suyun altında mühürlenmiş,", ["ORYG"]="Sealed beneath earth and water,"},
["979:12"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="binlerce yıldır rahatsız edilmemiş.", ["ORYG"]="undisturbed for thousands of years."},
["979:13"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="O zaman yolu açalım.", ["ORYG"]="Then let us open the way."},
["979:14"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Fyrakk, aşağıdaki elemental güçle", ["ORYG"]="Fyrakk, you will feast"},
["979:15"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="kendine ziyafet çekeceksin.", ["ORYG"]="upon the elemental power below."},
["979:16"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yaşlıları uykularından uyandırın", ["ORYG"]="Wake the Elders from their slumber"},
["979:17"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ve yolumuza çıkan herkesi yakıp kül edin.", ["ORYG"]="and incinerate any who stand in our way."},
["979:18"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Enfes.", ["ORYG"]="Exquisite."},
["979:19"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Onun ardından dracthyr,", ["ORYG"]="In his wake, the dracthyr will succumb"},
["979:20"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Aberrus'un cazibesine yenik düşecek", ["ORYG"]="to the temptation of Aberrus"},
["979:21"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="ve Aspect'lerin en karanlık", ["ORYG"]="and unleash"},
["979:22"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="kâbuslarını serbest bırakacak.", ["ORYG"]="the Aspects' darkest nightmares."},
["979:24"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Yapacak çok işimiz var.", ["ORYG"]="Yapacak çok işimiz var."},
["979:25"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="Neltharion'un çocukları", ["ORYG"]="Let the children of Neltharion"},
["979:26"]={["START"]=0, ["STOP"]=0, ["NAPIS"]="doğuştan gelen haklarını talep etsinler.", ["ORYG"]="claim their birthright."},
["Blood Elf:01"]={["START"]=1.04, ["STOP"]=7.40, ["NAPIS"]="Geçtiğimiz birkaç yıl, ebedi Quel\'Thalas diyarında benzeri görülmemiş değişikliklere tanık oldu."}, 
["Blood Elf:02"]={["START"]=7.62, ["STOP"]=13.16, ["NAPIS"]="Blood elfler, çılgın liderleri Kael\'thas Sunstrider\'ın iradesini izleyerek,"}, 
["Blood Elf:03"]={["START"]=13.16, ["STOP"]=22.20, ["NAPIS"]="kutsal Sunwell\'lerini ağza alınamaz bir kötülüğün geçidine dönüştürmek için tehlikeli kaotik büyüler kullandılar."}, 
["Blood Elf:04"]={["START"]=22.20, ["STOP"]=26.42, ["NAPIS"]="Kael\'thas ve şeytani efendileri sonunda yenildiğinde,"}, 
["Blood Elf:05"]={["START"]=26.42, ["STOP"]=30.86, ["NAPIS"]="ölmekte olan bir Naaru, Sunwell\'i kutsal bir enerji kaynağına dönüştürmek için"}, 
["Blood Elf:06"]={["START"]=30.86, ["STOP"]=39.40, ["NAPIS"]="yaşam özünü feda ettiğinden, Sunwell\'in kendi içinde farklı türde bir dönüşüm meydana geldi."}, 
["Blood Elf:07"]={["START"]=39.88, ["STOP"]=46.40, ["NAPIS"]="Şimdi Blood Elf hükümdarı Lor\'themar Theron halkı için ufukta yeni bir umut görüyor."}, 
["Blood Elf:08"]={["START"]=46.45, ["STOP"]=51.38, ["NAPIS"]="Zaman içinde, Sunwell\'in ışığı Blood Elfleri lanetli durumlarından kurtarabilir,"}, 
["Blood Elf:09"]={["START"]=51.38, ["STOP"]=55.38, ["NAPIS"]="ancak birçoğu hâlâ elde ettikleri gizemli güçlere tutunuyor"}, 
["Blood Elf:10"]={["START"]=55.38, ["STOP"]=57.64, ["NAPIS"]="ve onlardan vazgeçmekte tereddüt ediyor."}, 
["Blood Elf:11"]={["START"]=58.44, ["STOP"]=63.46, ["NAPIS"]="Kalan Blood Elflerinden biri olarak Quel\'Thalas\'ı korumak için savaşmalı,"}, 
["Blood Elf:12"]={["START"]=63.46, ["STOP"]=67.32, ["NAPIS"]="ve kadim atalarınızın ruhlarını kurtarmaya yardım etmelisin."}, 
["Blood Elf3:01"]={["START"]=1.46, ["STOP"]=4.20, ["NAPIS"]="Yaklaşık yedi bin yıl boyunca"}, 
["Blood Elf3:02"]={["START"]=4.20, ["STOP"]=8.16, ["NAPIS"]="Yüce Elfler, kuzey Lordaeron ormanlarının derinliklerinde saklı,"}, 
["Blood Elf3:03"]={["START"]=8.16, ["STOP"]=11.82, ["NAPIS"]="ışıltılı ve büyülü bir krallık geliştirdiler."}, 
["Blood Elf3:04"]={["START"]=11.84, ["STOP"]=13.50, ["NAPIS"]="Ama beş yıl önce"}, 
["Blood Elf3:05"]={["START"]=13.50, ["STOP"]=17.10, ["NAPIS"]="Undead vebasıQuel\'Thalas\'ı işgal etti"}, 
["Blood Elf3:06"]={["START"]=17.10, ["STOP"]=20.80, ["NAPIS"]="ve Elfleri yok oluşa sürükledi."}, 
["Blood Elf3:07"]={["START"]=20.82, ["STOP"]=24.50, ["NAPIS"]="Lich King Arthas tarafından yönetilen veba"}, 
["Blood Elf3:08"]={["START"]=24.60, ["STOP"]=27.28, ["NAPIS"]="Sunwell\'i yok etti ve"}, 
["Blood Elf3:09"]={["START"]=27.30, ["STOP"]=32.04, ["NAPIS"]="böylece Elfleri gizli güçlerinin kaynağından mahrum bıraktı."}, 
["Blood Elf3:10"]={["START"]=32.04, ["STOP"]=35.50, ["NAPIS"]="Bu çatışmanın izleri açıkça görülebilse de,"}, 
["Blood Elf3:11"]={["START"]=35.60, ["STOP"]=40.12, ["NAPIS"]="geriye kalan Elfler birleşerek anavatanlarının büyük bir kısmını geri aldılar."}, 
["Blood Elf3:12"]={["START"]=41.66, ["STOP"]=44.24, ["NAPIS"]="Kendilerine Blood Elf diyorlar,"}, 
["Blood Elf3:13"]={["START"]=44.24, ["STOP"]=49.92, ["NAPIS"]="Bu zalim hayatta kalanlar kendilerini bir zamanlar sahip oldukları güçleri geri almaya adamışlardır."}, 
["Blood Elf3:14"]={["START"]=50.34, ["STOP"]=55.20, ["NAPIS"]="Sevgili prensleri Kael\'thas Sunstrider\'ın liderliğinden ilham aldılar,"}, 
["Blood Elf3:15"]={["START"]=55.20, ["STOP"]=59.16, ["NAPIS"]="Blood Elfler şimdi yeni gizli büyü kaynakları ve"}, 
["Blood Elf3:16"]={["START"]=59.16, ["STOP"]=65.22, ["NAPIS"]="topraklarını Veba\'nın ölümsüz canavarlarından korumanın yolları arıyorlar."}, 
["Blood Elf3:17"]={["START"]=65.70, ["STOP"]=69.00, ["NAPIS"]="Hayatta kalan birkaç Blood Elf\'ten biri olarak,"}, 
["Blood Elf3:18"]={["START"]=69.20, ["STOP"]=72.24, ["NAPIS"]="Büyü arzunu kontrol etmeli"}, 
["Blood Elf3:19"]={["START"]=72.30, ["STOP"]=76.50, ["NAPIS"]="ve halkınızın kaderini şekillendirmeye yardımcı olmalısın.."}, 
["Death Knight:01"]={["START"]=1.00, ["STOP"]=5.16, ["NAPIS"]="Bir kahraman, bir zamanlar öyleydin. "}, 
["Death Knight:02"]={["START"]=5.16, ["STOP"]=10.00, ["NAPIS"]="Gölgeye karşı cesurca durdun ve hayatınla dünya için"}, 
["Death Knight:03"]={["START"]=10.20, ["STOP"]=12.30, ["NAPIS"]="başka bir doğuşu daha elde ettin."}, 
["Death Knight:04"]={["START"]=12.30, ["STOP"]=15.74, ["NAPIS"]="Ama savaştığın kötülük o kadar kolay kovulamaz."}, 
["Death Knight:05"]={["START"]=15.76, ["STOP"]=19.82, ["NAPIS"]="İddia ettiğiniz zafer o kadar kolay elde edilemez."}, 
["Death Knight:06"]={["START"]=19.86, ["STOP"]=24.50, ["NAPIS"]="Artık ölümün hayaleti bir kez daha dünyanın üzerinde beliriyor"}, 
["Death Knight:07"]={["START"]=24.50, ["STOP"]=29.14, ["NAPIS"]="ve son saltanatını getirecek yeni şampiyonlar buldu."}, 
["Death Knight:08"]={["START"]=29.14, ["STOP"]=31.20, ["NAPIS"]="Karanlığın şövalyeleri,"}, 
["Death Knight:09"]={["START"]=31.20, ["STOP"]=37.20, ["NAPIS"]="Lich King\'in iradesine bağlı ölüm ve yıkım rünlerine sahipler."}, 
["Death Knight:10"]={["START"]=37.50, ["STOP"]=40.98, ["NAPIS"]="Bu onların yükseliş saati."}, 
["Death Knight:11"]={["START"]=41.00, ["STOP"]=46.80, ["NAPIS"]="Bu senin karanlık yeniden doğuşunun saati."}, 
["Draenei:01"]={["START"]=1.00, ["STOP"]=5.82, ["NAPIS"]="Kutsal Işık\'tan ve inançlarının ölümsüz gücünden güç alan draenei,"}, 
["Draenei:02"]={["START"]=6.10, ["STOP"]=11.50, ["NAPIS"]="Outland\'deki şeytani Burning Legion\'a karşı hücuma öncülük etti."}, 
["Draenei:03"]={["START"]=12.50, ["STOP"]=15.00, ["NAPIS"]="Şimdi Lejyon\'un yenilgisiyle birlikte,"}, 
["Draenei:04"]={["START"]=15.00, ["STOP"]=19.70, ["NAPIS"]="onları Azeroth\'a ilk getiren umutsuz görevi tamamladılar."}, 
["Draenei:05"]={["START"]=19.70, ["STOP"]=25.00, ["NAPIS"]="Her ne kadar Draenei\'nin bir kısmı eski uygarlıklarını canlandırmak için Outland\'e geri gönderilmiş olsa da,"}, 
["Draenei:06"]={["START"]=25.44, ["STOP"]=31.50, ["NAPIS"]="çoğunluk kalmayı ve Antlaşma\'ya olan kutsal bağlılıklarını yerine getirmeyi tercih etti."}, 
["Draenei:07"]={["START"]=31.92, ["STOP"]=35.98, ["NAPIS"]="Güçlü bir vizyon tarafından yönlendirilen ölümsüz peygamber Velen şöyle inanır,"}, 
["Draenei:08"]={["START"]=35.98, ["STOP"]=41.70, ["NAPIS"]="ışık ve karanlık arasında büyük bir savaşın yakın olduğunu."}, 
["Draenei:09"]={["START"]=41.90, ["STOP"]=46.26, ["NAPIS"]="Ve Azeroth bunun en önemli savaş alanı olacak."}, 
["Draenei:10"]={["START"]=46.30, ["STOP"]=51.30, ["NAPIS"]="Velen\'in seçilmişlerinden biri olarak, cesurca gölgelere karşı durmalı."}, 
["Draenei:11"]={["START"]=51.70, ["STOP"]=55.80, ["NAPIS"]="Ve halkınızın yaklaşan savaşa hazır olmasını sağlamalısınız."}, 
["Draenei3:01"]={["START"]=0.88, ["STOP"]=2.22, ["NAPIS"]="Bir ay önce,"}, 
["Draenei3:02"]={["START"]=2.22, ["STOP"]=6.94, ["NAPIS"]="korkunç bir patlama kuzey Kalimdor semalarını yerle bir etti."}, 
["Draenei3:03"]={["START"]=6.94, ["STOP"]=11.68, ["NAPIS"]="O anda, büyük gemi Exodar göklerden düştü"}, 
["Draenei3:04"]={["START"]=11.68, ["STOP"]=14.58, ["NAPIS"]="ve Azeroth dünyasına çarptı."}, 
["Draenei3:05"]={["START"]=15.20, ["STOP"]=18.28, ["NAPIS"]="Harap olmuş Outland dünyasından kaçan asil Draenei,"}, 
["Draenei3:06"]={["START"]=18.28, ["STOP"]=21.94, ["NAPIS"]="güvenli bir sığınağa ulaşmak için"}, 
["Draenei3:07"]={["START"]=21.94, ["STOP"]=24.20, ["NAPIS"]="boyut yolculuğu yapan Exodar\'ı kullandı."}, 
["Draenei3:08"]={["START"]=24.20, ["STOP"]=30.04, ["NAPIS"]="Burning Legion\'un kudretine karşı duran kahraman İttifak\'ın hikayelerinden ilham alan Draenei,"}, 
["Draenei3:09"]={["START"]=30.04, ["STOP"]=35.46, ["NAPIS"]="parçalanmış vatanlarını geri almak için yardım istemeye geldi."}, 
["Draenei3:10"]={["START"]=35.46, ["STOP"]=41.01, ["NAPIS"]="Kendilerini yaşamı korumaya ve Kutsal Işık\'ın ilkelerini sürdürmeye adayan Draenei,"}, 
["Draenei3:11"]={["START"]=41.01, ["STOP"]=46.20, ["NAPIS"]="Burning Legion\'la savaşmak ve onun korkunç Burning Crusade\'ini durdurmak için"}, 
["Draenei3:12"]={["START"]=46.20, ["STOP"]=49.68, ["NAPIS"]="yeni bir savaşçı koalisyonu toplamayı umuyor."}, 
["Draenei3:13"]={["START"]=49.68, ["STOP"]=54.42, ["NAPIS"]="Sadece cesaret ve Işığa olan sarsılmaz inançlarıyla"}, 
["Draenei3:14"]={["START"]=54.42, ["STOP"]=57.46, ["NAPIS"]="donanmış olan Draenei, İttifak\'ı bulmayı ve"}, 
["Draenei3:15"]={["START"]=57.46, ["STOP"]=62.88, ["NAPIS"]="onları Azeroth göklerinin ötesinde bekleyen kadere doğru"}, 
["Draenei3:16"]={["START"]=63.14, ["STOP"]=69.06, ["NAPIS"]="yönlendirmeyi dört gözle bekliyor."}, 
["Dwarf:01"]={["START"]=0.00, ["STOP"]=4.94, ["NAPIS"]="Ironforge\'un kalıcı salonlarına büyük bir değişim geldi."}, 
["Dwarf:02"]={["START"]=4.94, ["STOP"]=14.32, ["NAPIS"]="Titanların çalışmalarına kafayı takan cüceler, yaratıcılarının mistik tabletlerini efsanevi Ulduar Şehri\'nden aldılar."}, 
["Dwarf:03"]={["START"]=14.32, ["STOP"]=22.78, ["NAPIS"]="Böyle bir tableti aktive eden Kral Magni Bronzbeard heykele benzeyen formunu"}, 
["Dwarf:04"]={["START"]=22.78, ["STOP"]=26.60, ["NAPIS"]="Ironforge\'un elmas kalbiyle birleştiren korkunç bir lanetin kurbanı oldu."}, 
["Dwarf:05"]={["START"]=27.10, ["STOP"]=32.34, ["NAPIS"]="Bu trajediyi daha da derinleştirmek için Magni\'nin ayrı yaşadığı kızı Moira geldi"}, 
["Dwarf:06"]={["START"]=32.34, ["STOP"]=39.26, ["NAPIS"]="ve babasının tahtını kendisi ve bebek Kara Demir oğlu için talep etti."}, 
["Dwarf:07"]={["START"]=39.26, ["STOP"]=49.58, ["NAPIS"]="İç savaşı önlemek için cüceler, gücü klanlar arasında eşit olarak paylaştıracak huzursuz bir koalisyon olan Üç Çekiç Konseyi\'ni kurdular."}, 
["Dwarf:08"]={["START"]=49.58, ["STOP"]=56.78, ["NAPIS"]="Şimdi, Krallık içinde yükselen siyasi kargaşa ve çevredeki toprakları kasıp kavuran büyük Tufan ile"}, 
["Dwarf:09"]={["START"]=56.78, ["STOP"]=64.14, ["NAPIS"]="Ironforge\'un geleceği sizin gibi cesur cücelere bağlı."}, 
["Dwarf3:01"]={["START"]=0.00, ["STOP"]=2.86, ["NAPIS"]="Ironforge\'un metanetli Cüceleri"}, 
["Dwarf3:02"]={["START"]=2.86, ["STOP"]=7.60, ["NAPIS"]="sayısız nesiller boyunca toprağın derinliklerinden hazineler çıkardılar."}, 
["Dwarf3:03"]={["START"]=7.60, ["STOP"]=11.68, ["NAPIS"]="Ironforge Dağı\'ndaki zaptedilemez kalelerinde saklanarak,"}, 
["Dwarf3:04"]={["START"]=11.68, ["STOP"]=15.90, ["NAPIS"]="Dun Morogh\'un kış tepelerinin ötesine nadiren geçtiler."}, 
["Dwarf3:05"]={["START"]=16.02, ["STOP"]=19.98, ["NAPIS"]="Ancak son zamanlarda Cüceler, kadim miraslarına dair"}, 
["Dwarf3:06"]={["START"]=20.02, ["STOP"]=23.14, ["NAPIS"]="sırlar barındıran bir dizi harabeyi gün yüzüne çıkardılar."}, 
["Dwarf3:07"]={["START"]=23.16, ["STOP"]=27.16, ["NAPIS"]="Halkının efsanevi kökenleri hakkındaki gerçeği keşfetmeye kararlı olan"}, 
["Dwarf3:08"]={["START"]=27.18, ["STOP"]=30.26, ["NAPIS"]="büyük Kral Magni Bronzebeard,"}, 
["Dwarf3:09"]={["START"]=30.26, ["STOP"]=34.86, ["NAPIS"]="Cücelerin endüstrilerini madencilikten arkeolojiye kaydırmalarını emretti."}, 
["Dwarf3:10"]={["START"]=34.86, ["STOP"]=36.96, ["NAPIS"]="Büyük İttifak\'ın bir parçası olarak,"}, 
["Dwarf3:11"]={["START"]=36.96, ["STOP"]=43.46, ["NAPIS"]="sadık Cüce orduları uzak diyarlardaki acımasız Horde ile savaşmaya çağrıldı."}, 
["Dwarf3:12"]={["START"]=43.46, ["STOP"]=45.24, ["NAPIS"]="Bu tehlikeli zamanlarda,"}, 
["Dwarf3:13"]={["START"]=45.24, ["STOP"]=50.24, ["NAPIS"]="dağ krallığının savunması senin gibi cesur Cücelere düşüyor."}, 
["Dwarf3:14"]={["START"]=50.24, ["STOP"]=53.36, ["NAPIS"]="Kadim kralların ruhları seni izliyor"}, 
["Dwarf3:15"]={["START"]=53.36, ["STOP"]=56.52, ["NAPIS"]="ve dağlar senin gücün."}, 
["Dwarf3:16"]={["START"]=56.54, ["STOP"]=60.58, ["NAPIS"]="Halkının geleceği senin ellerinde."}, 
["Gnome:01"]={["START"]=1.50, ["STOP"]=4.54, ["NAPIS"]="Ironforge\'daki son siyasi karışıklıklar göz önüne alındığında,"}, 
["Gnome:02"]={["START"]=4.54, ["STOP"]=9.18, ["NAPIS"]="cüceler kendilerini birdenbire Şehir\'de istenmeyen misafirler olarak buldular."}, 
["Gnome:03"]={["START"]=10.62, ["STOP"]=16.12, ["NAPIS"]="Dahiyane teknolojilerinden ve bastırılamaz macera ruhlarından yararlanan cüceler,"}, 
["Gnome:04"]={["START"]=16.12, ["STOP"]=20.92, ["NAPIS"]="Khaz Modan\'daki rollerini yeniden değerlendirmeye başladılar."}, 
["Gnome:05"]={["START"]=20.92, ["STOP"]=24.88, ["NAPIS"]="Yüce Tamirci Gelbin Mekkatorque\'un yaratıcı liderliği altında"}, 
["Gnome:06"]={["START"]=24.88, ["STOP"]=33.48, ["NAPIS"]="cüceler, eski başkentleri Gnomeregan\'ı geri almak için barbar troglara karşı cesur bir sefer planlıyorlar."}, 
["Gnome:07"]={["START"]=35.68, ["STOP"]=42.56, ["NAPIS"]="Olasılıklar onlara karşı dizilmişken, cüceler sizin gibi cesur kahramanların ayakta durmasına ve sayılmasına güveniyor."}, 
["Gnome:08"]={["START"]=43.98, ["STOP"]=46.74, ["NAPIS"]="Halkınızın en büyük saati yaklaşıyor."}, 
["Gnome3:01"]={["START"]=0.26, ["STOP"]=3.16, ["NAPIS"]="Eksantrik, çoğu zaman zeki Gnome\'lar"}, 
["Gnome3:02"]={["START"]=3.16, ["STOP"]=7.10, ["NAPIS"]="dünyanın en tuhaf ırklarından biri olarak kabul edilir."}, 
["Gnome3:03"]={["START"]=7.10, ["STOP"]=10.66, ["NAPIS"]="Radikal yeni teknolojiler geliştirme ve"}, 
["Gnome3:04"]={["START"]=10.66, ["STOP"]=14.50, ["NAPIS"]="akıllara durgunluk veren mühendislik harikaları inşa etme takıntılarıyla,"}, 
["Gnome3:05"]={["START"]=14.50, ["STOP"]=18.52, ["NAPIS"]="herhangi bir Gnome\'un çoğalmak için hayatta kalması bir mucizedir."}, 
["Gnome3:06"]={["START"]=18.52, ["STOP"]=22.54, ["NAPIS"]="Yıllar boyunca Gnome\'lar, Horde\'a karşı verdiği"}, 
["Gnome3:07"]={["START"]=22.54, ["STOP"]=27.28, ["NAPIS"]="çetin savaşlarda Büyük İttifak\'a yardımcı olmak için dahiyane silahlar üretti."}, 
["Gnome3:08"]={["START"]=27.28, ["STOP"]=31.18, ["NAPIS"]="Gnomeregan\'ın harikulade tekno-kentinde gelişen Gnome\'lar,"}, 
["Gnome3:09"]={["START"]=31.18, ["STOP"]=37.10, ["NAPIS"]="Dun Morogh tepelerindeki ormanların kaynaklarını Cüce kuzenleriyle paylaştı."}, 
["Gnome3:10"]={["START"]=37.10, ["STOP"]=44.10, ["NAPIS"]="Ancak yakın zamanda, barbar bir tehdit yeryüzünün derinliklerinden yükselip Gnomeregan\'ı istila etti."}, 
["Gnome3:11"]={["START"]=44.10, ["STOP"]=46.14, ["NAPIS"]="Gnome\'lar, Cüce müttefiklerinin de yardımıyla"}, 
["Gnome3:12"]={["START"]=46.14, ["STOP"]=50.68, ["NAPIS"]="sevgili şehirlerini kurtarmak için yiğitçe bir savaş verdiler."}, 
["Gnome3:13"]={["START"]=50.68, ["STOP"]=55.20, ["NAPIS"]="Yine de Gnomeregan geri dönülmez bir şekilde kaybedildi."}, 
["Gnome3:14"]={["START"]=55.20, ["STOP"]=60.24, ["NAPIS"]="Hayatta kalan Gnome\'lar, Cücelerin kalesi Ironforge\'un emniyetine sığındı."}, 
["Gnome3:15"]={["START"]=60.24, ["STOP"]=65.74, ["NAPIS"]="Orada kaldılar ve şehirlerini geri almak için stratejiler geliştirdiler."}, 
["Gnome3:16"]={["START"]=65.74, ["STOP"]=70.84, ["NAPIS"]="Gururlu bir Gnome olarak, meydan okumaya cevap vermek ve"}, 
["Gnome3:17"]={["START"]=70.84, ["STOP"]=75.62, ["NAPIS"]="meraklı halkınızı daha parlak bir geleceğe taşımak sana düşüyor."}, 
["Goblin:01"]={["START"]=00.00, ["STOP"]=06.12, ["NAPIS"]="Kezan\'ın kurnaz goblinleri nesiller boyunca göreceli bir barış içinde yaşamışlardır."}, 
["Goblin:02"]={["START"]=06.12, ["STOP"]=10.80, ["NAPIS"]="Irklarından bazıları İkinci Savaş sırasında yağmacı orkların yanında yer almış olsa da"}, 
["Goblin:03"]={["START"]=10.80, ["STOP"]=16.94, ["NAPIS"]="Goblinlerin çoğu Alliance ve Horde arasındaki çeşitli çatışmalar boyunca tarafsız kalmıştır."}, 
["Goblin:04"]={["START"]=17.52, ["STOP"]=21.60, ["NAPIS"]="Yozlaşmış ama son derece varlıklı Ticaret Prensleri tarafından yönetilen goblinler,"}, 
["Goblin:05"]={["START"]=21.60, ["STOP"]=27.40, ["NAPIS"]="Güney Denizi adalarında kendileri için sanal bir cennet yarattılar."}, 
["Goblin:06"]={["START"]=27.40, ["STOP"]=31.12, ["NAPIS"]="Onların ustaca mühendislik becerileri ve geniş ticaret filoları"}, 
["Goblin:07"]={["START"]=31.12, ["STOP"]=36.84, ["NAPIS"]="Ada başkentleri Kezan\'ın dünyanın en büyük teknolojik harikalarından biri haline gelmesine yardımcı oldu."}, 
["Goblin:08"]={["START"]=37.68, ["STOP"]=47.35, ["NAPIS"]="Ancak şimdi, elementlerin kendileri dünyanın dört bir yanında öfkeyle ayaklanırken, goblinlerin mekanik cenneti teste tabi tutulacak"}, 
["Goblin:09"]={["START"]=47.40, ["STOP"]=56.14, ["NAPIS"]="çünkü çok yakında kader onları dünyanın tarihini sarsacak bir çatışmada taraf seçmeye zorlayacak."}, 
["Human:01"]={["START"]=0.00, ["STOP"]=4.66, ["NAPIS"]="Kahraman Kralları Varian Wrynn\'in dönüşüyle cesaretlenen,"}, 
["Human:02"]={["START"]=4.66, ["STOP"]=11.82, ["NAPIS"]="Stormwind\'in gururlu insanları, İttifak\'ı korkunç Lich King\'e karşı savaşında zafere taşıdı."}, 
["Human:03"]={["START"]=12.38, ["STOP"]=17.16, ["NAPIS"]="Başarılı olsa da Northrend\'deki sefer pahalıya mal oldu,"}, 
["Human:04"]={["START"]=17.18, ["STOP"]=22.18, ["NAPIS"]="ve insanlar şimdi dünya genelindeki stratejik varlıklarını güçlendirmeye çalışıyor."}, 
["Human:05"]={["START"]=22.18, ["STOP"]=32.58, ["NAPIS"]="Varian\'ın cesur liderliği altında insanlık, ezeli düşmanı Horde ile yeni bir çatışmaya hazırlanıyor."}, 
["Human:06"]={["START"]=32.98, ["STOP"]=39.98, ["NAPIS"]="Ancak büyük felaket dünyayı kasıp kavururken, tanıdık tehditler bir kez daha eve daha yakın bir yerde ortaya çıktı."}, 
["Human:07"]={["START"]=39.98, ["STOP"]=46.28, ["NAPIS"]="Krallığı savunmak ve insanlığın onurunu korumak artık size düşüyor."}, 
["Human3:01"]={["START"]=15.02, ["STOP"]=20.34, ["NAPIS"]="Stormwind\'in asil İnsanları gururlu ve inatçı bir ırktır."}, 
["Human3:02"]={["START"]=20.34, ["STOP"]=26.90, ["NAPIS"]="Şeytani Burning Legion\'un son istilası kardeş krallıkları Lordaeron\'u yok etmiş olsa da,"}, 
["Human3:03"]={["START"]=26.90, ["STOP"]=34.00, ["NAPIS"]="Stormwind\'in savunucuları topraklarının kutsallığını tehdit edecek herkese karşı tetikte durmaktadır."}, 
["Human3:04"]={["START"]=34.00, ["STOP"]=37.00, ["NAPIS"]="Elwynn Ormanı\'nın eteklerinde yer alan Stormwind Şehri,"}, 
["Human3:05"]={["START"]=37.00, ["STOP"]=42.70, ["NAPIS"]="İnsan gücünün dünyadaki son kalelerinden biridir."}, 
["Human3:06"]={["START"]=42.70, ["STOP"]=45.70, ["NAPIS"]="Çocuk-kral Anduin Wrynn tarafından yönetilen Stormwind halkı,"}, 
["Human3:07"]={["START"]=45.70, ["STOP"]=52.00, ["NAPIS"]="Büyük İttifak\'a olan bağlılıklarında kararlıdır."}, 
["Human3:08"]={["START"]=52.02, ["STOP"]=56.40, ["NAPIS"]="Sadık müttefikleri tarafından desteklenen Stormwind orduları,"}, 
["Human3:09"]={["START"]=56.40, ["STOP"]=60.60, ["NAPIS"]="uzak savaş meydanlarında vahşi Horde ile savaşmak için çağrıldı."}, 
["Human3:10"]={["START"]=60.60, ["STOP"]=67.00, ["NAPIS"]="Ordular gittiğine göre, Stormwind\'in savunması artık gururlu vatandaşlarına düşüyor."}, 
["Human3:11"]={["START"]=67.00, ["STOP"]=72.14, ["NAPIS"]="Krallığı, ona saldıran iğrenç melezlere karşı savunmalı ve"}, 
["Human3:12"]={["START"]=72.14, ["STOP"]=78.22, ["NAPIS"]="onu içeriden yok etmeye çalışan yıkıcı hainleri avlamalısın."}, 
["Human3:13"]={["START"]=78.22, ["STOP"]=81.02, ["NAPIS"]="Şimdi kahramanların zamanı;"}, 
["Human3:14"]={["START"]=81.02, ["STOP"]=86.50, ["NAPIS"]="şimdi İnsanlığın en büyük hikayesini anlatma zamanı."}, 
["Night Elf:01"]={["START"]=0.00, ["STOP"]=3.94, ["NAPIS"]="Emerald Nightmare\'de yıllarca hapis kaldıktan sonra,"}, 
["Night Elf:02"]={["START"]=3.94, ["STOP"]=9.82, ["NAPIS"]="Archdruid Malfurion Stormrage nihai olarak ölümlü dünyaya geri döndü."}, 
["Night Elf:03"]={["START"]=10.24, ["STOP"]=13.64, ["NAPIS"]="Aşkı Tyrande Whisperwind ile yeniden bir araya geldi,"}, 
["Night Elf:04"]={["START"]=13.64, ["STOP"]=21.76, ["NAPIS"]="Malfurion şimdi bozulmuş Dünya Ağacı Teldrassil\'i iyileştirmek ve gece elfi halkının ruhunu canlandırmak için çabalıyor."}, 
["Night Elf:05"]={["START"]=21.78, ["STOP"]=29.24, ["NAPIS"]="Ancak büyük Cataclysm devasa ağaçlarının dallarını sallarken, gece elfleri yaklaşan fırtınaya karşı kendilerini hazırlıyorlar."}, 
["Night Elf:06"]={["START"]=29.24, ["STOP"]=33.42, ["NAPIS"]="Savaş ve yıkım her taraftan yaklaşırken"}, 
["Night Elf:07"]={["START"]=33.42, ["STOP"]=41.30, ["NAPIS"]="güçlü durmak ve halkınızın kalıcı mirasını korumak sizin gibi gece elflerine düşüyor."}, 
["Night Elf3:01"]={["START"]=1.94, ["STOP"]=4.08, ["NAPIS"]="On bin yıl boyunca,"}, 
["Night Elf3:02"]={["START"]=4.08, ["STOP"]=11.66, ["NAPIS"]="ölümsüz Night Elfler, Ashenvale Ormanı\'nın karanlık köşelerinde druidik bir toplum geliştirdiler."}, 
["Night Elf3:03"]={["START"]=11.66, ["STOP"]=16.20, ["NAPIS"]="Ancak son zamanlarda, Burning Legion\'ın feci istilası"}, 
["Night Elf3:04"]={["START"]=16.20, ["STOP"]=20.50, ["NAPIS"]="kadim medeniyetlerinin huzurunu bozdu."}, 
["Night Elf3:05"]={["START"]=21.26, ["STOP"]=26.98, ["NAPIS"]="Baş Druid Malfurion Stormrage ve Rahibe Tyrande Whisperwind önderliğindeki kudretli Night Elfler,"}, 
["Night Elf3:06"]={["START"]=26.98, ["STOP"]=31.62, ["NAPIS"]="şeytani saldırıya meydan okumak için ayağa kalktı."}, 
["Night Elf3:07"]={["START"]=31.62, ["STOP"]=37.78, ["NAPIS"]="Galip gelmelerine rağmen, Night Elfler aziz ölümsüzlüklerini feda etmek"}, 
["Night Elf3:08"]={["START"]=37.78, ["STOP"]=42.10, ["NAPIS"]="ve sevgili ormanlarının yanışını izlemek zorunda kaldılar."}, 
["Night Elf3:09"]={["START"]=42.12, ["STOP"]=44.78, ["NAPIS"]="Ölümsüzlüklerini yeniden kazanmak isteyen"}, 
["Night Elf3:10"]={["START"]=44.78, ["STOP"]=49.14, ["NAPIS"]="birkaç asi Druid, ruhlarını ebedi dünyaya bağlayacak"}, 
["Night Elf3:11"]={["START"]=49.14, ["STOP"]=53.06, ["NAPIS"]="özel bir ağaç dikmek için plan yaptı."}, 
["Night Elf3:12"]={["START"]=53.06, ["STOP"]=58.44, ["NAPIS"]="Malfurion\'un Doğa\'nın böylesine bencilce bir eylemi asla kutsamayacağına dair uyarılarına rağmen,"}, 
["Night Elf3:13"]={["START"]=58.44, ["STOP"]=65.12, ["NAPIS"]="Druidler büyük ağaç Teldrassil\'i kuzey Kalimdor\'un fırtınalı kıyılarına diktiler."}, 
["Night Elf3:14"]={["START"]=65.12, ["STOP"]=68.56, ["NAPIS"]="Devasa ağacın alacakaranlık dalları arasında,"}, 
["Night Elf3:15"]={["START"]=68.56, ["STOP"]=71.82, ["NAPIS"]="harikulade Darnassus şehri kök saldı."}, 
["Night Elf3:16"]={["START"]=71.82, ["STOP"]=76.32, ["NAPIS"]="Ancak ulu ağaç Doğa\'nın kutsamasıyla kutsanmamıştı ve"}, 
["Night Elf3:17"]={["START"]=76.32, ["STOP"]=80.66, ["NAPIS"]="çok geçmeden Burning Legion\'ın yozlaşmasının kurbanı oldu."}, 
["Night Elf3:18"]={["START"]=80.66, ["STOP"]=85.38, ["NAPIS"]="Şimdi, yaban hayatı ve hatta ulu ağacın uzuvları bile"}, 
["Night Elf3:19"]={["START"]=85.38, ["STOP"]=89.22, ["NAPIS"]="büyüyen bir karanlıkla lekelenmiş durumda."}, 
["Night Elf3:20"]={["START"]=89.66, ["STOP"]=93.02, ["NAPIS"]="Dünyada kalan birkaç Night Elf\'ten biri olarak,"}, 
["Night Elf3:21"]={["START"]=93.02, ["STOP"]=97.04, ["NAPIS"]="Darnassus\'u ve doğanın vahşi çocuklarını"}, 
["Night Elf3:22"]={["START"]=97.04, ["STOP"]=103.84, ["NAPIS"]="Legion\'un yaklaşan yozlaşmasına karşı savunmak senin yeminli görevin."}, 
["Orc:01"]={["START"]=0.00, ["STOP"]=4.56, ["NAPIS"]="Büyük Tufan, dünyadan çok daha fazlasını paramparça etti."}, 
["Orc:02"]={["START"]=4.56, ["STOP"]=9.24, ["NAPIS"]="Tartışmasız yaşayan en güçlü şaman olan Warchief Thrall,"}, 
["Orc:03"]={["START"]=9.24, ["STOP"]=14.70, ["NAPIS"]="Cataclysm\'i kaynağında durdurabilmek için halkını geride bıraktı."}, 
["Orc:04"]={["START"]=15.20, ["STOP"]=19.98, ["NAPIS"]="Ancak onun yokluğunda, ork şampiyonu Garrosh Hellscream"}, 
["Orc:05"]={["START"]=19.98, ["STOP"]=23.08, ["NAPIS"]="Horde\'un yeni Warchief\'i oldu."}, 
["Orc:06"]={["START"]=23.08, ["STOP"]=27.60, ["NAPIS"]="Lich King\'e karşı kazandığı zaferler orklar arasında popüler olsa da"}, 
["Orc:07"]={["START"]=27.60, ["STOP"]=34.58, ["NAPIS"]="Garrosh\'un pervasız liderliği, kendisi ve Horde\'un diğer liderleri arasında bir çatlağa neden olmaya başladı."}, 
["Orc:08"]={["START"]=34.58, ["STOP"]=37.80, ["NAPIS"]="Durotar\'ın doğal kaynakları neredeyse tükenmek üzereyken,"}, 
["Orc:09"]={["START"]=37.80, ["STOP"]=41.60, ["NAPIS"]="Garrosh, yoluna kim çıkarsa çıksın halkının hayatta kalmak için"}, 
["Orc:10"]={["START"]=41.60, ["STOP"]=45.28, ["NAPIS"]="ihtiyaç duyduğu her şeyi almaya çalışır."}, 
["Orc:11"]={["START"]=45.28, ["STOP"]=48.58, ["NAPIS"]="Horde için tehlikeli yeni bir dönem başladı."}, 
["Orc:12"]={["START"]=48.58, ["STOP"]=60, ["NAPIS"]="ve yeni Warchief\'in iradesini korumak ve halkınızın hakimiyetini sağlamak sizin gibi cesur orklara düşüyor."}, 
["Orc3:01"]={["START"]=4.22, ["STOP"]=5.36, ["NAPIS"]="Uzun zaman önce Orklar,"}, 
["Orc3:02"]={["START"]=5.36, ["STOP"]=9.04, ["NAPIS"]="Burning Legion tarafından yozlaştırıldı  ve"}, 
["Orc3:03"]={["START"]=9.04, ["STOP"]=12.16, ["NAPIS"]="Azeroth dünyasına çekildi."}, 
["Orc3:04"]={["START"]=12.16, ["STOP"]=19.46, ["NAPIS"]="Orklar nesiller boyunca Stormwind ve Lordaeron\'daki İnsan krallıklarına savaş açtı."}, 
["Orc3:05"]={["START"]=19.90, ["STOP"]=22.72, ["NAPIS"]="Horde sonunda yenilse de, Thrall adında"}, 
["Orc3:06"]={["START"]=22.72, ["STOP"]=25.82, ["NAPIS"]="ileri görüşlü genç bir savaş şefi, halkına en karanlık "}, 
["Orc3:07"]={["START"]=25.82, ["STOP"]=29.64, ["NAPIS"]="zamanlarında liderlik etmek için ortaya çıktı."}, 
["Orc3:08"]={["START"]=29.64, ["STOP"]=35.46, ["NAPIS"]="Thrall\'ın yönetimi altında Orklar kendilerini şeytani yozlaşmanın zincirlerinden kurtardılar"}, 
["Orc3:09"]={["START"]=35.46, ["STOP"]=39.06, ["NAPIS"]="ve Şamanistik miraslarını kucakladılar."}, 
["Orc3:10"]={["START"]=39.06, ["STOP"]=43.08, ["NAPIS"]="Yıllarca göçebe yaşadıktan sonra Orklar,"}, 
["Orc3:11"]={["START"]=43.08, ["STOP"]=47.12, ["NAPIS"]="Durotar\'ın sert çorak topraklarında kendi krallıklarını kurdular."}, 
["Orc3:12"]={["START"]=47.12, ["STOP"]=50.94, ["NAPIS"]="Savaşçı şehir Orgrimmar\'da, üstünlüklerine meydan okuyacak"}, 
["Orc3:13"]={["START"]=50.94, ["STOP"]=54.74, ["NAPIS"]="herkesi yok etmeye hazır bekliyorlar."}, 
["Orc3:14"]={["START"]=54.74, ["STOP"]=57.24, ["NAPIS"]="Durotar\'ın gururlu bir savunucusu olarak,"}, 
["Orc3:15"]={["START"]=57.24, ["STOP"]=61.58, ["NAPIS"]="görünen ve görünmeyen düşmanlarını ezmek senin görevin,"}, 
["Orc3:16"]={["START"]=61.58, ["STOP"]=69.62, ["NAPIS"]="çünkü Burning Legion\'ın hain ajanları hâlâ bu topraklarda dolaşıyor."}, 
["Pandaren:01"]={["START"]=0.00, ["STOP"]=7.34, ["NAPIS"]="Sen gizemli Gezgin Ada\'da doğmuş ve büyümüş bir pandarensin."}, 
["Pandaren:02"]={["START"]=7.34, ["STOP"]=16.34, ["NAPIS"]="Pandaren dostlarınızın çoğu sakin bir hayatı tercih ederken, maceranın cazibesi kanınızda dolaşıyor."}, 
["Pandaren:03"]={["START"]=16.34, ["STOP"]=24.10, ["NAPIS"]="Son zamanlarda, Gezgin Ada dünya okyanuslarında düzensiz bir şekilde dolaşmaya başladı."}, 
["Pandaren:04"]={["START"]=24.10, ["STOP"]=30.26, ["NAPIS"]="Hava soğuyor ve adadaki eviniz felakete doğru sürükleniyor."}, 
["Pandaren:05"]={["START"]=30.26, ["STOP"]=40.24, ["NAPIS"]="Usta Shang\'ın manastırındaki en gelecek vaat eden öğrencilerden biri olarak, halkınız için kurtuluş olabilirsiniz."}, 
["Pandaren:06"]={["START"]=40.24, ["STOP"]=44.76, ["NAPIS"]="Ama önce eğitiminizi tamamlamalısınız."}, 
["Tauren:01"]={["START"]=0.00, ["STOP"]=7.20, ["NAPIS"]="Büyük trajedi Tauren kabilelerini derinden etkiledi ve bir zamanlar Horde\'a olan güçlü bağlılıklarını sarstı."}, 
["Tauren:02"]={["START"]=7.20, ["STOP"]=14.56, ["NAPIS"]="Yeni ork Warchief Garrosh Hellscream ile sevilen tauren Reisi Cairne Bloodhoof arasında bir anlaşmazlık"}, 
["Tauren:03"]={["START"]=14.56, ["STOP"]=19.14, ["NAPIS"]="Cairne\'in ölümüyle sonuçlanan bir düelloya yol açtı."}, 
["Tauren:04"]={["START"]=19.14, ["STOP"]=28.60, ["NAPIS"]="Onun kaybıyla birlikte, aşağılık anaerkil Magatha Grimtotem, Thunder Bluff\'un kontrolünü ele geçirmek için ölümcül bir saldırı başlattı."}, 
["Tauren:05"]={["START"]=29.02, ["STOP"]=34.86, ["NAPIS"]="Ancak Cairne\'in cesur oğlu Baine Bloodhoof saldırıyı başarıyla püskürttü"}, 
["Tauren:06"]={["START"]=34.86, ["STOP"]=39.84, ["NAPIS"]="ve hayatta kalan Grimtotem\'i ülkenin en uzak köşelerine sürgün etti."}, 
["Tauren:07"]={["START"]=40.62, ["STOP"]=45.56, ["NAPIS"]="Baine\'in umut dolu liderliği altında, Tauren halkı şimdi yaralarını sarmaya"}, 
["Tauren:08"]={["START"]=45.56, ["STOP"]=49.94, ["NAPIS"]="ve Horde\'un çeşitli grupları arasındaki dengeyi yeniden kurmaya çalışıyor."}, 
["Tauren:09"]={["START"]=50.88, ["STOP"]=60.96, ["NAPIS"]="Bu amaçla, halklarını yeni bir şafağın Işığına ve yeniden doğuş vaadine yönlendirmek için yeni bir tauren Sunwalker nesli ortaya çıktı."}, 
["Tauren:10"]={["START"]=61.36, ["STOP"]=69.60, ["NAPIS"]="Mulgore\'un gururlu bir kabilesi olarak, halkınızın onurunu korumalı ve atalarınızın topraklarını korumalısınız."}, 
["Tauren3:01"]={["START"]=1.20, ["STOP"]=3.16, ["NAPIS"]="Bir zamanlar göçebe bir halk olan Taurenler,"}, 
["Tauren3:02"]={["START"]=3.16, ["STOP"]=8.84, ["NAPIS"]="güçlü Kodo\'yu avlamak için Barrens\'in uçsuz bucaksız düzlüklerinde dolaşırdı."}, 
["Tauren3:03"]={["START"]=9.12, ["STOP"]=14.82, ["NAPIS"]="Diyarın dört bir yanına dağılmış olan bu gezgin kabileleri birleştiren tek şey,"}, 
["Tauren3:04"]={["START"]=14.82, ["STOP"]=19.10, ["NAPIS"]="ezeli düşmanları yağmacı Centaur\'a duydukları ortak nefretti. "}, 
["Tauren3:05"]={["START"]=19.10, ["STOP"]=23.94, ["NAPIS"]="Centaur\'a karşı yardım arayan büyük reis Cairne Bloodhoof,"}, 
["Tauren3:06"]={["START"]=23.94, ["STOP"]=28.94, ["NAPIS"]="yakın zamanda Kalimdor\'a yolculuk etmiş olan vahşi Orklarla dost oldu. "}, 
["Tauren3:07"]={["START"]=28.94, ["STOP"]=33.76, ["NAPIS"]="Orkların yardımıyla Cairne ve kabilesi Centaur\'u geri püskürtmeyi başardı"}, 
["Tauren3:08"]={["START"]=33.78, ["STOP"]=37.68, ["NAPIS"]="ve Mulgore\'un otlaklarını kendi topraklarına kattı."}, 
["Tauren3:09"]={["START"]=38.00, ["STOP"]=44.34, ["NAPIS"]="Thunderbluff\'un rüzgârlı tepesinde, Bloodhoof halkı için bir sığınak inşa etti."}, 
["Tauren3:10"]={["START"]=44.34, ["STOP"]=49.66, ["NAPIS"]="Zamanla, dağınık kabileler tek bir sancak altında birleşti."}, 
["Tauren3:11"]={["START"]=50.44, ["STOP"]=53.68, ["NAPIS"]="Soylu Taurenler doğaları gereği barışçıl olsalar da,"}, 
["Tauren3:12"]={["START"]=53.68, ["STOP"]=59.68, ["NAPIS"]="Büyük Av\'ın haklarına manevi kültürlerinin kalbi olarak saygı duyarlar."}, 
["Tauren3:13"]={["START"]=59.70, ["STOP"]=62.10, ["NAPIS"]="Mulgore\'un bir kabilesi olarak,"}, 
["Tauren3:14"]={["START"]=62.10, ["STOP"]=69.14, ["NAPIS"]="vahşi doğada yeteneklerini test etmeli ve Büyük Av\'da kendini kanıtlamalısın."}, 
["Troll:01"]={["START"]=0.00, ["STOP"]=4.06, ["NAPIS"]="Yıllar önce Stranglethorn Vadisi\'ndeki topraklarından sürgün edildiler."}, 
["Troll:02"]={["START"]=4.06, ["STOP"]=11.50, ["NAPIS"]="Darkspear trolleri, Horde\'un farklı ırkları arasında kendilerine yeni bir hayat kurmaya çalıştılar."}, 
["Troll:03"]={["START"]=11.54, ["STOP"]=14.54, ["NAPIS"]="Asil Warchief Thrall\'ın liderliğinde"}, 
["Troll:04"]={["START"]=14.54, ["STOP"]=21.50, ["NAPIS"]="Vol\'jin ve vahşi trolleri sonunda aradıkları onuru ve amacı bulmuşlardı."}, 
["Troll:05"]={["START"]=21.56, ["STOP"]=30.15, ["NAPIS"]="Ama şimdi, dikbaşlı Garrosh Hellscream\'in yönetimi altında, troller Horde\'un kendini parçalayabileceğinden korkuyor."}, 
["Troll:06"]={["START"]=30.20, ["STOP"]=36.68, ["NAPIS"]="Vol\'jin, ister Hord\'un içinden ister dışından gelsin, önümüzde beliren tehditler ne olursa olsun,"}, 
["Troll:07"]={["START"]=36.70, ["STOP"]=42.38, ["NAPIS"]="Hord\'un onurunu korumak için savaşacak olanların sizin gibi kurnaz troller olduğunu biliyor."}, 
["Troll3:01"]={["START"]=2.36, ["STOP"]=7.94, ["NAPIS"]="Güney Denizleri\'nin sayısız orman adasında yaşayan acımasız Troller,"}, 
["Troll3:02"]={["START"]=7.94, ["STOP"]=11.80, ["NAPIS"]="zalimlikleri ve karanlık gizemcilikleriyle ünlüdür."}, 
["Troll3:03"]={["START"]=12.10, ["STOP"]=14.34, ["NAPIS"]="Barbar ve batıl inançlıdırlar,"}, 
["Troll3:04"]={["START"]=14.34, ["STOP"]=18.74, ["NAPIS"]="diğer tüm ırklara karşı içten içe nefret beslerler."}, 
["Troll3:05"]={["START"]=19.44, ["STOP"]=25.50, ["NAPIS"]="Uzun zaman önce Stranglethorn Vadisi\'ndeki ata yurtlarından sürgün edilen Darkspear Kabilesi,"}, 
["Troll3:06"]={["START"]=25.54, ["STOP"]=29.82, ["NAPIS"]="azgın Murloclar tarafından neredeyse yok ediliyordu."}, 
["Troll3:07"]={["START"]=29.82, ["STOP"]=36.04, ["NAPIS"]="Genç Warchief Thrall ve Ork savaşçıları tarafından kurtarılan Darkspear Kabilesi,"}, 
["Troll3:08"]={["START"]=36.06, ["STOP"]=38.34, ["NAPIS"]="Horde\'a bağlılık yemini etti."}, 
["Troll3:09"]={["START"]=38.34, ["STOP"]=43.54, ["NAPIS"]="Kurnaz Gölge Avcısı Vol\'jin\'in önderliğindeki Kara Mızraklılar"}, 
["Troll3:10"]={["START"]=43.54, ["STOP"]=48.28, ["NAPIS"]="artık Ork müttefikleriyle birlikte Durotar\'da evlerini kuruyor."}, 
["Troll3:11"]={["START"]=48.28, ["STOP"]=51.75, ["NAPIS"]="Hayatta kalan tek Darkspear\'lardan biri olarak"}, 
["Troll3:12"]={["START"]=51.76, ["STOP"]=56.60, ["NAPIS"]="kabilenin şanını geri kazanmak sana düşüyor."}, 
["Undead:01"]={["START"]=0.00, ["STOP"]=11.08, ["NAPIS"]="Leydi Sylvanas ve Forsaken\'ı sonunda nefret ettikleri düşmanları Lich King\'den intikam almış olsalar da Northrend\'deki karanlık haçlı seferleri pahalıya mal oldu."}, 
["Undead:02"]={["START"]=11.08, ["STOP"]=16.00, ["NAPIS"]="Wrathgate Savaşı\'nda Büyük Eczacı Putress tarafından ihanete uğradı"}, 
["Undead:03"]={["START"]=16.00, ["STOP"]=24.16, ["NAPIS"]="Forsaken\'ın sinsi ölüm salgını hem Alliance hem de Horde üzerinde felaket etkisi yarattı."}, 
["Undead:04"]={["START"]=24.16, ["STOP"]=32.40, ["NAPIS"]="Sylvanas\'ın haberi olmadan, Putress ve şeytani müttefiki Varimathras Undercity\'nin kontrolünü ele geçirmişti."}, 
["Undead:05"]={["START"]=32.40, ["STOP"]=37.38, ["NAPIS"]="Sonuç olarak, Forsaken\'lar hainin zulmünden dolayı haksız yere suçlandılar."}, 
["Undead:06"]={["START"]=37.86, ["STOP"]=44.88, ["NAPIS"]="Undercity sonunda geri alınmış olsa da, Sylvanas ve takipçileri hâlâ Putress\'in işlediği günahların yükünü taşımaktadır."}, 
["Undead:07"]={["START"]=45.82, ["STOP"]=48.58, ["NAPIS"]="Horde\'un diğer üyeleri tarafından güvenilmeyen"}, 
["Undead:08"]={["START"]=48.58, ["STOP"]=55.32, ["NAPIS"]="Forsaken şimdi davaya olan sadakatlerini kanıtlamalı ve sözde ihanetlerinden kendilerini kurtarmalıdır."}, 
["Undead:09"]={["START"]=55.32, ["STOP"]=64.94, ["NAPIS"]="Bu amaçla Sylvanas, Tirisfal Glades\'teki savunmasını güçlendirdi ve ölümsüz güçlerini her türlü olasılığa karşı hazırladı."}, 
["Undead:10"]={["START"]=64.94, ["STOP"]=73.10, ["NAPIS"]="Forsaken\'lardan biri olarak, Sylvanas\'ın hükümdarlığına tehdit oluşturabilecek herkesi öldürmek için kurnazlığınızı ve acımasızlığınızı kullanmalısınız"}, 
["Undead:11"]={["START"]=73.10, ["STOP"]=77.08, ["NAPIS"]="ister insan ister ölümsüz olsunlar."}, 
["Undead3:01"]={["START"]=0.22, ["STOP"]=4.06,  ["NAPIS"]="Zalim Lich King\'in demir iradesine bağlı olan"}, 
["Undead3:02"]={["START"]=4.06, ["STOP"]=7.54,  ["NAPIS"]="Scourge\'un devasa Undead orduları,"}, 
["Undead3:03"]={["START"]=7.54, ["STOP"]=11.22,  ["NAPIS"]="Azeroth\'taki tüm yaşamı ortadan kaldırmaya çalışıyor."}, 
["Undead3:04"]={["START"]=11.46, ["STOP"]=14.62,  ["NAPIS"]="Banshee Sylvanas Windrunner liderliğindeki bir grup hain,"}, 
["Undead3:05"]={["START"]=14.62, ["STOP"]=18.04,  ["NAPIS"]="Scourge\'dan ayrıldı ve kendilerini "}, 
["Undead3:06"]={["START"]=18.04, ["STOP"]=21.02,  ["NAPIS"]="Lich King\'in egemenliğinden kurtardı."}, 
["Undead3:07"]={["START"]=21.16, ["STOP"]=24.02,  ["NAPIS"]="Bazıları tarafından Forsaken olarak bilinen bu grup,"}, 
["Undead3:08"]={["START"]=24.50, ["STOP"]=27.16,  ["NAPIS"]="yalnızca Scourge\'dan özgürlüğünü korumak için değil,"}, 
["Undead3:09"]={["START"]=27.16, ["STOP"]=30.32,  ["NAPIS"]="aynı zamanda onları canavar olarak avlamak isteyenleri"}, 
["Undead3:10"]={["START"]=30.32, ["STOP"]=35.74,  ["NAPIS"]="katletmek için de sürekli bir savaş veriyor."}, 
["Undead3:11"]={["START"]=35.74, ["STOP"]=38.66,  ["NAPIS"]="Sylvanas\'ın Banshee Kraliçesi olduğu Forsaken,"}, 
["Undead3:12"]={["START"]=38.66, ["STOP"]=45.38,  ["NAPIS"]="Lordaeron\'un eski başkentinin kalıntılarının altında karanlık bir kale inşa etti."}, 
["Undead3:13"]={["START"]=45.38, ["STOP"]=50.02,  ["NAPIS"]="Bu gizli Yeraltı Şehri, Tirisfal Glades\'in"}, 
["Undead3:14"]={["START"]=50.02, ["STOP"]=54.78,  ["NAPIS"]="perili ormanlarının altında uzanan geniş bir labirent oluşturur."}, 
["Undead3:15"]={["START"]=54.78, ["STOP"]=57.58,  ["NAPIS"]="Toprakların tamamı lanetli olsa da,"}, 
